INSERT INTO public.build_project_plans (id, id_proyecto, nombre, presupuesto, duracion_semanas, prioridad, plan_data, created_at) VALUES ('BLD-PRJ0034', 'PRJ0034', 'Red Infraestructura Centro Financiero BCC', 384630.00, 28, 'Alta', '{"bf-edt": "1.0 | Diseño Arquitectura Red | Arquitecto Redes\n2.0 | Adquisición Hardware | JdP\n3.0 | Instalación Core | Equipo Redes\n4.0 | Configuración VLAN/Seguridad | Seguridad\n5.0 | Integración Backbone | Redes\n6.0 | Pruebas y Certificación | QA\n7.0 | Go-Live | Operaciones", "bf-area": "Infraestructura", "bf-opex": "30000", "bf-capex": "150000", "bf-hitos": "S4: Diseño red aprobado\nS10: Hardware recibido\nS16: Core switches operativos\nS22: Segmentación VLAN completada\nS26: Pruebas de rendimiento OK\nS28: Go-Live", "bf-horas": "85", "bf-nombre": "Red Infraestructura Centro Financiero BCC", "bf-tarifa": "145", "bf-alcance": "Red LAN/WAN completa del centro financiero BCC: capa core (2 switches), distribución (4 switches), acceso (8 switches), firewalls (2 HA), cableado estructurado Cat6A, integración con backbone existente.", "bf-calidad": "PCI DSS v4.0, ISO 27001, Normativa interna seguridad Cajamar", "bf-resumen": "Despliegue de la infraestructura de red completa para el nuevo centro financiero BCC, incluyendo switches core Cisco, cableado estructurado y segmentación de red.", "bf-riesgos": "Retraso entrega switches Cisco | 3 | 4 | Mitigar — Orden compra anticipada\nIncompatibilidad firmware | 2 | 4 | Mitigar — Lab de pruebas previo\nFallo segmentación PCI DSS | 2 | 5 | Mitigar — Auditoría intermedia S20\nCorte servicio en integración | 3 | 5 | Mitigar — Ventana nocturna con rollback", "bf-sponsor": "CIO / Director de Tecnología", "bf-duracion": "28", "bf-personal": "12325", "bf-criterios": "Throughput >10Gbps, 0 incidencias P1 en 30 días post-implantación, PCI DSS compliance audit pass", "bf-objetivos": "Específico: Desplegar red core+distribución+acceso en BCC\nMedible: Throughput >10Gbps, latencia <1ms intra-site\nAlcanzable: Con equipo de Redes N3 y soporte Cisco\nRelevante: Centro financiero es crítico para operaciones\nTemporal: 28 semanas", "bf-prioridad": "Alta", "bf-servicios": "61200", "bf-asunciones": "• Hardware Cisco entregado en 8 semanas\n• Acceso físico al CPD sin restricciones\n• Personal de Redes N3 disponible", "bf-beneficios": "• Conectividad de alta velocidad (10/40Gbps) para el centro financiero\n• Segmentación de red conforme a PCI DSS\n• Redundancia total en capa core y distribución\n• Monitorización centralizada de todos los activos de red", "bf-financiero": "BAC: 384,630€ | Contingencia: 13%", "bf-descripcion": "Implementación de la infraestructura de red del centro financiero BCC con switches core Cisco Catalyst, cableado Cat6A, firewalls perimetrales y segmentación VLAN conforme a PCI DSS.", "bf-entregables": "E01: Diseño de arquitectura de red aprobado\nE02: Switches core instalados y configurados\nE03: Segmentación VLAN implementada\nE04: Firewalls perimetrales operativos\nE05: Monitorización Nagios integrada\nE06: Documentación as-built completa", "bf-exclusiones": "• Conectividad WAN entre centros (otro proyecto)\n• Telefonía IP (se usará infraestructura existente)\n• WiFi corporativo (fase posterior)", "bf-interesados": "CIO | Patrocinador | A favor | Alto | Gestionar de cerca\nCISO | Seguridad | A favor | Alto | Involucrar en diseño PCI\nJefe Redes | Técnico líder | A favor | Medio | Responsable ejecución\nCisco Partner | Proveedor | A favor | Medio | SLA de entrega", "bf-presupuesto": "384630", "bf-contingencia": "13", "bf-justificacion": "• El centro financiero BCC requiere infraestructura de red dedicada y segura\n• Cumplimiento PCI DSS para transacciones financieras\n• Necesidad de alta disponibilidad (99.99%) para servicios críticos de pago", "bf-restricciones": "• Presupuesto: 384.630€\n• Plazo: 28 semanas\n• Cumplimiento PCI DSS obligatorio\n• Ventanas de mantenimiento solo fines de semana", "bf-comunicaciones": "Semanal: Reunión equipo (Acta)\nQuincenal: Informe a CIO\nPor hito: Informe cierre fase\nAd-hoc: Alertas de riesgo", "bf-contrabeneficios": "• Inversión CAPEX significativa en hardware de red\n• Requiere ventanas de mantenimiento para integración\n• Dependencia del proveedor Cisco para entrega de equipos"}', '2026-03-20 11:03:35.117888+00');
INSERT INTO public.build_project_plans (id, id_proyecto, nombre, presupuesto, duracion_semanas, prioridad, plan_data, created_at) VALUES ('BLD-PRJ0042', 'PRJ0042', 'Renovación Plataforma Clearpass NAC', 290250.50, 24, 'Alta', '{"bf-edt": "1.0 | Diseño Políticas NAC | Seguridad\n2.0 | Instalación Clearpass HA | Redes\n3.0 | Integración AD | Sistemas\n4.0 | Piloto 10 oficinas | Redes\n5.0 | Rollout masivo | Redes+Soporte\n6.0 | Cierre | JdP", "bf-area": "Infraestructura", "bf-opex": "36000", "bf-capex": "97000", "bf-hitos": "S4: Diseño aprobado\nS8: Clearpass en HA\nS12: Piloto completado\nS20: Rollout 100%\nS24: Cierre", "bf-horas": "75", "bf-nombre": "Renovación Plataforma Clearpass NAC", "bf-tarifa": "145", "bf-alcance": "Plataforma NAC Clearpass en HA, políticas 802.1X, profiling, guest portal, integración AD, reporting compliance.", "bf-calidad": "ISO 27001, DORA, PCI DSS, Política acceso red Cajamar", "bf-resumen": "Renovación completa de la plataforma de control de acceso a red (NAC) basada en Aruba Clearpass para securizar el acceso de dispositivos a la red corporativa.", "bf-riesgos": "Incompatibilidad switches antiguos | 3 | 4 | Mitigar — Inventario previo\nImpacto conectividad usuarios | 4 | 3 | Mitigar — Migración por fases nocturnas\nResistencia usuarios a 802.1X | 3 | 2 | Mitigar — Comunicación y soporte presencial", "bf-sponsor": "CISO", "bf-duracion": "24", "bf-personal": "10875", "bf-criterios": "100% oficinas migradas, 0 incidencias seguridad en 30 días", "bf-objetivos": "Específico: Migrar NAC a Clearpass en 120 oficinas\nMedible: 100% oficinas migradas, 0 accesos no autorizados\nAlcanzable: Con soporte Aruba y equipo Redes\nRelevante: Seguridad perimetral es prioridad BCE\nTemporal: 24 semanas", "bf-prioridad": "Alta", "bf-servicios": "41600", "bf-asunciones": "• Switches de acceso compatibles con 802.1X\n• AD actualizado con grupos de seguridad", "bf-beneficios": "• Control granular de acceso por dispositivo/usuario/ubicación\n• Integración con Active Directory para autenticación 802.1X\n• Visibilidad completa de dispositivos conectados\n• Compliance automático con políticas de seguridad", "bf-financiero": "BAC: 290,250€ | Contingencia: 12%", "bf-descripcion": "Migración de la plataforma NAC a Aruba Clearpass con despliegue de políticas 802.1X, profiling de dispositivos y guest access para todas las oficinas.", "bf-entregables": "E01: Diseño políticas NAC\nE02: Clearpass instalado en HA\nE03: Integración AD/LDAP\nE04: Piloto 10 oficinas\nE05: Rollout completo\nE06: Documentación operación", "bf-exclusiones": "• Segmentación de red (otro proyecto PRJ0044)\n• Renovación switches de acceso", "bf-interesados": "CISO | Sponsor | A favor | Alto | Gestionar de cerca\nJefe Redes | Ejecutor | A favor | Medio | Liderar implementación\nAruba Partner | Proveedor | A favor | Medio | Soporte técnico", "bf-presupuesto": "290250", "bf-contingencia": "12", "bf-justificacion": "• Plataforma NAC actual obsoleta y sin soporte\n• Incremento de dispositivos BYOD requiere mejor control\n• Requisitos DORA de resiliencia operativa digital", "bf-restricciones": "• Presupuesto: 290.251€\n• Plazo: 24 semanas\n• Sin interrupción de servicio durante migración", "bf-comunicaciones": "Semanal: Reunión equipo\nQuincenal: Informe CISO\nPor oficina: Validación migración", "bf-contrabeneficios": "• Periodo de coexistencia con plataforma antigua\n• Formación necesaria para equipo de Redes\n• Posible impacto en conectividad durante migración"}', '2026-03-20 11:03:35.126682+00');
INSERT INTO public.build_project_plans (id, id_proyecto, nombre, presupuesto, duracion_semanas, prioridad, plan_data, created_at) VALUES ('BLD-PRJ0006', 'PRJ0006', 'Exadata Mission Critical Oracle BD', 765240.00, 36, 'Media', '{"bf-edt": "1.0 | Diseño Arquitectura Exadata | Arquitecto BBDD\n2.0 | Adquisición y Rack | JdP\n3.0 | Instalación Nodo Primario | Oracle+DBA\n4.0 | Instalación Nodo DR | Oracle+DBA\n5.0 | Data Guard Config | DBA Senior\n6.0 | Migración Instancias | DBA\n7.0 | Pruebas DR | QA+DBA\n8.0 | Cierre | JdP", "bf-area": "Infraestructura", "bf-opex": "85000", "bf-capex": "325000", "bf-hitos": "S6: Diseño aprobado\nS12: Hardware instalado\nS20: Data Guard operativo\nS28: Migración completada\nS32: DR drill exitoso\nS36: Cierre", "bf-horas": "120", "bf-nombre": "Exadata Mission Critical Oracle BD", "bf-tarifa": "145", "bf-alcance": "2 nodos Oracle Exadata X9M, Data Guard activo-activo, 12 instancias Oracle migradas, monitorización OEM integrada.", "bf-calidad": "ISO 27001, PCI DSS, DORA Art.25, Política backup Cajamar", "bf-resumen": "Implantación de Oracle Exadata como plataforma de base de datos mission-critical para el core bancario, sustituyendo la infraestructura Oracle RAC actual.", "bf-riesgos": "Retraso entrega Exadata | 3 | 5 | Mitigar — PO anticipada con SLA\nCorrupción datos en migración | 2 | 5 | Mitigar — Backup completo + migración rolling\nFallo Data Guard | 2 | 5 | Mitigar — DR drill en S32\nSobrecarga DBA | 4 | 3 | Mitigar — Soporte Oracle Premium 24x7\nSobrecoste licencias | 2 | 4 | Mitigar — Contingencia 13%", "bf-sponsor": "CIO", "bf-duracion": "36", "bf-personal": "17400", "bf-criterios": "12/12 instancias migradas, DR failover <15min, 0 pérdida datos", "bf-objetivos": "Específico: 2 nodos Exadata con 12 instancias migradas\nMedible: Latencia OLTP <1ms, DR failover <15min\nAlcanzable: Con soporte Oracle Premium\nRelevante: Core bancario es el activo más crítico\nTemporal: 36 semanas", "bf-prioridad": "Media", "bf-servicios": "96500", "bf-asunciones": "• Oracle entrega hardware en 10 semanas\n• CPDs con capacidad eléctrica y refrigeración\n• DBAs N4 disponibles a tiempo completo", "bf-beneficios": "• Rendimiento 10x superior en queries OLTP del core bancario\n• DR activo-activo con RPO=0 y RTO<15min\n• Reducción 60% en tareas DBA por automatización\n• Consolidación de 12 instancias Oracle en 2 nodos Exadata", "bf-financiero": "BAC: 765,240€ | Contingencia: 13%", "bf-descripcion": "Despliegue de 2 nodos Oracle Exadata X9M en los CPDs principal y DR, migración de 12 instancias Oracle del core bancario, y configuración de Data Guard activo-activo.", "bf-entregables": "E01: Exadata nodo primario instalado\nE02: Exadata nodo DR instalado\nE03: Data Guard activo-activo\nE04: 12 instancias migradas\nE05: Pruebas DR completadas\nE06: Documentación DBA", "bf-exclusiones": "• Migración de aplicaciones (responsabilidad equipos desarrollo)\n• Upgrade de versión Oracle (se mantiene 19c)\n• Decommissioning servidores antiguos (fase posterior)", "bf-interesados": "CIO | Sponsor | A favor | Alto | Informes semanales\nCFO | Finanzas | Neutral | Alto | Justificar inversión con ROI\nJefe DBA | Ejecutor | A favor | Medio | Liderar migración\nOracle | Proveedor | A favor | Alto | SLA entrega y soporte", "bf-presupuesto": "765240", "bf-contingencia": "13", "bf-justificacion": "• Infraestructura Oracle RAC actual al límite de capacidad\n• Rendimiento degradado en picos de transacciones\n• Necesidad de DR activo-activo para servicios de pago\n• Cumplimiento DORA para resiliencia de servicios críticos", "bf-restricciones": "• Presupuesto: 765.240€\n• Plazo: 36 semanas\n• Migración sin downtime (rolling)\n• Ventanas mantenimiento solo domingos 02:00-06:00", "bf-comunicaciones": "Semanal: Reunión equipo DBA\nQuincenal: Informe CIO/CFO\nPor migración: Validación instancia\nPost-DR: Informe drill", "bf-contrabeneficios": "• Mayor inversión del portfolio (765.240€)\n• Complejidad extrema de migración de datos en caliente\n• 