INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('2864755b-2cc0-4aaa-89fb-6d2253b6d8f7', 'RHEL7-RHEL9-MIGRATION', 'Incompatibilidad crítica de aplicaciones core banking con RHEL 9 detectada tardíamente', 'Técnico', 3, 5, 'Ejecutar pruebas exhaustivas de compatibilidad en laboratorio durante semanas 7-12 con réplicas exactas de producción', 'Mantener servidores RHEL 7 en paralelo hasta validación completa, extender soporte Red Hat si necesario', 'Arquitecto de Sistemas', 'Fallos en pruebas de aplicaciones críticas durante fase de laboratorio', 'ABIERTO', '2026-03-23 12:24:25.311826');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('ea990a40-3d8a-4951-bb0c-abf0b45d7f6d', 'RHEL7-RHEL9-MIGRATION', 'Degradación de rendimiento en Bizum post-migración similar a INC-2026-0841', 'Técnico', 4, 4, 'Ejecutar pruebas de carga con volúmenes realistas >50,000 transacciones/día en laboratorio RHEL 9', 'Rollback inmediato a RHEL 7 si latencia >2s, activar servidores standby', 'Especialista Bizum', 'Latencia de transacciones Bizum >1.5s durante 5 minutos consecutivos', 'ABIERTO', '2026-03-23 12:24:25.320109');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('1e293889-e945-4d23-967a-97e63f707339', 'RHEL7-RHEL9-MIGRATION', 'Fallo en procedimientos de rollback durante migración de servidores críticos', 'Técnico', 2, 5, 'Validar scripts de rollback en cada servidor piloto, documentar tiempos de recuperación específicos', 'Restauración desde backups completos, activación de centro de respaldo si >4h downtime', 'Líder Técnico Migración', 'Script de rollback falla o tarda >30 minutos en ejecutarse', 'ABIERTO', '2026-03-23 12:24:25.324903');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('997db663-baea-4d9a-b932-c113ba422a1f', 'RHEL7-RHEL9-MIGRATION', 'Indisponibilidad de equipo clave durante ventanas de migración críticas', 'Recursos', 3, 4, 'Definir equipo backup para cada rol crítico, documentar procedimientos detallados para transferencia', 'Posponer migración de servidores críticos hasta disponibilidad de personal especializado', 'Project Manager', 'Ausencia confirmada de especialista Linux 48h antes de ventana crítica', 'ABIERTO', '2026-03-23 12:24:25.328122');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('a65c64c7-4450-4dc7-a85d-fcd298e2d849', 'RHEL7-RHEL9-MIGRATION', 'Retraso en adquisición de licencias RHEL 9 por departamento de compras', 'Recursos', 3, 3, 'Iniciar proceso de compra en semana 1, establecer acuerdos marco con Red Hat', 'Utilizar licencias de evaluación temporales, escalado a dirección para compra urgente', 'Responsable Compras IT', 'Licencias no confirmadas 4 semanas antes de inicio de migración', 'ABIERTO', '2026-03-23 12:24:25.333221');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('a43758e1-ff51-4eea-bd77-33dd8aaa1b36', 'RHEL7-RHEL9-MIGRATION', 'Extensión no planificada del alcance por descubrimiento de dependencias ocultas', 'Alcance', 4, 3, 'Inventario exhaustivo con herramientas automatizadas, entrevistas con administradores de cada aplicación', 'Solicitar extensión de presupuesto y cronograma, priorizar servidores críticos', 'Analista de Sistemas', 'Descubrimiento de >5 dependencias no documentadas durante análisis', 'ABIERTO', '2026-03-23 12:24:25.337808');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('3c051656-19d0-4e76-b054-180e3fde0736', 'RHEL7-RHEL9-MIGRATION', 'Cambios regulatorios PCI-DSS durante el proyecto que afecten configuración RHEL 9', 'Regulatorio', 2, 4, 'Monitorización mensual de actualizaciones PCI-DSS, contacto directo con auditor asignado', 'Ajustar configuraciones de seguridad, solicitar extensión de cronograma si necesario', 'Responsable Cumplimiento', 'Publicación de nueva versión PCI-DSS o comunicación oficial del auditor', 'ABIERTO', '2026-03-23 12:24:25.342298');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('a6a7664e-f022-4718-a2d5-3704a8831e24', 'RHEL7-RHEL9-MIGRATION', 'Fallo en certificación PCI-DSS post-migración por configuraciones de seguridad', 'Regulatorio', 3, 5, 'Pre-auditoría interna con herramientas automatizadas, validación con auditor externo en fase piloto', 'Corrección inmediata de configuraciones, re-certificación urgente antes de auditoría Banco España', 'CISO', 'Fallo en cualquier control PCI-DSS durante pre-auditoría', 'ABIERTO', '2026-03-23 12:24:25.345332');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('b6d89bb0-3363-42be-9f43-b3f8973fbe2d', 'RHEL7-RHEL9-MIGRATION', 'Interrupción no planificada >4h en servicios core banking durante migración', 'Externo', 2, 5, 'Ventanas de mantenimiento en horarios de menor actividad, servidores standby configurados', 'Activación inmediata de centro de respaldo, comunicación a clientes y regulador', 'Director de Operaciones', 'Downtime de servicios críticos >2h sin resolución clara', 'ABIERTO', '2026-03-23 12:24:25.34956');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('b0fa4cd6-682c-4d80-aec9-b7abef36f858', 'RHEL7-RHEL9-MIGRATION', 'Auditoría adelantada del Banco de España antes de completar migración', 'Externo', 2, 4, 'Comunicación proactiva con Banco de España sobre cronograma, documentación de progreso', 'Priorizar migración de servidores más críticos, solicitar prórroga justificada', 'Director de Cumplimiento', 'Notificación oficial de auditoría con <8 semanas de antelación', 'ABIERTO', '2026-03-23 12:24:25.352403');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('5d885284-2b9c-42f9-838b-f02d5c6f213c', 'OPENSHIFT-2026-001', 'Incompatibilidad entre versiones de Red Hat OpenShift y Docker existente en infraestructura legacy', 'Técnico', 4, 4, 'Ejecutar matriz de compatibilidad en laboratorio sandbox antes de instalación en producción. Validar versiones Docker 20.10+ con OpenShift 4.12+', 'Rollback a configuración anterior y upgrade Docker en ventana de mantenimiento extendida', 'Arquitecto de Infraestructura', 'Fallos en pruebas de integración Docker-OpenShift en sandbox', 'ABIERTO', '2026-03-24 10:04:21.201817');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('739d9aa9-b4f9-4b53-8767-5f84eff32d71', 'OPENSHIFT-2026-001', 'Insuficiencia de recursos hardware (CPU/RAM) en nodos worker para soportar carga de contenedores', 'Técnico', 3, 4, 'Dimensionar clústeres con 30% overhead. Implementar monitoring Prometheus desde día 1 con alertas en 80% uso CPU/RAM', 'Escalar horizontalmente añadiendo nodos worker adicionales o migrar workloads críticos a clúster dedicado', 'Especialista en Capacity Planning', 'Métricas de uso CPU >85% o RAM >90% sostenido por 15 minutos', 'ABIERTO', '2026-03-24 10:04:21.233026');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('f35daeea-fde3-43cb-b401-9123ba43e622', 'OPENSHIFT-2026-001', 'Pérdida de personal clave especializado en OpenShift durante el proyecto', 'Recursos', 3, 5, 'Formar equipo de 3 especialistas OpenShift internos. Documentar procedimientos críticos. Contratar consultor Red Hat como backup', 'Activar contrato de soporte Red Hat Premium y contratar consultor externo especializado', 'Director de Recursos Humanos IT', 'Renuncia o baja médica prolongada de especialista OpenShift principal', 'ABIERTO', '2026-03-24 10:04:21.245755');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('4191a291-277a-41e8-a9d9-ad9b9837f301', 'OPENSHIFT-2026-001', 'Fallos en configuración de red VLAN que impidan comunicación entre clústeres', 'Técnico', 4, 3, 'Validar configuración VLAN en laboratorio. Documentar topología de red. Realizar pruebas de conectividad entre todos los nodos', 'Reconfigurar VLANs en ventana de mantenimiento y ejecutar plan de rollback de configuración de red', 'Administrador de Redes', 'Pérdida de conectividad entre nodos de diferentes clústeres por >5 minutos', 'ABIERTO', '2026-03-24 10:04:21.250993');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('b2be947b-9242-4b8a-8b9e-ccb5a3c73f77', 'OPENSHIFT-2026-001', 'Retrasos en aprobaciones regulatorias para nueva plataforma de contenedores', 'Regulatorio', 4, 4, 'Iniciar proceso de aprobación regulatoria en paralelo a fase de diseño. Preparar documentación de seguridad y compliance desde semana 1', 'Implementar en entorno no-productivo hasta obtener aprobaciones. Diferir go-live 8 semanas', 'Chief Compliance Officer', 'Solicitud de información adicional por parte de reguladores o demora >4 semanas en respuesta', 'ABIERTO', '2026-03-24 10:04:21.254718');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('ca472be3-1a9b-4937-b2bf-571ec0f1acff', 'OPENSHIFT-2026-001', 'Fallos de seguridad en configuración de firewall que expongan contenedores', 'Técnico', 3, 5, 'Implementar security scanning automatizado con Twistlock. Realizar penetration testing antes de go-live. Configurar network policies restrictivas', 'Aislar clúster afectado inmediatamente. Activar protocolo de respuesta a incidentes de seguridad', 'Chief Information Security Officer', 'Detección de tráfico no autorizado o vulnerabilidades críticas en security scan', 'ABIERTO', '2026-03-24 10:04:21.259978');
INSERT INTO public.build_risks (id, id_proyecto, descripcion, categoria, probabilidad, impacto, plan_mitigacion, plan_contingencia, responsable, trigger_evento, estado, created_at) VALUES ('879a074f-0aac-4b4f-8136-aeccd28e741c', 'OPENSHIFT-2026-001', 'Problemas de integración con sistemas legacy durante migración CI/CD', 'Técnico', 4, 3, 'Desarrollar adaptadores de integración específicos. Realizar pruebas de integración incrementales. Mantener pipelines legacy en paralelo', 'Rollback a pipelines CI/CD legacy y diferir migración por fases más pequeñas', 'Arquitecto de Integración', 'Fallos en >20% de deployments automatizados o errores de integración recurrentes', 'ABIERTO', '2026-03-24 10:04:21.264013');
