INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-929F', 'Validación y cierre de incidencia', '{"silo": "SOPORTE", "tipo": "RUN", "orden": 7, "enriched": true, "checklist": ["Funcionalidad de liquidación operativa", "Logs sin errores críticos", "Casos de prueba ejecutados exitosamente", "Ticket actualizado con evidencias", "Usuario final notificado del cierre"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Sistema de Liquidaciones", "source": "IA"}, {"campo": "Base de datos", "valor": "Oracle 19c", "source": "IA"}, {"campo": "Puerto BD", "valor": "1521", "source": "IA"}, {"campo": "Logs aplicación", "valor": "/opt/liquidacion/logs/", "source": "IA"}, {"campo": "Usuario BD", "valor": "liquidacion_user", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución de incidencia", "detalle": "Confirmar que la funcionalidad reportada está operativa", "comandos": ["curl -X GET http://liquidacion-api:8080/health", "systemctl status liquidacion-service"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar logs de aplicación", "detalle": "Revisar que no hay errores recientes en logs", "comandos": ["tail -100 /opt/liquidacion/logs/application.log | grep ERROR", "grep -i ''exception\\|error'' /opt/liquidacion/logs/liquidacion_$(date +%Y%m%d).log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar casos de prueba", "detalle": "Realizar pruebas funcionales del proceso de liquidación", "comandos": ["./test_liquidacion.sh --mode=validation", "curl -X POST http://liquidacion-api:8080/test/liquidacion -d ''{\"test_mode\": true}''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar cierre", "detalle": "Actualizar ticket con evidencias de resolución", "comandos": ["echo ''Incidencia validada y cerrada'' > /tmp/cierre_$(date +%Y%m%d_%H%M).txt"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 0.5, 0.0, '2026-03-24 22:09:45.871708+00', '2026-04-01 18:31:53.958476+00', '2026-04-01 18:31:59.384656+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:53.958520"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.384720"}]', '2026-03-24 22:09:45.871708+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-7E77', 'Revisión de procesos de liquidación en sistema', '{"silo": "APLICACIONES", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Acceso al servidor establecido", "Estado de servicios verificado", "Configuración de procesos revisada", "Logs analizados", "Integración con BD comprobada", "Hallazgos documentados"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Sistema de Liquidaciones", "source": "IA"}, {"campo": "Servidor App", "valor": "srv-app-liquidacion-01", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080", "source": "IA"}, {"campo": "Logs sistema", "valor": "/opt/liquidacion/logs/", "source": "IA"}, {"campo": "Configuración", "valor": "/opt/liquidacion/config/", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor de aplicaciones", "detalle": "Conectar al servidor donde corre el sistema de liquidaciones", "comandos": ["ssh liquidacion@srv-app-liquidacion-01"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar estado de servicios", "detalle": "Verificar que los procesos de liquidación estén activos", "comandos": ["systemctl status liquidacion-service", "ps -ef | grep liquidacion", "netstat -tulpn | grep :8080"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar configuración de procesos", "detalle": "Revisar parámetros de configuración del sistema", "comandos": ["cat /opt/liquidacion/config/liquidacion.properties", "grep -i ''batch\\|schedule'' /opt/liquidacion/config/*.conf"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de procesos", "detalle": "Analizar logs de ejecución de procesos de liquidación", "comandos": ["tail -200 /opt/liquidacion/logs/proceso_liquidacion.log", "grep -i ''error\\|exception\\|failed'' /opt/liquidacion/logs/liquidacion_$(date +%Y%m%d).log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar integración con BD", "detalle": "Comprobar conectividad y consultas a base de datos", "comandos": ["curl -X GET http://localhost:8080/health/database", "grep -i ''database\\|connection'' /opt/liquidacion/logs/application.log | tail -20"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Documentar hallazgos", "detalle": "Generar reporte de revisión de procesos", "comandos": ["echo ''Revision procesos liquidacion - $(date)'' > /tmp/revision_procesos_$(date +%Y%m%d).txt"], "source_comandos": "IA"}], "skill_requerida": "Linux: Procesos", "requiere_negocio": false, "sla_tarea_minutos": 150}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 1.5, 0.0, '2026-03-24 22:09:45.849586+00', '2026-04-01 18:31:54.127968+00', '2026-04-01 18:31:59.485056+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:54.128012"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.485121"}]', '2026-03-24 22:09:45.849586+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260326-002A', 'Verificación estado conexiones activas', '{"silo": "REDES", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Conexiones activas en puerto 7777 verificadas", "Estados de conexión analizados", "Cajeros conectados identificados", "Sin conexiones en estado TIME_WAIT excesivo", "Límites de conexiones adecuados", "Recursos del sistema suficientes"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Controllers ATM", "valor": "10.0.80.10, 10.0.80.11", "source": "CMDB"}, {"campo": "Puerto ATM", "valor": "7777 (NDC+)", "source": "IA"}, {"campo": "Puerto HTTPS", "valor": "443", "source": "IA"}, {"campo": "Puerto SSH", "valor": "22", "source": "IA"}, {"campo": "Timeout conexión", "valor": "30 segundos", "source": "IA"}, {"campo": "Máx conexiones", "valor": "100 por controller", "source": "IA"}, {"campo": "Herramientas", "valor": "netstat, ss, lsof, nmap", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conexiones establecidas en controllers", "detalle": "Revisar conexiones activas en cada controller ATM", "comandos": ["ssh root@10.0.80.10", "netstat -tuln | grep :7777", "ss -tuln | grep :7777", "netstat -an | grep ESTABLISHED"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Contar conexiones por estado", "detalle": "Analizar distribución de estados de conexión", "comandos": ["netstat -an | awk ''/^tcp/ {print $6}'' | sort | uniq -c", "ss -s", "lsof -i :7777"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conexiones desde cajeros", "detalle": "Identificar cajeros conectados activamente", "comandos": ["netstat -an | grep :7777 | grep ESTABLISHED | wc -l", "netstat -an | grep :7777 | awk ''{print $5}'' | cut -d: -f1 | sort | uniq -c"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitoreo de conexiones en tiempo real", "detalle": "Observar establecimiento/cierre de conexiones", "comandos": ["watch -n 2 ''netstat -an | grep :7777 | wc -l''", "tcpdump -i any port 7777 -c 20"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar límites y recursos", "detalle": "Comprobar límites de conexiones y recursos del sistema", "comandos": ["ulimit -n", "cat /proc/sys/net/core/somaxconn", "cat /proc/sys/net/ipv4/tcp_max_syn_backlog"], "source_comandos": "IA"}], "skill_requerida": "Redes: Netstat", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Análisis', 'FTE-023', NULL, 'INC-20260326-3E15', NULL, 0.2, 0.0, '2026-03-26 11:21:54.632737+00', '2026-04-07 11:14:43.998936+00', NULL, '[{"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T11:14:43.998984"}, {"estado": "asignada", "columna": "Análisis", "timestamp": "2026-04-07T11:14:46.260180"}]', '2026-03-26 11:21:54.632737+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('BLD-1D671C', 'Estrategia almacenamiento persistente', '{"skill": "Documentación", "fase": "Fase 1", "enriched": false}', 'BUILD', 'Media', 'Backlog', 'FTE-057', 'AG-016', NULL, NULL, 20.0, 0.0, '2026-03-23 22:57:05.486369+00', NULL, NULL, '[]', '2026-03-23 22:57:05.486369+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('BLD-6E8DB4', 'Definición de entornos y topología', '{"skill": "Arquitecto", "fase": "Inicio", "enriched": false}', 'BUILD', 'Media', 'Backlog', NULL, 'openshift-onpremise', NULL, NULL, 12.0, 0.0, '2026-03-21 13:16:41.18558+00', NULL, NULL, '[]', '2026-03-21 13:16:41.18558+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-6909', 'Restaurar servicio y configurar bucket backup', '{"tipo": "RUN", "silo": "Cloud", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Servicio Cloud", "valor": "AWS S3/Azure Blob/GCP Storage", "source": "IA"}, {"campo": "Bucket", "valor": "bucket-backup-prod", "source": "IA"}, {"campo": "Región", "valor": "us-east-1 (sugerida)", "source": "IA"}, {"campo": "Herramientas", "valor": "AWS CLI/Azure CLI/gsutil", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado del servicio", "detalle": "Comprobar disponibilidad del servicio de almacenamiento", "comandos": ["aws s3 ls", "az storage account list", "gsutil ls"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Restaurar servicio principal", "detalle": "Reiniciar servicios y verificar conectividad", "comandos": ["systemctl restart servicio-backup", "systemctl status servicio-backup"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Configurar bucket backup", "detalle": "Crear/verificar bucket y permisos", "comandos": ["aws s3 mb s3://bucket-backup-prod", "aws s3api put-bucket-versioning --bucket bucket-backup-prod --versioning-configuration Status=Enabled"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Configurar políticas de backup", "detalle": "Establecer retención y ciclo de vida", "comandos": ["aws s3api put-bucket-lifecycle-configuration --bucket bucket-backup-prod --lifecycle-configuration file://lifecycle.json"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar backup", "detalle": "Ejecutar backup de prueba y verificar", "comandos": ["./script-backup.sh --test", "aws s3 ls s3://bucket-backup-prod/"], "source_comandos": "IA"}], "checklist": ["Servicio de backup operativo", "Bucket creado con permisos correctos", "Políticas de retención configuradas", "Backup de prueba exitoso", "Monitoreo configurado", "Documentación actualizada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-64BF', NULL, 0.2, 0.0, '2026-03-21 17:28:43.964044+00', NULL, NULL, '[]', '2026-03-21 17:28:43.964044+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-1083', 'Análisis de logs y errores backend', '{"tipo": "RUN", "silo": "Backend", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Servidor Backend", "valor": "SRV-APP-PRO-XX", "source": "IA"}, {"campo": "Ruta logs", "valor": "/var/log/aplicacion/ o /opt/app/logs/", "source": "IA"}, {"campo": "Tecnología", "valor": "Java/Node.js/Python", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080/3000/5000", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor backend", "detalle": "Conectar por SSH al servidor de aplicación", "comandos": ["ssh usuario@servidor-backend", "cd /var/log/aplicacion/"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs de aplicación", "detalle": "Analizar logs recientes buscando errores", "comandos": ["tail -f application.log", "grep -i error application.log | tail -50", "grep -i exception application.log | tail -20"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs del sistema", "detalle": "Verificar logs del sistema operativo", "comandos": ["journalctl -u nombre-servicio --since ''1 hour ago''", "tail -f /var/log/syslog", "dmesg | tail -20"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar recursos del sistema", "detalle": "Comprobar CPU, memoria y disco", "comandos": ["top -n 1", "free -h", "df -h", "iostat 1 5"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Identificar patrones de error", "detalle": "Buscar errores recurrentes y causa raíz", "comandos": ["awk ''/ERROR/ {print $0}'' application.log | sort | uniq -c | sort -nr", "grep -E ''(OutOfMemory|Connection|Timeout)'' application.log"], "source_comandos": "IA"}], "checklist": ["Logs de aplicación revisados", "Errores identificados y categorizados", "Recursos del sistema verificados", "Patrones de error documentados", "Causa raíz identificada", "Recomendaciones documentadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-64BF', NULL, 0.4, 0.0, '2026-03-21 17:28:43.958752+00', NULL, NULL, '[]', '2026-03-21 17:28:43.958752+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-B494', 'Verificar conexiones a base de datos', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor BD", "valor": "SRV-DB-PRO-XX", "source": "IA"}, {"campo": "Puerto BD", "valor": "1521 (Oracle) / 3306 (MySQL) / 5432 (PostgreSQL)", "source": "IA"}, {"campo": "Usuario conexión", "valor": "app_user / aplicacion", "source": "IA"}, {"campo": "Esquema/BD", "valor": "PRODUCCION / app_db", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Probar conectividad desde servidor aplicación", "comandos": ["telnet servidor-bd 1521", "ping servidor-bd", "nslookup servidor-bd"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión con cliente BD", "detalle": "Conectar usando cliente nativo de base de datos", "comandos": ["sqlplus usuario/password@servidor:1521/SID", "mysql -h servidor -u usuario -p", "psql -h servidor -U usuario -d database"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado del listener/servicio", "detalle": "Comprobar que el servicio de BD esté activo", "comandos": ["lsnrctl status", "systemctl status mysql", "systemctl status postgresql"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de conexión", "detalle": "Analizar logs de la base de datos", "comandos": ["tail -f /u01/app/oracle/diag/rdbms/*/alert_*.log", "tail -f /var/log/mysql/error.log", "tail -f /var/log/postgresql/postgresql-*.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar consultas básicas", "detalle": "Ejecutar consultas simples para verificar funcionalidad", "comandos": ["SELECT 1 FROM DUAL;", "SELECT 1;", "SELECT version();"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Servicio de BD operativo", "Conexión con credenciales exitosa", "Logs revisados sin errores críticos", "Consultas básicas funcionando", "Pool de conexiones verificado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-64BF', NULL, 0.5, 0.0, '2026-03-21 17:28:43.955153+00', NULL, NULL, '[]', '2026-03-21 17:28:43.955153+00');
