INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-8D47', 'Testing APIs con Postman - Identificar endpoints fallidos', '{"tipo": "RUN", "silo": "QA", "sla_tarea_minutos": 150, "contexto_cmdb": {"items": [{"campo": "Servidor API", "valor": "SRV-API-PRO-XX", "source": "IA"}, {"campo": "Puerto API", "valor": "8080/443/80", "source": "IA"}, {"campo": "Base URL", "valor": "https://api.empresa.com", "source": "IA"}, {"campo": "Herramienta", "valor": "Postman/Newman", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["Abrir Postman", "Importar colección de APIs", "Configurar variables: {{base_url}}, {{token}}"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar endpoints básicos", "detalle": "Verificar endpoints de health y autenticación", "comandos": ["GET {{base_url}}/health", "POST {{base_url}}/auth/login", "GET {{base_url}}/api/version"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar suite completa", "detalle": "Correr todos los tests de la colección", "comandos": ["Runner -> Seleccionar colección", "Configurar iteraciones y delay", "Ejecutar y capturar resultados"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Identificar endpoints fallidos", "detalle": "Analizar respuestas con códigos de error", "comandos": ["Filtrar por status 4xx y 5xx", "Revisar response body de errores", "Documentar endpoints con timeout"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte detallado", "detalle": "Crear reporte con endpoints fallidos y causas", "comandos": ["Export results to JSON", "newman run collection.json --reporters cli,json"], "source_comandos": "IA"}], "checklist": ["Colección Postman configurada", "Endpoints básicos probados", "Suite completa ejecutada", "Endpoints fallidos identificados", "Causas de fallo documentadas", "Reporte generado y compartido"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-64BF', NULL, 0.4, 0.0, '2026-03-21 17:28:43.950045+00', NULL, NULL, '[]', '2026-03-21 17:28:43.950045+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-A43D', 'Verificar conectividad con proveedor SMS', '{"silo": "Redes", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["IPs del proveedor identificadas", "Conectividad ICMP verificada", "Puerto SMPP 2775 accesible", "Puerto backup 2776 accesible", "Reglas firewall validadas", "Latencia dentro de límites aceptables"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Proveedor SMS", "valor": "No identificado en CMDB", "source": "CMDB"}, {"campo": "IP Proveedor", "valor": "A determinar desde config", "source": "IA"}, {"campo": "Puerto SMPP", "valor": "2775", "source": "IA"}, {"campo": "Backup SMPP", "valor": "Puerto 2776", "source": "IA"}, {"campo": "Timeout", "valor": "30 segundos", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Obtener IPs del proveedor SMS", "detalle": "Extraer configuración de conexión", "comandos": ["grep -i ''host\\|ip'' /etc/sms-gateway/config.xml", "nslookup proveedor-sms.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Test de conectividad básica", "detalle": "Verificar alcance de red", "comandos": ["ping -c 4 [IP_PROVEEDOR]", "traceroute [IP_PROVEEDOR]"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar puertos SMPP", "detalle": "Comprobar puertos primario y backup", "comandos": ["telnet [IP_PROVEEDOR] 2775", "nc -zv [IP_PROVEEDOR] 2775", "nc -zv [IP_PROVEEDOR] 2776"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar reglas de firewall", "detalle": "Validar configuración de seguridad", "comandos": ["iptables -L | grep 2775", "firewall-cmd --list-ports", "netstat -tulpn | grep :2775"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Test de latencia", "detalle": "Medir tiempos de respuesta", "comandos": ["hping3 -S -p 2775 -c 10 [IP_PROVEEDOR]", "mtr --report-cycles 10 [IP_PROVEEDOR]"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Baja', 'Backlog', 'FTE-101', NULL, 'INC-20260322-35D1', NULL, 3.0, 0.0, '2026-03-22 19:06:44.871788+00', NULL, NULL, '[]', '2026-03-22 19:06:44.871788+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-0517', 'Análisis de datos de liquidación con joins', '{"silo": "BBDD", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Conexión a BD establecida", "Estructura de tablas analizada", "Consultas con joins ejecutadas", "Performance optimizada", "Reporte de resultados generado", "Documentación de hallazgos completada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Liquidaciones", "source": "IA"}, {"campo": "Esquema principal", "valor": "LIQUIDACION_PROD", "source": "IA"}, {"campo": "Esquema auxiliar", "valor": "COMERCIO_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Herramienta", "valor": "SQL Developer / SQLPlus", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos", "detalle": "Establecer sesión en esquema de liquidaciones", "comandos": ["sqlplus liquidacion_user/password@srv-db-liquidacion-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar estructura de tablas", "detalle": "Revisar relaciones entre tablas de liquidación", "comandos": ["DESC liquidaciones;", "DESC transacciones;", "DESC comercios;", "SELECT table_name FROM user_tables WHERE table_name LIKE ''%LIQUID%'';"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar consulta con joins", "detalle": "Realizar análisis de datos con joins complejos", "comandos": ["SELECT l.liquidacion_id, l.monto, t.tipo_transaccion, c.nombre_comercio FROM liquidaciones l INNER JOIN transacciones t ON l.transaccion_id = t.id INNER JOIN comercios c ON t.comercio_id = c.id WHERE l.fecha >= TRUNC(SYSDATE-7);"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Optimizar consulta", "detalle": "Revisar plan de ejecución y optimizar performance", "comandos": ["EXPLAIN PLAN FOR SELECT...", "SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY);", "CREATE INDEX idx_liquidacion_fecha ON liquidaciones(fecha) TABLESPACE LIQUIDACION_IDX;"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de resultados", "detalle": "Exportar resultados del análisis", "comandos": ["SPOOL /tmp/analisis_liquidacion_$(date +%Y%m%d).txt", "SELECT COUNT(*), SUM(monto), AVG(monto) FROM vista_analisis_liquidacion;", "SPOOL OFF"], "source_comandos": "IA"}], "skill_requerida": "SQL: Inner Join", "requiere_negocio": false, "sla_tarea_minutos": 180}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 1.5, 0.0, '2026-03-24 22:09:45.858575+00', '2026-04-01 18:31:54.044257+00', '2026-04-01 18:31:59.448134+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:54.044302"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.448190"}]', '2026-03-24 22:09:45.858575+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260320-024', 'Implementar reglas NAC en oficinas comerciales', NULL, 'BUILD', 'Alta', 'En Progreso', 'FTE-016', 'PRJ0004', NULL, NULL, 16.0, 8.0, '2026-03-14 01:13:00.493591+00', '2026-03-14 20:13:00.493591+00', NULL, '[{"columna": "Backlog", "timestamp": "2026-03-14T01:13:00.493591"}, {"columna": "En Progreso", "timestamp": "2026-03-14T20:13:00.493591"}, {"estado": "pte_tercero", "columna": "Bloqueado", "timestamp": "2026-04-07T11:22:14.949261"}, {"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T11:22:15.115861"}, {"estado": "asignada", "columna": "Análisis", "timestamp": "2026-04-07T11:22:51.578975"}, {"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T11:22:51.634976"}]', '2026-03-20 08:13:01.435744+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-5E60', 'Diagnóstico inicial - Verificar conectividad y APIs', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Servidores", "valor": "SRV-WEB-XX, SRV-APP-XX, SRV-DB-XX", "source": "IA"}, {"campo": "APIs principales", "valor": "/api/users, /api/orders, /api/products", "source": "IA"}, {"campo": "Puertos", "valor": "80, 443, 8080, 3000", "source": "IA"}, {"campo": "Load Balancer", "valor": "LB-PRO-01", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Probar conectividad de red a servidores principales", "comandos": ["ping servidor-web", "ping servidor-app", "ping servidor-db", "nmap -p 80,443,8080 servidor"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar servicios web", "detalle": "Comprobar respuesta de servicios HTTP/HTTPS", "comandos": ["curl -I http://servidor-web", "curl -I https://servidor-web", "curl -k https://servidor-web/health"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar APIs principales", "detalle": "Verificar endpoints críticos de la aplicación", "comandos": ["curl -X GET http://servidor:8080/api/health", "curl -X GET http://servidor:8080/api/version", "curl -X GET http://servidor:8080/api/status"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar load balancer", "detalle": "Comprobar estado del balanceador de carga", "comandos": ["curl -I http://load-balancer/health", "Revisar panel de administración LB", "Verificar backend servers activos"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos iniciales", "detalle": "Registrar servicios operativos y no operativos", "comandos": ["Crear lista de servicios OK", "Crear lista de servicios con problemas", "Priorizar por criticidad"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Servicios web respondiendo", "APIs principales probadas", "Load balancer operativo", "Hallazgos documentados", "Próximos pasos definidos"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260321-64BF', NULL, 0.3, 0.0, '2026-03-21 17:28:43.913247+00', NULL, NULL, '[]', '2026-03-21 17:28:43.913247+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-2441', 'Validación y cierre - Documentar resolución', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "APIs Backend", "source": "IA"}, {"campo": "Entorno", "valor": "Producción", "source": "IA"}, {"campo": "Herramienta ticketing", "valor": "ServiceNow/JIRA", "source": "IA"}, {"campo": "Base conocimiento", "valor": "Confluence/SharePoint", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar información de resolución", "detalle": "Documentar causa raíz, acciones realizadas y tiempo de resolución", "comandos": ["Revisar logs de todas las tareas anteriores", "Consolidar timeline de eventos"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Crear documento de resolución", "detalle": "Generar reporte con causa raíz, solución aplicada y lecciones aprendidas", "comandos": ["Usar plantilla estándar de post-mortem", "Incluir capturas de pantalla relevantes"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Actualizar base de conocimiento", "detalle": "Crear/actualizar artículo KB para futuras referencias", "comandos": ["Publicar en base de conocimiento", "Etiquetar con palabras clave relevantes"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar ticket principal", "detalle": "Actualizar ticket con resolución final y cerrar", "comandos": ["Actualizar campo ''Resolución''", "Cambiar estado a ''Resuelto''", "Notificar a stakeholders"], "source_comandos": "IA"}], "checklist": ["Documento de resolución creado y revisado", "Artículo KB publicado", "Ticket actualizado con resolución detallada", "Stakeholders notificados del cierre", "Métricas de tiempo registradas", "Lecciones aprendidas documentadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.2, 0.0, '2026-03-21 17:51:30.369079+00', NULL, NULL, '[]', '2026-03-21 17:51:30.369079+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-F019', 'Restaurar servicios y configurar respaldos cloud', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Servicios", "valor": "APIs Backend + Base de datos", "source": "IA"}, {"campo": "Cloud Provider", "valor": "AWS/Azure/GCP", "source": "IA"}, {"campo": "Backup Tool", "valor": "AWS S3/Azure Backup", "source": "IA"}, {"campo": "Monitoring", "valor": "CloudWatch/Azure Monitor", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado de servicios", "detalle": "Comprobar que todos los servicios estén operativos", "comandos": ["systemctl status api-service", "systemctl status database-service", "docker ps -a (si containerizado)"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Iniciar servicios si están caídos", "detalle": "Levantar servicios en orden correcto", "comandos": ["systemctl start database-service", "systemctl start api-service", "systemctl enable api-service database-service"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Configurar respaldos cloud", "detalle": "Establecer políticas de backup automatizado", "comandos": ["aws s3 sync /data/backups s3://backup-bucket/", "aws backup create-backup-plan --backup-plan file://backup-plan.json", "crontab -e # Añadir backup schedule"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar respaldos", "detalle": "Verificar que los backups se ejecuten correctamente", "comandos": ["aws s3 ls s3://backup-bucket/ --recursive", "aws backup list-backup-jobs", "tail -f /var/log/backup.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Configurar monitoreo", "detalle": "Establecer alertas para servicios y backups", "comandos": ["aws cloudwatch put-metric-alarm --alarm-name ServiceHealth", "aws sns create-topic --name backup-alerts"], "source_comandos": "IA"}], "checklist": ["Todos los servicios están activos y estables", "Políticas de backup cloud configuradas", "Primer backup ejecutado exitosamente", "Alertas de monitoreo configuradas", "Documentación de configuración actualizada", "Prueba de restauración realizada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.2, 0.0, '2026-03-21 17:51:30.365115+00', NULL, NULL, '[]', '2026-03-21 17:51:30.365115+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-86FE', 'Análisis de logs y errores del sistema', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "Servidor APIs Backend", "source": "IA"}, {"campo": "Ruta logs aplicación", "valor": "/var/log/api-service/", "source": "IA"}, {"campo": "Ruta logs sistema", "valor": "/var/log/messages", "source": "IA"}, {"campo": "Ruta logs web", "valor": "/var/log/nginx/ o /var/log/apache2/", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Analizar logs de aplicación", "detalle": "Revisar logs de APIs para identificar errores", "comandos": ["tail -f /var/log/api-service/error.log", "grep -i ''error\\|exception\\|failed'' /var/log/api-service/*.log", "journalctl -u api-service --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs del sistema", "detalle": "Buscar errores a nivel de SO y servicios", "comandos": ["tail -100 /var/log/messages", "dmesg | grep -i error", "journalctl --priority=err --since today"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs de web server", "detalle": "Revisar logs de nginx/apache para errores HTTP", "comandos": ["tail -100 /var/log/nginx/error.log", "grep ''5[0-9][0-9]'' /var/log/nginx/access.log", "awk ''$9 >= 400'' /var/log/nginx/access.log | tail -20"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar recursos del sistema", "detalle": "Comprobar uso de CPU, memoria y disco", "comandos": ["top -n 1", "free -h", "df -h", "iostat -x 1 5"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de análisis", "detalle": "Consolidar hallazgos y patrones identificados", "comandos": ["grep -c ''ERROR'' /var/log/api-service/*.log", "awk ''{print $4}'' /var/log/nginx/access.log | sort | uniq -c | sort -nr"], "source_comandos": "IA"}], "checklist": ["Logs de aplicación analizados completamente", "Errores del sistema identificados", "Logs de web server revisados", "Recursos del sistema verificados", "Patrones de error documentados", "Reporte de análisis generado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.4, 0.0, '2026-03-21 17:51:30.360188+00', NULL, NULL, '[]', '2026-03-21 17:51:30.360188+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-FE16', 'Verificar conexiones a base de datos backend', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "MySQL/PostgreSQL/Oracle", "source": "IA"}, {"campo": "Puerto BD", "valor": "3306/5432/1521", "source": "IA"}, {"campo": "IP BD", "valor": "192.168.1.100 (ejemplo)", "source": "IA"}, {"campo": "Usuario conexión", "valor": "api_user", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar que el servidor puede alcanzar la BD", "comandos": ["ping 192.168.1.100", "telnet 192.168.1.100 3306", "nmap -p 3306 192.168.1.100"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión directa a BD", "detalle": "Conectar directamente desde servidor de APIs", "comandos": ["mysql -h 192.168.1.100 -u api_user -p", "psql -h 192.168.1.100 -U api_user -d database_name", "sqlplus api_user@192.168.1.100:1521/ORCL"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar pool de conexiones", "detalle": "Revisar configuración y estado del pool", "comandos": ["grep -i ''pool\\|connection'' /etc/api-service/config.yml", "netstat -an | grep :3306 | wc -l", "ss -tuln | grep :3306"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de conexión BD", "detalle": "Analizar errores de conexión en logs de BD", "comandos": ["tail -100 /var/log/mysql/error.log", "grep ''connection'' /var/log/postgresql/postgresql.log", "tail -f /u01/app/oracle/diag/rdbms/*/alert_*.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar queries básicas", "detalle": "Ejecutar consultas simples para validar funcionalidad", "comandos": ["SELECT 1;", "SHOW PROCESSLIST;", "SELECT COUNT(*) FROM information_schema.tables;"], "source_comandos": "IA"}], "checklist": ["Conectividad de red a BD verificada", "Conexión directa a BD exitosa", "Pool de conexiones configurado correctamente", "Logs de BD revisados sin errores críticos", "Queries básicas ejecutadas exitosamente", "Rendimiento de conexiones validado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.5, 0.0, '2026-03-21 17:51:30.35635+00', NULL, NULL, '[]', '2026-03-21 17:51:30.35635+00');
