INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-13B0', 'Testing APIs con Postman - Identificar endpoints fallidos', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 150, "contexto_cmdb": {"items": [{"campo": "API Base URL", "valor": "https://api.empresa.com/v1", "source": "IA"}, {"campo": "Endpoints principales", "valor": "/users, /orders, /products, /auth", "source": "IA"}, {"campo": "Herramienta testing", "valor": "Postman + Newman CLI", "source": "IA"}, {"campo": "Autenticación", "valor": "Bearer Token/API Key", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["postman --version", "newman --version", "Importar colección API existente"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar endpoints de autenticación", "detalle": "Validar login y obtención de tokens", "comandos": ["POST {{base_url}}/auth/login", "GET {{base_url}}/auth/validate", "Verificar response status 200"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Testing endpoints CRUD principales", "detalle": "Probar operaciones básicas en cada endpoint", "comandos": ["GET {{base_url}}/users", "POST {{base_url}}/users", "PUT {{base_url}}/users/{{user_id}}", "DELETE {{base_url}}/users/{{user_id}}"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Identificar endpoints fallidos", "detalle": "Documentar errores y códigos de respuesta", "comandos": ["newman run collection.json -e environment.json --reporters cli,json", "grep -E ''4[0-9][0-9]|5[0-9][0-9]'' newman-report.json", "Capturar response bodies de errores"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de testing", "detalle": "Consolidar resultados y endpoints problemáticos", "comandos": ["newman run collection.json --reporters htmlextra", "Exportar resultados a CSV", "Crear dashboard de métricas"], "source_comandos": "IA"}], "checklist": ["Entorno Postman configurado correctamente", "Autenticación API funcionando", "Todos los endpoints principales probados", "Endpoints fallidos identificados y documentados", "Reporte detallado de testing generado", "Métricas de performance capturadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.4, 0.0, '2026-03-21 17:51:30.351038+00', NULL, NULL, '[]', '2026-03-21 17:51:30.351038+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-89F8', 'Diagnóstico inicial - Verificar estado APIs y conectividad', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "APIs URL", "valor": "https://api.empresa.com", "source": "IA"}, {"campo": "Puertos APIs", "valor": "80, 443, 8080, 8443", "source": "IA"}, {"campo": "Load Balancer", "valor": "nginx/HAProxy/F5", "source": "IA"}, {"campo": "Monitoreo", "valor": "Nagios/Zabbix/Prometheus", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Comprobar acceso a URLs de APIs", "comandos": ["curl -I https://api.empresa.com/health", "ping api.empresa.com", "nslookup api.empresa.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar puertos de servicio", "detalle": "Verificar que puertos estén abiertos y respondiendo", "comandos": ["telnet api.empresa.com 443", "nmap -p 80,443,8080,8443 api.empresa.com", "netstat -tuln | grep -E '':80|:443|:8080|:8443''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado de APIs", "detalle": "Comprobar endpoints de health check", "comandos": ["curl -s https://api.empresa.com/health | jq", "curl -w ''%{http_code}'' https://api.empresa.com/status", "curl -I https://api.empresa.com/v1/ping"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar load balancer", "detalle": "Verificar configuración y estado del balanceador", "comandos": ["nginx -t", "systemctl status nginx", "curl -H ''Host: api.empresa.com'' http://localhost/health"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar DNS y certificados", "detalle": "Comprobar resolución DNS y validez de certificados SSL", "comandos": ["dig api.empresa.com", "openssl s_client -connect api.empresa.com:443 -servername api.empresa.com", "curl -vI https://api.empresa.com 2>&1 | grep -E ''SSL|TLS''"], "source_comandos": "IA"}], "checklist": ["Conectividad básica a APIs verificada", "Todos los puertos de servicio accesibles", "Endpoints de health check respondiendo", "Load balancer operativo", "DNS resolviendo correctamente", "Certificados SSL válidos"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260321-C7EB', NULL, 0.3, 0.0, '2026-03-21 17:51:30.342625+00', NULL, NULL, '[]', '2026-03-21 17:51:30.342625+00');
