INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-7DB1', 'Verificar configuración productos seguros', '{"silo": "SEGURIDAD", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Acceso WAF verificado", "40 políticas revisadas", "Protección seguros validada", "SSL offload confirmado", "Reporte generado", "Configuración documentada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "WAF", "valor": "NET-WAF-001 - BIG-IP ASM", "source": "CMDB"}, {"campo": "Versión", "valor": "17.1", "source": "CMDB"}, {"campo": "Policies", "valor": "40 políticas activas", "source": "CMDB"}, {"campo": "Virtual Servers", "valor": "25 servidores virtuales", "source": "CMDB"}, {"campo": "Ubicación", "valor": "CPD Madrid", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al WAF de aplicaciones", "detalle": "Conectar a la consola de administración del F5 BIG-IP", "comandos": ["ssh admin@waf-seguros.empresa.com", "tmsh show sys version"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar políticas de seguridad", "detalle": "Verificar configuración de las 40 políticas activas", "comandos": ["tmsh list asm policy", "tmsh show asm policy-stats", "tmsh list ltm virtual"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar protección aplicaciones seguros", "detalle": "Comprobar reglas específicas para módulos de seguros", "comandos": ["tmsh list asm policy seguros*", "tmsh show asm events", "tmsh list security firewall"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar SSL offload", "detalle": "Confirmar configuración de descarga SSL", "comandos": ["tmsh list ltm profile client-ssl", "tmsh show ltm profile client-ssl stats", "tmsh list sys crypto cert"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de configuración", "detalle": "Documentar estado actual de seguridad", "comandos": ["tmsh save sys config", "Exportar configuración", "Generar reporte compliance"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-7FFC', NULL, 3.0, 0.0, '2026-03-22 16:56:48.051349+00', NULL, NULL, '[]', '2026-03-22 16:56:48.051349+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-0DD9', 'Validación y cierre incidencia', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Sistema ticketing", "valor": "ServiceNow/Remedy", "source": "IA"}, {"campo": "Estado objetivo", "valor": "Cerrado - Resuelto", "source": "IA"}, {"campo": "Documentación", "valor": "Bitácora de resolución", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución completa", "detalle": "Confirmar que la incidencia está completamente resuelta", "comandos": ["Revisar logs de la solución aplicada", "Verificar que el servicio funciona correctamente"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Documentar solución", "detalle": "Actualizar el ticket con la causa raíz y solución aplicada", "comandos": ["Completar campos: Causa, Solución, Tiempo resolución"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar con usuario", "detalle": "Confirmar con el solicitante que el problema está resuelto", "comandos": ["Contactar usuario vía email/teléfono", "Obtener confirmación escrita"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado a cerrado con código de resolución", "comandos": ["Estado: Cerrado", "Código: Resuelto", "Fecha cierre: actual"], "source_comandos": "IA"}], "checklist": ["Servicio funcionando correctamente", "Usuario confirma resolución", "Documentación completa en ticket", "Estado cambiado a cerrado", "Tiempo de resolución registrado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-02BB', NULL, 0.2, 0.0, '2026-03-21 18:06:18.784118+00', NULL, NULL, '[]', '2026-03-21 18:06:18.784118+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-86E8', 'Restaurar servicio y configuración cloud', '{"tipo": "RUN", "silo": "Cloud", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Plataforma", "valor": "AWS/Azure/GCP", "source": "IA"}, {"campo": "Servicios", "valor": "EC2, RDS, Load Balancer", "source": "IA"}, {"campo": "Región", "valor": "us-east-1 / eastus", "source": "IA"}, {"campo": "Backup config", "valor": "S3/Blob Storage", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado actual", "detalle": "Revisar estado de servicios cloud afectados", "comandos": ["aws ec2 describe-instances --region us-east-1", "az vm list --output table", "gcloud compute instances list"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Identificar configuración backup", "detalle": "Localizar última configuración válida", "comandos": ["aws s3 ls s3://backup-configs/", "az storage blob list --container-name configs", "Revisar snapshots de instancias"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Restaurar servicios", "detalle": "Aplicar configuración desde backup", "comandos": ["aws ec2 run-instances --launch-template", "az vm create --image backup-image", "Restaurar security groups y networking"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar conectividad", "detalle": "Probar acceso y comunicación entre servicios", "comandos": ["curl -I http://load-balancer-url/health", "telnet database-endpoint 3306", "nslookup service-dns-name"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar aplicación", "detalle": "Confirmar funcionamiento end-to-end", "comandos": ["Probar login de usuarios", "Verificar transacciones críticas", "Monitorear métricas CloudWatch/Monitor"], "source_comandos": "IA"}], "checklist": ["Servicios cloud restaurados", "Configuración aplicada correctamente", "Conectividad verificada", "Aplicación funcional", "Métricas normalizadas", "Backup actualizado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-02BB', NULL, 0.2, 0.0, '2026-03-21 18:06:18.781612+00', NULL, NULL, '[]', '2026-03-21 18:06:18.781612+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-85FB', 'Análisis logs errores aplicación móvil', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Plataforma móvil", "valor": "iOS/Android", "source": "IA"}, {"campo": "Backend", "valor": "API REST/GraphQL", "source": "IA"}, {"campo": "Logs ubicación", "valor": "/var/log/mobile-app/", "source": "IA"}, {"campo": "Herramientas", "valor": "ELK Stack, Splunk, CloudWatch", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder a logs de aplicación", "detalle": "Conectar a servidores y localizar logs móvil", "comandos": ["ssh appuser@mobile-backend-server", "cd /var/log/mobile-app/", "ls -la *.log | head -10"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Filtrar errores recientes", "detalle": "Buscar errores en ventana de tiempo del incidente", "comandos": ["grep -i ''error\\|exception\\|fatal'' app.log | tail -50", "awk ''/2026-03-21 08:00/,/2026-03-21 12:00/'' error.log", "journalctl -u mobile-app --since ''2 hours ago''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar stack traces", "detalle": "Identificar causa raíz de errores", "comandos": ["grep -A 10 -B 5 ''NullPointerException\\|SQLException'' app.log", "cat crash.log | grep -E ''(at |Caused by)''", "Revisar códigos de error HTTP 4xx/5xx"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Correlacionar con métricas", "detalle": "Verificar impacto en rendimiento y usuarios", "comandos": ["Revisar dashboard APM (New Relic/Dynatrace)", "Analizar métricas de latencia API", "Verificar tasa de errores por endpoint"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte", "detalle": "Documentar hallazgos y recomendaciones", "comandos": ["Crear resumen de errores encontrados", "Identificar patrones temporales", "Sugerir acciones correctivas"], "source_comandos": "IA"}], "checklist": ["Logs de aplicación revisados", "Errores identificados y categorizados", "Stack traces analizados", "Correlación con métricas realizada", "Reporte de análisis generado", "Recomendaciones documentadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-02BB', NULL, 0.4, 0.0, '2026-03-21 18:06:18.777789+00', NULL, NULL, '[]', '2026-03-21 18:06:18.777789+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-4DF3', 'Verificar conexiones base de datos backend', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "MySQL/PostgreSQL/Oracle", "source": "IA"}, {"campo": "Puerto", "valor": "3306/5432/1521", "source": "IA"}, {"campo": "Backend server", "valor": "app-backend-01", "source": "IA"}, {"campo": "Connection pool", "valor": "HikariCP/c3p0", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad red", "detalle": "Probar conexión desde servidor backend a BD", "comandos": ["telnet db-server 3306", "nc -zv db-server 5432", "ping db-server -c 4"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar autenticación BD", "detalle": "Verificar credenciales y permisos", "comandos": ["mysql -h db-server -u appuser -p", "psql -h db-server -U appuser -d appdb", "sqlplus appuser/password@db-server:1521/ORCL"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar connection pool", "detalle": "Verificar estado del pool de conexiones", "comandos": ["grep -i ''connection.*pool'' /var/log/app/app.log", "jstack <java-pid> | grep -A 5 -B 5 ''HikariCP''", "Revisar métricas JMX del pool"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar queries activas", "detalle": "Verificar consultas bloqueantes o lentas", "comandos": ["SHOW PROCESSLIST; -- MySQL", "SELECT * FROM pg_stat_activity; -- PostgreSQL", "SELECT * FROM v$session WHERE status=''ACTIVE''; -- Oracle"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar recursos BD", "detalle": "Revisar CPU, memoria y espacio en disco", "comandos": ["SHOW STATUS LIKE ''Threads_connected''; -- MySQL", "SELECT count(*) FROM pg_stat_activity; -- PostgreSQL", "df -h /u01/app/oracle/ -- Oracle"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Autenticación BD exitosa", "Connection pool funcionando", "No hay queries bloqueantes", "Recursos BD suficientes", "Logs revisados sin errores"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-02BB', NULL, 0.5, 0.0, '2026-03-21 18:06:18.775132+00', NULL, NULL, '[]', '2026-03-21 18:06:18.775132+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-52E0', 'Testing APIs core banking con Postman', '{"tipo": "RUN", "silo": "QA", "sla_tarea_minutos": 150, "contexto_cmdb": {"items": [{"campo": "APIs core banking", "valor": "Cuentas, Transacciones, Pagos", "source": "IA"}, {"campo": "Base URL", "valor": "https://api-core-banking.bank.com", "source": "IA"}, {"campo": "Autenticación", "valor": "OAuth 2.0 / JWT Token", "source": "IA"}, {"campo": "Entorno", "valor": "Testing/Staging", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["Importar colección Core Banking APIs", "Configurar variables: {{base_url}}, {{auth_token}}", "Verificar certificados SSL"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Obtener token autenticación", "detalle": "Generar token válido para las pruebas", "comandos": ["POST {{base_url}}/auth/token", "Body: {\"client_id\": \"test\", \"client_secret\": \"xxx\"}", "Guardar access_token en variable"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Testing APIs Cuentas", "detalle": "Probar endpoints de gestión de cuentas", "comandos": ["GET {{base_url}}/accounts - Listar cuentas", "GET {{base_url}}/accounts/{id} - Detalle cuenta", "POST {{base_url}}/accounts - Crear cuenta"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Testing APIs Transacciones", "detalle": "Verificar operaciones transaccionales", "comandos": ["GET {{base_url}}/transactions - Historial", "POST {{base_url}}/transactions - Nueva transacción", "GET {{base_url}}/transactions/{id}/status"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Testing APIs Pagos", "detalle": "Probar sistema de pagos", "comandos": ["POST {{base_url}}/payments - Crear pago", "GET {{base_url}}/payments/{id} - Estado pago", "PUT {{base_url}}/payments/{id}/cancel"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte", "detalle": "Documentar resultados y generar reporte HTML", "comandos": ["newman run collection.json -e environment.json", "Exportar resultados a HTML", "Documentar casos fallidos"], "source_comandos": "IA"}], "checklist": ["Entorno Postman configurado", "Autenticación exitosa", "APIs Cuentas probadas", "APIs Transacciones verificadas", "APIs Pagos funcionales", "Reporte generado y documentado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-02BB', NULL, 0.4, 0.0, '2026-03-21 18:06:18.771438+00', NULL, NULL, '[]', '2026-03-21 18:06:18.771438+00');
