INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-CFA8', 'Diagnóstico inicial - Verificar estado servicios críticos', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "Web, BD, App, Load Balancer", "source": "IA"}, {"campo": "Herramientas monitoreo", "valor": "Nagios, Zabbix, PRTG", "source": "IA"}, {"campo": "Servidores core", "valor": "web-01, db-01, app-01", "source": "IA"}, {"campo": "Puertos críticos", "valor": "80, 443, 3306, 8080", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar servicios web", "detalle": "Comprobar estado de servidores web y proxy", "comandos": ["systemctl status httpd nginx", "curl -I http://web-server/health", "netstat -tlnp | grep '':80\\|:443''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar base de datos", "detalle": "Revisar estado de servicios de BD", "comandos": ["systemctl status mysql postgresql oracle", "mysqladmin ping -h localhost", "ps aux | grep -E ''mysql|postgres|oracle''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar aplicaciones", "detalle": "Comprobar servicios de aplicación", "comandos": ["systemctl status tomcat wildfly", "curl -I http://app-server:8080/health", "jps -l | grep -i app"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar load balancer", "detalle": "Revisar balanceador y distribución de carga", "comandos": ["systemctl status haproxy nginx", "curl -I http://load-balancer/status", "Revisar backend servers activos"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar conectividad", "detalle": "Probar comunicación entre componentes", "comandos": ["ping -c 3 web-server db-server app-server", "telnet db-server 3306", "nmap -p 80,443,3306,8080 target-servers"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Consultar monitoreo", "detalle": "Verificar alertas y métricas en herramientas", "comandos": ["Revisar dashboard Nagios/Zabbix", "Verificar alertas activas", "Comprobar métricas de rendimiento"], "source_comandos": "IA"}], "checklist": ["Servicios web operativos", "Base de datos accesible", "Aplicaciones funcionando", "Load balancer activo", "Conectividad verificada", "Sin alertas críticas en monitoreo", "Estado general: VERDE"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260321-02BB', NULL, 0.3, 0.0, '2026-03-21 18:06:18.764475+00', NULL, NULL, '[]', '2026-03-21 18:06:18.764475+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-03B7', 'Diagnóstico inicial - Verificar conectividad de red', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Diagnóstico inicial - Conectividad red", "source": "IA"}, {"campo": "Herramientas", "valor": "Cable tester, laptop, ping, traceroute", "source": "IA"}, {"campo": "Puertos comunes", "valor": "80, 443, 22, 23, 53, 3389", "source": "IA"}, {"campo": "Tiempo estimado", "valor": "45-60 minutos", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificación física", "detalle": "Comprobar conectividad física de red", "comandos": ["Verificar cable de red conectado", "Comprobar LEDs de enlace", "Probar con cable conocido bueno", "Verificar puerto switch"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Pruebas de conectividad básica", "detalle": "Realizar pruebas ping y conectividad IP", "comandos": ["ping -c 4 127.0.0.1", "ping -c 4 [gateway_local]", "ping -c 4 8.8.8.8", "ipconfig /all o ip addr show"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Diagnóstico de ruta", "detalle": "Analizar ruta de red y posibles bloqueos", "comandos": ["traceroute 8.8.8.8", "nslookup google.com", "telnet [servidor] [puerto]", "netstat -rn"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentación de hallazgos", "detalle": "Registrar resultados y determinar siguientes pasos", "comandos": ["Documentar resultados ping", "Capturar configuración IP", "Identificar punto de falla", "Recomendar acciones correctivas"], "source_comandos": "IA"}], "checklist": ["Conectividad física verificada", "Ping local exitoso", "Conectividad gateway comprobada", "Resolución DNS funcional", "Ruta de red analizada", "Punto de falla identificado"], "enriched": true}', 'RUN', 'Media', 'En Progreso', 'FTE-107', NULL, 'INC-20260322-23DB', NULL, 1.0, 0.0, '2026-03-22 11:34:34.782452+00', NULL, NULL, '[]', '2026-03-22 11:34:34.782452+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-867E', 'Diagnóstico inicial - Revisión sistema de rutas', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Sistema de gestión de rutas", "source": "IA"}, {"campo": "Protocolo", "valor": "OSPF/BGP", "source": "IA"}, {"campo": "Equipos", "valor": "Routers core y distribución", "source": "IA"}, {"campo": "Logs", "valor": "/var/log/routing.log", "source": "IA"}, {"campo": "Comandos", "valor": "show ip route, show ip ospf", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado general del sistema de rutas", "detalle": "Conectar a equipos de red y revisar estado de protocolos de enrutamiento", "comandos": ["show ip route summary", "show ip ospf neighbor", "show ip bgp summary"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar tabla de enrutamiento", "detalle": "Analizar rutas activas y detectar posibles inconsistencias", "comandos": ["show ip route", "show route-map", "show ip prefix-list"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad entre segmentos", "detalle": "Probar conectividad end-to-end en rutas críticas", "comandos": ["ping -c 5 [gateway_remoto]", "traceroute [destino_critico]"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar hallazgos iniciales", "detalle": "Registrar estado actual y anomalías detectadas", "comandos": ["show running-config | section router"], "source_comandos": "IA"}], "checklist": ["Estado de protocolos de enrutamiento verificado", "Tabla de rutas revisada completamente", "Conectividad entre segmentos probada", "Anomalías documentadas en ticket", "Logs de sistema revisados"], "enriched": true}', 'RUN', 'Baja', 'En Progreso', 'FTE-013', NULL, 'INC-20260322-7C5D', NULL, 2.0, 0.0, '2026-03-22 12:33:46.126129+00', NULL, NULL, '[]', '2026-03-22 12:33:46.126129+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-DE9B', 'Análisis logs sistema de gestión de rutas', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Logs ubicación", "valor": "/var/log/routing/, /var/log/syslog", "source": "IA"}, {"campo": "Herramientas", "valor": "grep, awk, tail", "source": "IA"}, {"campo": "Patrones búsqueda", "valor": "ERROR, WARN, OSPF, BGP", "source": "IA"}, {"campo": "Periodo análisis", "valor": "Últimas 24 horas", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder a logs del sistema de rutas", "detalle": "Conectar a servidores de gestión y localizar archivos de log", "comandos": ["cd /var/log/", "ls -la *routing* *ospf* *bgp*", "tail -100 /var/log/syslog"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Filtrar eventos relacionados con rutas", "detalle": "Buscar errores y warnings en protocolos de enrutamiento", "comandos": ["grep -i ''ospf\\|bgp\\|route'' /var/log/syslog | tail -50", "grep -E ''ERROR|WARN|FAIL'' /var/log/routing.log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar patrones de errores", "detalle": "Identificar frecuencia y tipos de errores en el periodo", "comandos": ["awk ''/OSPF|BGP/ {print $1, $2, $3, $6}'' /var/log/syslog | sort | uniq -c", "grep -c ''neighbor down'' /var/log/routing.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Generar resumen de hallazgos", "detalle": "Documentar eventos críticos y tendencias detectadas", "comandos": ["grep -A 5 -B 5 ''CRITICAL\\|EMERGENCY'' /var/log/routing.log"], "source_comandos": "IA"}], "checklist": ["Logs de sistema accedidos correctamente", "Eventos de enrutamiento filtrados", "Patrones de error identificados", "Frecuencia de incidencias calculada", "Resumen de hallazgos documentado", "Eventos críticos escalados si aplica"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-139', NULL, 'INC-20260322-7C5D', NULL, 3.0, 0.0, '2026-03-22 12:33:46.135786+00', NULL, NULL, '[]', '2026-03-22 12:33:46.135786+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-C034', 'Validación y cierre de incidencia', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Validación y cierre", "source": "IA"}, {"campo": "Sistema ticketing", "valor": "ServiceNow/ITSM", "source": "IA"}, {"campo": "Documentación", "valor": "Plantilla cierre incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Revisar resolución implementada", "detalle": "Verificar que la solución aplicada resuelve completamente el problema reportado", "comandos": ["Revisar logs de la implementación", "Validar funcionalidad afectada"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Confirmar con usuario/cliente", "detalle": "Contactar al reportante para validar que el servicio funciona correctamente", "comandos": ["Llamada/email de confirmación", "Pruebas funcionales con usuario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Documentar resolución", "detalle": "Completar la documentación del ticket con causa raíz y solución aplicada", "comandos": ["Actualizar ticket con resolución detallada", "Adjuntar evidencias"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado del ticket a cerrado y notificar a stakeholders", "comandos": ["Cambiar estado a ''Cerrado''", "Enviar notificación automática"], "source_comandos": "IA"}], "checklist": ["Resolución validada técnicamente", "Usuario confirma funcionamiento", "Documentación completa en ticket", "Evidencias adjuntadas", "Ticket cerrado correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-2859', NULL, 0.1, 0.0, '2026-03-21 18:16:10.570554+00', NULL, NULL, '[]', '2026-03-21 18:16:10.570554+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-29C4', 'Restaurar servicio y configurar cloud storage', '{"tipo": "RUN", "silo": "Cloud", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Plataforma", "valor": "AWS/Azure/GCP", "source": "IA"}, {"campo": "Servicio storage", "valor": "S3/Blob Storage/Cloud Storage", "source": "IA"}, {"campo": "Región", "valor": "us-east-1 (sugerida)", "source": "IA"}, {"campo": "Backup location", "valor": "/backup/cloud-storage/", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado actual del servicio", "detalle": "Comprobar el estado del servicio de cloud storage y identificar el problema", "comandos": ["aws s3 ls s3://bucket-name", "az storage account show --name storageaccount", "gsutil ls gs://bucket-name"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Restaurar desde backup", "detalle": "Identificar el backup más reciente y proceder con la restauración", "comandos": ["aws s3 sync s3://backup-bucket/ s3://production-bucket/", "az storage blob copy start-batch", "gsutil -m cp -r gs://backup-bucket/* gs://production-bucket/"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Configurar permisos y políticas", "detalle": "Aplicar las políticas de acceso y configuración necesarias", "comandos": ["aws s3api put-bucket-policy --bucket bucket-name --policy file://policy.json", "az storage account update --name storageaccount --default-action Allow", "gsutil iam set policy.json gs://bucket-name"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar funcionalidad", "detalle": "Probar operaciones de lectura/escritura para confirmar restauración", "comandos": ["aws s3 cp test-file.txt s3://bucket-name/", "az storage blob upload --file test.txt --name test.txt", "gsutil cp test-file.txt gs://bucket-name/"], "source_comandos": "IA"}], "checklist": ["Estado del servicio verificado", "Backup identificado y restaurado", "Permisos configurados correctamente", "Operaciones CRUD funcionando", "Monitoreo activado", "Documentación actualizada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-2859', NULL, 0.2, 0.0, '2026-03-21 18:16:10.565058+00', NULL, NULL, '[]', '2026-03-21 18:16:10.565058+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-8E2F', 'Revisar logs de errores backend', '{"tipo": "RUN", "silo": "Backend", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor aplicación", "valor": "app-backend-01", "source": "IA"}, {"campo": "Ruta logs", "valor": "/var/log/application/", "source": "IA"}, {"campo": "Framework", "valor": "Spring Boot/Node.js/Django", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080/3000/8000", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor backend", "detalle": "Conectarse al servidor donde se ejecuta la aplicación backend", "comandos": ["ssh admin@app-backend-01", "sudo su - appuser"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Localizar archivos de logs", "detalle": "Identificar y acceder a los logs de la aplicación y del sistema", "comandos": ["ls -la /var/log/application/", "ls -la /var/log/nginx/", "ls -la /var/log/tomcat/"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs de errores", "detalle": "Revisar los logs más recientes buscando errores, excepciones y warnings", "comandos": ["tail -f /var/log/application/error.log", "grep -i ''error\\|exception\\|fatal'' /var/log/application/app.log", "journalctl -u application-service --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Identificar patrones y causa raíz", "detalle": "Analizar la frecuencia y contexto de los errores encontrados", "comandos": ["grep -c ''ERROR'' /var/log/application/app.log", "awk ''/ERROR/ {print $1, $2, $5}'' /var/log/application/app.log | sort | uniq -c"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de análisis", "detalle": "Documentar los hallazgos y recomendaciones", "comandos": ["cat > error_analysis_report.txt", "echo ''Timestamp: $(date)'' >> error_analysis_report.txt"], "source_comandos": "IA"}], "checklist": ["Acceso al servidor confirmado", "Logs localizados y accesibles", "Errores identificados y categorizados", "Patrones de error analizados", "Causa raíz determinada", "Reporte generado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-2859', NULL, 0.3, 0.0, '2026-03-21 18:16:10.561076+00', NULL, NULL, '[]', '2026-03-21 18:16:10.561076+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-A686', 'Diagnosticar conexión a base de datos', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Servidor BD", "valor": "db-server-01", "source": "IA"}, {"campo": "Puerto BD", "valor": "3306 (MySQL) / 1521 (Oracle) / 5432 (PostgreSQL)", "source": "IA"}, {"campo": "Usuario conexión", "valor": "app_user", "source": "IA"}, {"campo": "Base de datos", "valor": "production_db", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar que el servidor de BD es accesible desde el cliente", "comandos": ["ping db-server-01", "telnet db-server-01 3306", "nmap -p 3306 db-server-01"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión a la base de datos", "detalle": "Intentar conectarse usando las credenciales de la aplicación", "comandos": ["mysql -h db-server-01 -u app_user -p production_db", "sqlplus app_user/password@db-server-01:1521/production_db", "psql -h db-server-01 -U app_user -d production_db"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar logs de la base de datos", "detalle": "Examinar los logs del motor de BD para identificar errores de conexión", "comandos": ["tail -f /var/log/mysql/error.log", "tail -f /u01/app/oracle/diag/rdbms/*/alert_*.log", "tail -f /var/log/postgresql/postgresql-*.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar estado del servicio", "detalle": "Comprobar que el servicio de BD esté ejecutándose correctamente", "comandos": ["systemctl status mysql", "systemctl status oracle", "systemctl status postgresql"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar configuración de conexiones", "detalle": "Verificar límites de conexiones y configuración de red", "comandos": ["SHOW VARIABLES LIKE ''max_connections'';", "SELECT name, value FROM v$parameter WHERE name=''processes'';", "SHOW max_connections;"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Credenciales de BD validadas", "Logs de BD revisados", "Servicio de BD funcionando", "Configuración de conexiones OK", "Causa raíz identificada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-2859', NULL, 0.4, 0.0, '2026-03-21 18:16:10.555702+00', NULL, NULL, '[]', '2026-03-21 18:16:10.555702+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-1C5A', 'Testing APIs con Postman - Validar endpoints', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Herramienta testing", "valor": "Postman", "source": "IA"}, {"campo": "Base URL", "valor": "https://api.production.com/v1", "source": "IA"}, {"campo": "Autenticación", "valor": "Bearer Token / API Key", "source": "IA"}, {"campo": "Endpoints", "valor": "/users, /products, /orders", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno en Postman", "detalle": "Crear colección y configurar variables de entorno", "comandos": ["Crear nueva colección ''API Testing''", "Configurar variable {{base_url}} = https://api.production.com/v1", "Configurar variable {{auth_token}} con token válido"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar endpoints GET", "detalle": "Probar todos los endpoints de consulta y verificar respuestas", "comandos": ["GET {{base_url}}/users", "GET {{base_url}}/products", "GET {{base_url}}/orders"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar endpoints POST", "detalle": "Probar creación de recursos con datos válidos", "comandos": ["POST {{base_url}}/users con JSON body", "POST {{base_url}}/products con JSON body", "POST {{base_url}}/orders con JSON body"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar endpoints PUT/PATCH", "detalle": "Probar actualización de recursos existentes", "comandos": ["PUT {{base_url}}/users/{id}", "PATCH {{base_url}}/products/{id}", "PUT {{base_url}}/orders/{id}"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar endpoints DELETE", "detalle": "Probar eliminación de recursos", "comandos": ["DELETE {{base_url}}/users/{id}", "DELETE {{base_url}}/products/{id}", "DELETE {{base_url}}/orders/{id}"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte de testing", "detalle": "Exportar resultados y generar reporte de cobertura", "comandos": ["Ejecutar colección completa", "Exportar resultados a JSON/HTML", "Generar reporte de cobertura"], "source_comandos": "IA"}], "checklist": ["Entorno Postman configurado", "Endpoints GET validados", "Endpoints POST funcionando", "Endpoints PUT/PATCH OK", "Endpoints DELETE probados", "Reporte generado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-2859', NULL, 0.3, 0.0, '2026-03-21 18:16:10.551619+00', NULL, NULL, '[]', '2026-03-21 18:16:10.551619+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-3719', 'Verificar APIs y códigos de respuesta HTTP', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "APIs objetivo", "valor": "REST APIs production", "source": "IA"}, {"campo": "Herramientas", "valor": "curl, Postman, Newman", "source": "IA"}, {"campo": "Códigos esperados", "valor": "200, 201, 400, 401, 404, 500", "source": "IA"}, {"campo": "Documentación", "valor": "Swagger/OpenAPI spec", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar APIs con curl", "detalle": "Probar endpoints principales y capturar códigos de respuesta HTTP", "comandos": ["curl -I -X GET https://api.production.com/v1/health", "curl -I -X GET https://api.production.com/v1/users", "curl -I -X POST https://api.production.com/v1/users -d ''{}''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar códigos de éxito (2xx)", "detalle": "Confirmar que las operaciones exitosas devuelven códigos apropiados", "comandos": ["curl -w ''%{http_code}'' -s -o /dev/null GET_ENDPOINT", "Verificar 200 para GET exitoso", "Verificar 201 para POST exitoso"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar códigos de error del cliente (4xx)", "detalle": "Probar escenarios de error del cliente y validar respuestas", "comandos": ["curl -w ''%{http_code}'' -X GET https://api.production.com/v1/users/999999", "curl -w ''%{http_code}'' -X POST https://api.production.com/v1/users", "curl -w ''%{http_code}'' -H ''Authorization: Bearer invalid'' GET_ENDPOINT"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar códigos de error del servidor (5xx)", "detalle": "Identificar si existen errores del servidor", "comandos": ["curl -w ''%{http_code}'' -X GET https://api.production.com/v1/stress-endpoint", "Revisar logs del servidor durante las pruebas", "Documentar cualquier código 5xx encontrado"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar matriz de códigos", "detalle": "Crear tabla de resumen con todos los códigos encontrados", "comandos": ["echo ''Endpoint | Método | Código | Estado'' > api_codes_report.txt", "Completar matriz con resultados", "Identificar discrepancias con documentación"], "source_comandos": "IA"}], "checklist": ["APIs principales probadas", "Códigos 2xx validados", "Códigos 4xx verificados", "Códigos 5xx documentados", "Matriz de códigos generada", "Discrepancias identificadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-2859', NULL, 0.4, 0.0, '2026-03-21 18:16:10.547101+00', NULL, NULL, '[]', '2026-03-21 18:16:10.547101+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-A327', 'Diagnóstico inicial - Verificar estado servicios', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "Web, BD, API, Cache", "source": "IA"}, {"campo": "Herramientas monitoreo", "valor": "systemctl, ps, netstat, top", "source": "IA"}, {"campo": "Puertos principales", "valor": "80, 443, 3306, 6379, 8080", "source": "IA"}, {"campo": "Logs sistema", "valor": "/var/log/messages, journalctl", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar servicios del sistema", "detalle": "Comprobar el estado de todos los servicios críticos", "comandos": ["systemctl status nginx", "systemctl status mysql", "systemctl status redis", "systemctl status application"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar procesos en ejecución", "detalle": "Listar procesos activos y verificar consumo de recursos", "comandos": ["ps aux | grep -E ''(nginx|mysql|redis|java|python)''", "top -b -n1 | head -20", "htop (si está disponible)"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad de red", "detalle": "Comprobar que los puertos de servicios estén abiertos", "comandos": ["netstat -tlnp | grep -E '':(80|443|3306|6379|8080)''", "ss -tlnp | grep -E '':(80|443|3306|6379|8080)''", "lsof -i :80,443,3306,6379,8080"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs del sistema", "detalle": "Examinar logs recientes para identificar errores o warnings", "comandos": ["journalctl --since ''30 minutes ago'' --priority=err", "tail -50 /var/log/messages", "dmesg | tail -20"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar recursos del sistema", "detalle": "Comprobar uso de CPU, memoria y disco", "comandos": ["df -h", "free -h", "uptime", "iostat 1 3"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar resumen de estado", "detalle": "Crear reporte inicial con el estado de todos los componentes", "comandos": ["echo ''=== DIAGNÓSTICO INICIAL ==='' > diagnostic_report.txt", "date >> diagnostic_report.txt", "echo ''Servicios, Procesos, Red, Logs, Recursos'' >> diagnostic_report.txt"], "source_comandos": "IA"}], "checklist": ["Servicios del sistema verificados", "Procesos críticos ejecutándose", "Conectividad de red OK", "Logs del sistema revisados", "Recursos del sistema normales", "Reporte inicial generado"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', 'FTE-037', NULL, 'INC-20260321-2859', NULL, 0.3, 0.0, '2026-03-21 18:16:10.539149+00', NULL, NULL, '[]', '2026-03-21 18:16:10.539149+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-BC96', 'Validación y cierre - Documentar resolución', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Documentación y cierre", "source": "IA"}, {"campo": "Sistema ITSM", "valor": "ServiceNow/Remedy", "source": "IA"}, {"campo": "Plantilla", "valor": "Resolución de incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar información de resolución", "detalle": "Documenta causa raíz, acciones realizadas y tiempo invertido", "comandos": ["Revisar logs de actividades", "Consolidar evidencias técnicas"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Actualizar ticket principal", "detalle": "Registra resolución detallada en el sistema ITSM", "comandos": ["Actualizar estado a ''Resuelto''", "Adjuntar evidencias"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar con usuario final", "detalle": "Confirmar que el servicio funciona correctamente", "comandos": ["Contactar usuario reportante", "Solicitar confirmación"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado final y documentar lecciones aprendidas", "comandos": ["Estado: Cerrado", "Categorizar correctamente"], "source_comandos": "IA"}], "checklist": ["Causa raíz documentada", "Acciones de resolución registradas", "Usuario confirma funcionamiento", "Ticket actualizado y cerrado", "Evidencias adjuntadas", "Tiempo de resolución registrado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.2, 0.0, '2026-03-21 18:34:32.725152+00', NULL, NULL, '[]', '2026-03-21 18:34:32.725152+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-FBB7', 'Restaurar servicio y configurar infraestructura cloud', '{"tipo": "RUN", "silo": "Cloud", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Plataforma", "valor": "AWS/Azure/GCP", "source": "IA"}, {"campo": "Herramientas", "valor": "Terraform, kubectl, AWS CLI", "source": "IA"}, {"campo": "Entorno", "valor": "Producción", "source": "IA"}, {"campo": "Backup", "valor": "Snapshot antes de cambios", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado actual", "detalle": "Revisar recursos cloud y configuración existente", "comandos": ["aws ec2 describe-instances", "kubectl get pods --all-namespaces", "terraform plan"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Crear backup de configuración", "detalle": "Respaldar estado actual antes de restauración", "comandos": ["aws ec2 create-snapshot", "kubectl get all -o yaml > backup.yaml"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Restaurar servicios", "detalle": "Aplicar configuración desde backup o repositorio", "comandos": ["terraform apply", "kubectl apply -f restore-config.yaml", "aws elbv2 modify-target-group"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar conectividad", "detalle": "Verificar que todos los servicios estén operativos", "comandos": ["curl -I https://api.dominio.com/health", "kubectl get svc", "aws elbv2 describe-target-health"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Monitorear métricas", "detalle": "Revisar dashboards y alertas post-restauración", "comandos": ["aws cloudwatch get-metric-statistics", "kubectl top pods"], "source_comandos": "IA"}], "checklist": ["Estado actual documentado", "Backup de configuración creado", "Servicios restaurados exitosamente", "Conectividad validada", "Métricas normalizadas", "Alertas despejadas", "Documentación actualizada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.2, 0.0, '2026-03-21 18:34:32.720156+00', NULL, NULL, '[]', '2026-03-21 18:34:32.720156+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-CDDD', 'Análisis de logs y errores del sistema', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Rutas logs", "valor": "/var/log/messages, /var/log/syslog", "source": "IA"}, {"campo": "Logs aplicación", "valor": "/opt/app/logs/, /var/log/tomcat/", "source": "IA"}, {"campo": "Herramientas", "valor": "grep, awk, journalctl", "source": "IA"}, {"campo": "Periodo", "valor": "Últimas 24 horas", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Revisar logs del sistema", "detalle": "Analizar logs principales del SO en busca de errores", "comandos": ["tail -f /var/log/messages", "journalctl -xe --since ''24 hours ago''", "grep -i error /var/log/syslog"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar logs de aplicación", "detalle": "Identificar errores específicos en logs de aplicaciones", "comandos": ["find /opt/app/logs -name ''*.log'' -mtime -1 -exec grep -l ERROR {} \\;", "tail -100 /var/log/tomcat/catalina.out"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Buscar patrones de error", "detalle": "Identificar errores recurrentes y correlaciones temporales", "comandos": ["grep -E ''(FATAL|ERROR|CRITICAL)'' /var/log/messages | awk ''{print $1, $2, $3}''", "journalctl -p err --since yesterday"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar recursos del sistema", "detalle": "Verificar uso de CPU, memoria y disco durante errores", "comandos": ["sar -u 1 10", "free -h", "df -h", "iostat -x 1 5"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de análisis", "detalle": "Consolidar hallazgos y recomendaciones", "comandos": ["echo ''Resumen de errores encontrados'' > analisis_logs.txt", "grep -c ERROR /var/log/messages >> analisis_logs.txt"], "source_comandos": "IA"}], "checklist": ["Logs del sistema revisados", "Logs de aplicación analizados", "Patrones de error identificados", "Recursos del sistema verificados", "Correlaciones temporales encontradas", "Reporte de análisis generado", "Recomendaciones documentadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.4, 0.0, '2026-03-21 18:34:32.716476+00', NULL, NULL, '[]', '2026-03-21 18:34:32.716476+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-F171', 'Testing APIs con Postman - Identificar puntos de fallo', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 150, "contexto_cmdb": {"items": [{"campo": "Herramienta", "valor": "Postman, Newman CLI", "source": "IA"}, {"campo": "Endpoints", "valor": "REST APIs principales", "source": "IA"}, {"campo": "Entorno", "valor": "Desarrollo/Testing", "source": "IA"}, {"campo": "Autenticación", "valor": "Bearer Token / API Key", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["Importar colección de APIs", "Configurar variables: {{base_url}}, {{api_key}}", "Verificar autenticación"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Ejecutar tests básicos", "detalle": "Probar endpoints principales con casos happy path", "comandos": ["GET /api/health", "GET /api/users", "POST /api/login", "GET /api/data"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar puntos de fallo", "detalle": "Ejecutar casos edge y validar respuestas de error", "comandos": ["POST con datos inválidos", "GET con IDs inexistentes", "Requests sin autenticación", "Timeout tests"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar respuestas y tiempos", "detalle": "Revisar códigos de estado, headers y performance", "comandos": ["Verificar status codes (200, 400, 401, 500)", "Medir response time", "Validar content-type headers"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de testing", "detalle": "Documentar resultados y puntos de fallo identificados", "comandos": ["newman run collection.json --reporters html", "Exportar resultados", "Documentar issues encontrados"], "source_comandos": "IA"}], "checklist": ["Entorno Postman configurado", "Tests básicos ejecutados", "Casos edge probados", "Puntos de fallo identificados", "Performance analizada", "Reporte generado", "Issues documentados"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.4, 0.0, '2026-03-21 18:34:32.70474+00', NULL, NULL, '[]', '2026-03-21 18:34:32.70474+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-AECC', 'Verificar conexión a base de datos backend', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Puerto BD", "valor": "1521 (Oracle) / 3306 (MySQL) / 5432 (PostgreSQL)", "source": "IA"}, {"campo": "IP Backend", "valor": "192.168.10.x", "source": "IA"}, {"campo": "Usuario conexión", "valor": "app_user", "source": "IA"}, {"campo": "Herramientas", "valor": "sqlplus, mysql, psql, telnet", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar que el backend puede alcanzar la base de datos", "comandos": ["telnet <ip_bd> 1521", "ping <ip_bd>", "nmap -p 1521,3306,5432 <ip_bd>"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión con cliente BD", "detalle": "Intentar conexión directa usando cliente de base de datos", "comandos": ["sqlplus app_user/password@<ip_bd>:1521/ORCL", "mysql -h <ip_bd> -u app_user -p", "psql -h <ip_bd> -U app_user -d database"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar configuración de conexión", "detalle": "Verificar parámetros de conexión en aplicación backend", "comandos": ["grep -r ''jdbc:'' /opt/app/config/", "cat /opt/app/config/database.properties", "netstat -an | grep :1521"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar estado del listener/servicio", "detalle": "Comprobar que el servicio de BD esté escuchando", "comandos": ["lsnrctl status", "systemctl status mysql", "systemctl status postgresql"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar consulta simple", "detalle": "Ejecutar query básica para validar funcionalidad", "comandos": ["SELECT 1 FROM DUAL;", "SELECT NOW();", "SELECT version();"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Cliente BD conecta exitosamente", "Configuración de conexión revisada", "Servicio de BD operativo", "Consulta simple ejecutada", "Logs de conexión revisados", "Backend conecta a BD correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.5, 0.0, '2026-03-21 18:34:32.709868+00', NULL, NULL, '[]', '2026-03-21 18:34:32.709868+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-E087', 'Diagnóstico inicial - Verificar estado APIs y conectividad', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "APIs objetivo", "valor": "Endpoints críticos del sistema", "source": "IA"}, {"campo": "Puertos", "valor": "80, 443, 8080, 8443", "source": "IA"}, {"campo": "Herramientas", "valor": "curl, wget, nmap, ping", "source": "IA"}, {"campo": "Timeout", "valor": "30 segundos", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Comprobar que los servidores API responden", "comandos": ["ping api.dominio.com", "nmap -p 80,443,8080 api.dominio.com", "telnet api.dominio.com 443"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar endpoints principales", "detalle": "Verificar que las APIs responden correctamente", "comandos": ["curl -I https://api.dominio.com/health", "curl -I https://api.dominio.com/status", "wget --spider https://api.dominio.com/api/v1"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar certificados SSL", "detalle": "Comprobar validez de certificados HTTPS", "comandos": ["openssl s_client -connect api.dominio.com:443", "curl -vI https://api.dominio.com 2>&1 | grep -i ssl"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Medir tiempos de respuesta", "detalle": "Evaluar performance de las APIs", "comandos": ["curl -w ''@curl-format.txt'' -o /dev/null https://api.dominio.com", "time curl https://api.dominio.com/health"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar estado inicial", "detalle": "Registrar hallazgos para comparación posterior", "comandos": ["echo ''Diagnóstico inicial APIs'' > diagnostico.log", "date >> diagnostico.log", "curl -s https://api.dominio.com/health >> diagnostico.log"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Endpoints principales probados", "Certificados SSL validados", "Tiempos de respuesta medidos", "Estado inicial documentado", "Issues identificados", "Baseline establecido"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260321-7C0D', NULL, 0.3, 0.0, '2026-03-21 18:34:32.698172+00', NULL, NULL, '[]', '2026-03-21 18:34:32.698172+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-81EB', 'Validación y cierre de incidencia', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Validación y cierre", "source": "IA"}, {"campo": "Sistema ticketing", "valor": "ServiceNow/Remedy", "source": "IA"}, {"campo": "Documentación", "valor": "Plantilla cierre incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Validar resolución completa", "detalle": "Verificar que todos los síntomas reportados han sido resueltos", "comandos": ["Revisar descripción inicial del ticket", "Validar cada punto del impacto reportado"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Confirmar con usuario/solicitante", "detalle": "Contactar al reportante para validación funcional", "comandos": ["Llamada telefónica o email de confirmación", "Documentar respuesta del usuario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Actualizar documentación", "detalle": "Completar campos obligatorios de cierre", "comandos": ["Causa raíz identificada", "Solución aplicada", "Acciones preventivas"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado a Resuelto/Cerrado", "comandos": ["Actualizar estado en sistema", "Notificar automáticamente a stakeholders"], "source_comandos": "IA"}], "checklist": ["Síntomas originales validados como resueltos", "Usuario/solicitante confirma resolución", "Causa raíz documentada", "Solución aplicada documentada", "Estado cambiado a Cerrado", "Notificaciones enviadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.2, 0.0, '2026-03-21 18:44:31.500712+00', NULL, NULL, '[]', '2026-03-21 18:44:31.500712+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-63B5', 'Restaurar servicio y componentes críticos', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "httpd, mysqld, tomcat, nginx", "source": "IA"}, {"campo": "Puertos estándar", "valor": "80, 443, 8080, 3306, 1521", "source": "IA"}, {"campo": "Logs ubicación", "valor": "/var/log/messages, /var/log/httpd/", "source": "IA"}, {"campo": "Scripts inicio", "valor": "/etc/init.d/ o systemctl", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Inventariar servicios caídos", "detalle": "Identificar todos los servicios críticos detenidos", "comandos": ["systemctl list-units --failed", "ps -ef | grep -E ''(httpd|mysql|tomcat|nginx)''", "netstat -tlnp | grep -E ''(80|443|8080|3306)''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Iniciar servicios en orden de dependencia", "detalle": "Restaurar servicios respetando dependencias", "comandos": ["systemctl start mysqld", "systemctl start httpd", "systemctl start tomcat", "systemctl enable <servicio>"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado y conectividad", "detalle": "Confirmar que servicios están operativos", "comandos": ["systemctl status <servicio>", "curl -I http://localhost", "telnet localhost <puerto>", "tail -f /var/log/messages"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar componentes críticos", "detalle": "Probar funcionalidad de componentes restaurados", "comandos": ["curl -X GET http://localhost/health", "mysql -u root -p -e ''SHOW DATABASES;''", "Probar endpoints críticos de aplicación"], "source_comandos": "IA"}], "checklist": ["Todos los servicios críticos iniciados", "Puertos de red escuchando correctamente", "Logs sin errores de inicio", "Conectividad de red verificada", "Componentes responden a health checks", "Aplicaciones accesibles para usuarios"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.5, 0.0, '2026-03-21 18:44:31.492165+00', NULL, NULL, '[]', '2026-03-21 18:44:31.492165+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-400F', 'Verificar conexión a base de datos backend', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Servidor Backend", "valor": "SRV-API-PRO-01", "source": "IA"}, {"campo": "Servidor BD", "valor": "SRV-DB-PRO-01", "source": "IA"}, {"campo": "Puerto BD", "valor": "5432 (PostgreSQL)", "source": "IA"}, {"campo": "Base de datos", "valor": "api_backend_db", "source": "IA"}, {"campo": "Usuario BD", "valor": "api_user", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Probar conexión desde servidor backend a BD", "comandos": ["ping srv-db-pro-01", "telnet srv-db-pro-01 5432", "nmap -p 5432 srv-db-pro-01"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión con cliente BD", "detalle": "Conectar directamente a la base de datos", "comandos": ["psql -h srv-db-pro-01 -p 5432 -U api_user -d api_backend_db", "\\l", "\\dt"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado del servicio BD", "detalle": "Comprobar que PostgreSQL esté ejecutándose", "comandos": ["systemctl status postgresql", "ps aux | grep postgres", "netstat -tlnp | grep 5432"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar configuración de conexión", "detalle": "Verificar parámetros de conexión en aplicación", "comandos": ["grep -r ''database\\|jdbc'' /opt/api-backend/config/", "cat /opt/api-backend/config/application.properties | grep -i db", "tail -f /var/log/api-backend/application.log | grep -i ''connection\\|database''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar consulta desde aplicación", "detalle": "Ejecutar endpoint que requiera BD", "comandos": ["curl -X GET http://localhost:8080/api/health/database", "curl -X GET http://localhost:8080/api/users/1", "tail -f /var/log/api-backend/application.log"], "source_comandos": "IA"}], "checklist": ["Conectividad de red a BD verificada", "Conexión directa con cliente BD exitosa", "Servicio PostgreSQL ejecutándose", "Configuración de conexión revisada", "Endpoint de BD respondiendo", "Logs de conexión analizados"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-096', NULL, 'INC-20260321-B278', NULL, 0.5, 0.0, '2026-03-21 19:01:53.504161+00', NULL, NULL, '[]', '2026-03-21 19:01:53.504161+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-7174', 'Validación funcional post-restauración', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Tipo validación", "valor": "Post-restauración BD", "source": "IA"}, {"campo": "Puerto BD", "valor": "1521 (Oracle) / 3306 (MySQL)", "source": "IA"}, {"campo": "Scripts validación", "valor": "/scripts/post_restore_check.sql", "source": "IA"}, {"campo": "Logs ubicación", "valor": "/u01/app/oracle/diag/ o /var/log/mysql/", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar integridad de datos", "detalle": "Ejecutar queries de validación de integridad", "comandos": ["SELECT COUNT(*) FROM tabla_critica;", "DBCC CHECKDB (SQL Server) o CHECK TABLE (MySQL)", "SELECT * FROM v$database; (Oracle)"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar conectividad aplicaciones", "detalle": "Probar conexiones desde aplicaciones críticas", "comandos": ["telnet <ip_bd> <puerto>", "Test de conexión desde app servers", "Validar pools de conexiones"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar casos de prueba funcionales", "detalle": "Realizar transacciones de negocio críticas", "comandos": ["Ejecutar script de pruebas funcionales", "Validar operaciones CRUD principales", "Verificar stored procedures críticos"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear rendimiento", "detalle": "Verificar métricas de performance post-restauración", "comandos": ["SELECT * FROM v$sysstat; (Oracle)", "SHOW STATUS LIKE ''Threads%''; (MySQL)", "Revisar tiempos de respuesta"], "source_comandos": "IA"}], "checklist": ["Integridad de datos verificada", "Conectividad aplicaciones OK", "Casos de prueba funcionales exitosos", "Métricas de rendimiento normales", "Logs sin errores críticos", "Usuarios finales notificados"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.3, 0.0, '2026-03-21 18:44:31.497164+00', NULL, NULL, '[]', '2026-03-21 18:44:31.497164+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-17DB', 'Analizar logs de errores backend', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Logs backend", "valor": "/var/log/app/, /opt/tomcat/logs/", "source": "IA"}, {"campo": "Formatos log", "valor": "catalina.out, error.log, access.log", "source": "IA"}, {"campo": "Herramientas", "valor": "grep, awk, tail, journalctl", "source": "IA"}, {"campo": "Patrones error", "valor": "ERROR, FATAL, Exception, Stack trace", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Localizar archivos de log relevantes", "detalle": "Identificar logs de aplicación y sistema del período del incidente", "comandos": ["find /var/log -name ''*.log'' -mtime -1", "ls -la /opt/tomcat/logs/", "journalctl --since ''1 hour ago'' --no-pager"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Filtrar errores críticos", "detalle": "Extraer mensajes de error del timeframe del incidente", "comandos": ["grep -i ''error\\|exception\\|fatal'' /var/log/app/*.log", "tail -1000 /opt/tomcat/logs/catalina.out | grep ERROR", "awk ''/ERROR/ {print $0}'' logfile.log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar stack traces y patrones", "detalle": "Identificar causa raíz de errores recurrentes", "comandos": ["grep -A 10 -B 2 ''Exception'' catalina.out", "sort error_messages.txt | uniq -c | sort -nr", "grep -E ''(OutOfMemory|Connection|Timeout)'' *.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar hallazgos", "detalle": "Compilar resumen de errores y posibles causas", "comandos": ["echo ''Análisis completado'' > analisis_logs.txt", "Documentar patrones identificados", "Recomendar acciones correctivas"], "source_comandos": "IA"}], "checklist": ["Logs del período identificados", "Errores críticos extraídos", "Stack traces analizados", "Patrones de error documentados", "Causa raíz identificada", "Recomendaciones generadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.3, 0.0, '2026-03-21 18:44:31.488201+00', NULL, NULL, '[]', '2026-03-21 18:44:31.488201+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-C3C6', 'Verificar conexiones a base de datos', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Puertos BD", "valor": "1521 (Oracle), 3306 (MySQL), 5432 (PostgreSQL)", "source": "IA"}, {"campo": "Herramientas test", "valor": "telnet, nc, sqlplus, mysql client", "source": "IA"}, {"campo": "Conexiones típicas", "valor": "App servers, web servers, ETL", "source": "IA"}, {"campo": "Pool conexiones", "valor": "Tomcat JDBC, WebLogic", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Probar alcance de red a servidores de BD", "comandos": ["ping <ip_servidor_bd>", "telnet <ip_bd> 1521", "nc -zv <ip_bd> 3306", "nmap -p 1521,3306,5432 <ip_bd>"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar autenticación BD", "detalle": "Validar credenciales y permisos de conexión", "comandos": ["sqlplus usuario/password@<ip_bd>:1521/SID", "mysql -h <ip_bd> -u usuario -p", "psql -h <ip_bd> -U usuario -d database"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar pools de conexión", "detalle": "Revisar estado de pools en servidores de aplicación", "comandos": ["grep -i ''connection pool'' /opt/tomcat/logs/catalina.out", "Revisar configuración JNDI", "SELECT * FROM v$session WHERE username IS NOT NULL; (Oracle)"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear conexiones activas", "detalle": "Verificar número y estado de conexiones", "comandos": ["SELECT COUNT(*) FROM v$session; (Oracle)", "SHOW PROCESSLIST; (MySQL)", "SELECT * FROM pg_stat_activity; (PostgreSQL)"], "source_comandos": "IA"}], "checklist": ["Conectividad de red a BD verificada", "Autenticación de usuarios exitosa", "Pools de conexión operativos", "Número de conexiones normal", "Sin errores en logs de conexión", "Aplicaciones conectando correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.3, 0.0, '2026-03-21 18:44:31.482858+00', NULL, NULL, '[]', '2026-03-21 18:44:31.482858+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-FF25', 'Diagnosticar APIs backend y códigos HTTP', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "APIs backend", "valor": "REST/SOAP endpoints", "source": "IA"}, {"campo": "Puertos API", "valor": "8080, 8443, 9080, 8090", "source": "IA"}, {"campo": "Herramientas test", "valor": "curl, postman, wget", "source": "IA"}, {"campo": "Códigos HTTP", "valor": "200, 404, 500, 503, 401, 403", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Inventariar endpoints API", "detalle": "Identificar todas las APIs backend críticas", "comandos": ["curl -I http://localhost:8080/api/health", "netstat -tlnp | grep -E ''(8080|8443|9080)''", "ps -ef | grep -E ''(tomcat|jetty|nodejs)''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar endpoints principales", "detalle": "Ejecutar requests HTTP a APIs críticas", "comandos": ["curl -X GET http://api-server:8080/api/status", "curl -X POST -H ''Content-Type: application/json'' -d ''{}'' http://api/test", "wget --spider http://api-server:8080/health"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar códigos de respuesta", "detalle": "Interpretar códigos HTTP y diagnosticar problemas", "comandos": ["curl -w ''%{http_code}\\n'' -s -o /dev/null http://api/endpoint", "Documentar códigos 4xx y 5xx", "grep -E ''(404|500|503)'' /var/log/httpd/access.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar logs de aplicación", "detalle": "Revisar logs para errores de API", "comandos": ["tail -100 /opt/app/logs/api.log", "grep -i ''api\\|endpoint\\|http'' /var/log/messages", "journalctl -u api-service --since ''30 minutes ago''"], "source_comandos": "IA"}], "checklist": ["Endpoints API identificados", "Conectividad HTTP verificada", "Códigos de respuesta analizados", "Errores 4xx/5xx documentados", "Logs de aplicación revisados", "Performance de APIs normal"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-7A55', NULL, 0.4, 0.0, '2026-03-21 18:44:31.478539+00', NULL, NULL, '[]', '2026-03-21 18:44:31.478539+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-E922', 'Verificar conectividad y DNS móvil', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "DNS servers", "valor": "8.8.8.8, 1.1.1.1, DNS corporativo", "source": "IA"}, {"campo": "Herramientas móvil", "valor": "ping, nslookup, traceroute, speedtest", "source": "IA"}, {"campo": "APNs móviles", "valor": "internet.movistar.es, orangeworld", "source": "IA"}, {"campo": "Puertos test", "valor": "53 (DNS), 80, 443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Probar alcance a internet desde dispositivos móviles", "comandos": ["ping -c 4 8.8.8.8", "ping -c 4 google.com", "curl -I https://www.google.com", "traceroute 8.8.8.8"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Diagnosticar resolución DNS", "detalle": "Verificar que DNS resuelve correctamente", "comandos": ["nslookup google.com", "nslookup google.com 8.8.8.8", "dig @1.1.1.1 empresa.com", "cat /etc/resolv.conf"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar APN y configuración móvil", "detalle": "Verificar configuración de red móvil", "comandos": ["Verificar APN configurado", "Probar datos móviles vs WiFi", "speedtest-cli (si disponible)", "Revisar configuración proxy"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear latencia y pérdida", "detalle": "Medir calidad de conexión móvil", "comandos": ["ping -c 20 8.8.8.8 | tail -1", "mtr --report-cycles 10 google.com", "Documentar % pérdida de paquetes", "Medir jitter y latencia"], "source_comandos": "IA"}], "checklist": ["Conectividad a internet verificada", "DNS resolviendo correctamente", "APN móvil configurado", "Latencia dentro de rangos normales", "Sin pérdida significativa de paquetes", "Velocidad de datos aceptable"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-7A55', NULL, 0.3, 0.0, '2026-03-21 18:44:31.473653+00', NULL, NULL, '[]', '2026-03-21 18:44:31.473653+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-940D', 'Diagnóstico inicial - Verificar estado servicios críticos', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "httpd, mysqld, sshd, network, firewall", "source": "IA"}, {"campo": "Comandos diagnóstico", "valor": "systemctl, ps, netstat, df, top", "source": "IA"}, {"campo": "Logs sistema", "valor": "/var/log/messages, /var/log/syslog", "source": "IA"}, {"campo": "Métricas clave", "valor": "CPU, memoria, disco, red", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar servicios del sistema", "detalle": "Comprobar estado de servicios críticos", "comandos": ["systemctl status sshd httpd mysqld", "systemctl list-units --failed", "ps -ef | grep -E ''(httpd|mysql|sshd)''", "service --status-all | grep -E ''(\\+|\\-)''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar recursos del sistema", "detalle": "Verificar uso de CPU, memoria y disco", "comandos": ["top -bn1 | head -20", "free -h", "df -h", "iostat -x 1 3", "vmstat 1 3"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad de red", "detalle": "Probar conectividad interna y externa", "comandos": ["ping -c 3 gateway_ip", "netstat -tlnp | head -20", "ss -tuln", "iptables -L -n | head -10"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de sistema", "detalle": "Buscar errores recientes en logs", "comandos": ["tail -50 /var/log/messages", "journalctl --since ''1 hour ago'' --no-pager", "dmesg | tail -20", "grep -i error /var/log/messages | tail -10"], "source_comandos": "IA"}], "checklist": ["Servicios críticos ejecutándose", "Recursos del sistema normales", "Conectividad de red operativa", "Sin errores críticos en logs", "Puertos de red escuchando", "Sistema respondiendo normalmente"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', 'FTE-037', NULL, 'INC-20260321-7A55', NULL, 0.3, 0.0, '2026-03-21 18:44:31.46449+00', NULL, NULL, '[]', '2026-03-21 18:44:31.46449+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-D059', 'Restaurar servicio y componentes afectados', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "Web, BBDD, App Server", "source": "IA"}, {"campo": "Puertos estándar", "valor": "80, 443, 1521, 8080", "source": "IA"}, {"campo": "Logs principales", "valor": "/var/log/messages, /var/log/syslog", "source": "IA"}, {"campo": "Comandos restart", "valor": "systemctl restart <servicio>", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Identificar servicios afectados", "detalle": "Revisar estado de servicios críticos del sistema", "comandos": ["systemctl status httpd", "systemctl status nginx", "systemctl status oracle", "systemctl status tomcat"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar conectividad de red", "detalle": "Comprobar puertos y conectividad básica", "comandos": ["netstat -tulpn | grep LISTEN", "ping -c 4 gateway", "telnet localhost 80"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Reiniciar servicios en orden", "detalle": "Restaurar servicios siguiendo dependencias", "comandos": ["systemctl restart network", "systemctl restart oracle", "systemctl restart httpd"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar restauración", "detalle": "Confirmar que servicios están operativos", "comandos": ["systemctl is-active httpd", "curl -I http://localhost", "ps aux | grep java"], "source_comandos": "IA"}], "checklist": ["Estado de servicios verificado", "Conectividad de red confirmada", "Servicios reiniciados exitosamente", "Aplicaciones respondiendo correctamente", "Logs revisados sin errores críticos", "Ticket actualizado con resolución"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-F339', NULL, 0.2, 0.0, '2026-03-21 18:53:47.438043+00', NULL, NULL, '[]', '2026-03-21 18:53:47.438043+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-9045', 'Diagnóstico inicial - Verificar estado servicios críticos', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Servicios críticos", "valor": "httpd, nginx, oracle, mysql, tomcat", "source": "IA"}, {"campo": "Puertos monitoreo", "valor": "22, 80, 443, 1521, 3306, 8080", "source": "IA"}, {"campo": "Procesos clave", "valor": "java, httpd, mysqld, oracle", "source": "IA"}, {"campo": "Recursos sistema", "valor": "CPU, Memoria, Disco, Red", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar servicios del sistema", "detalle": "Comprobar estado de servicios críticos", "comandos": ["systemctl status httpd nginx oracle mysql", "ps aux | grep -E ''(java|httpd|mysqld|oracle)''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar conectividad", "detalle": "Probar puertos y conectividad de red", "comandos": ["netstat -tulpn | grep -E '':(22|80|443|1521|3306|8080)''", "ss -tulpn | grep LISTEN"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Monitorear recursos", "detalle": "Verificar uso de CPU, memoria y disco", "comandos": ["top -bn1 | head -20", "free -h", "df -h", "iostat 1 3"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs recientes", "detalle": "Buscar errores críticos en logs del sistema", "comandos": ["journalctl -xe --since ''30 minutes ago''", "tail -50 /var/log/messages | grep -i error"], "source_comandos": "IA"}], "checklist": ["Estado de servicios verificado", "Conectividad de puertos confirmada", "Recursos del sistema monitoreados", "Logs revisados", "Problemas críticos identificados", "Diagnóstico inicial completado"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260321-F339', NULL, 0.3, 0.0, '2026-03-21 18:53:47.369343+00', NULL, NULL, '[]', '2026-03-21 18:53:47.369343+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-6F5F', 'Análisis de logs y errores del sistema', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Logs sistema", "valor": "/var/log/messages, /var/log/syslog", "source": "IA"}, {"campo": "Logs aplicación", "valor": "/var/log/httpd/, /opt/app/logs/", "source": "IA"}, {"campo": "Herramientas análisis", "valor": "grep, awk, tail, journalctl", "source": "IA"}, {"campo": "Patrones error", "valor": "ERROR, FATAL, Exception, Failed", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Revisar logs de sistema", "detalle": "Analizar logs principales del sistema operativo", "comandos": ["tail -100 /var/log/messages", "journalctl -xe --since ''1 hour ago''", "grep -i error /var/log/syslog"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar logs de aplicación", "detalle": "Buscar errores en logs de servicios específicos", "comandos": ["tail -200 /var/log/httpd/error_log", "find /opt/app/logs/ -name ''*.log'' -mtime -1 -exec grep -l ERROR {} \\;"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar patrones de error", "detalle": "Buscar errores recurrentes y críticos", "comandos": ["grep -i ''exception\\|error\\|fatal'' /var/log/messages | tail -50", "awk ''/ERROR/ {print $1, $2, $3, $NF}'' /var/log/application.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Generar reporte de análisis", "detalle": "Documentar hallazgos y recomendaciones", "comandos": ["grep -c ERROR /var/log/messages", "ls -la /var/log/ | grep $(date +%b)"], "source_comandos": "IA"}], "checklist": ["Logs de sistema revisados", "Logs de aplicación analizados", "Patrones de error identificados", "Errores críticos documentados", "Reporte de análisis generado", "Recomendaciones proporcionadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-F339', NULL, 0.3, 0.0, '2026-03-21 18:53:47.433774+00', NULL, NULL, '[]', '2026-03-21 18:53:47.433774+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-58EB', 'Verificar conexiones a base de datos', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Puerto Oracle", "valor": "1521", "source": "IA"}, {"campo": "Puerto MySQL", "valor": "3306", "source": "IA"}, {"campo": "Puerto PostgreSQL", "valor": "5432", "source": "IA"}, {"campo": "Herramientas conexión", "valor": "sqlplus, mysql, psql, telnet", "source": "IA"}, {"campo": "Archivos config", "valor": "tnsnames.ora, my.cnf, postgresql.conf", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar acceso a puertos de base de datos", "comandos": ["telnet dbserver 1521", "telnet dbserver 3306", "netstat -an | grep :1521"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conexión Oracle", "detalle": "Verificar acceso a instancias Oracle", "comandos": ["sqlplus system/password@dbserver:1521/ORCL", "tnsping ORCL", "lsnrctl status"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar conexión MySQL/PostgreSQL", "detalle": "Verificar acceso a otras bases de datos", "comandos": ["mysql -h dbserver -u root -p -e ''SELECT 1''", "psql -h dbserver -U postgres -c ''SELECT version()''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar configuración", "detalle": "Revisar archivos de configuración de conexión", "comandos": ["cat $ORACLE_HOME/network/admin/tnsnames.ora", "grep -v ''^#'' /etc/my.cnf"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Conexiones Oracle probadas", "Conexiones MySQL/PostgreSQL validadas", "Configuración de conexión revisada", "Errores de conexión documentados", "Estado de servicios BBDD confirmado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-F339', NULL, 0.5, 0.0, '2026-03-21 18:53:47.428883+00', NULL, NULL, '[]', '2026-03-21 18:53:47.428883+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-B23B', 'Validación con Postman de endpoints críticos', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Endpoints críticos", "valor": "/api/health, /api/login, /api/users", "source": "IA"}, {"campo": "Métodos HTTP", "valor": "GET, POST, PUT, DELETE", "source": "IA"}, {"campo": "Headers requeridos", "valor": "Content-Type, Authorization", "source": "IA"}, {"campo": "Códigos esperados", "valor": "200, 201, 400, 401, 500", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar colección Postman", "detalle": "Preparar requests para endpoints críticos", "comandos": ["Crear nueva colección ''API_Validation''", "Configurar variables de entorno (base_url, token)"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar endpoint de salud", "detalle": "Probar endpoint de health check", "comandos": ["GET {{base_url}}/api/health", "Verificar response 200 OK", "Validar JSON response structure"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar autenticación", "detalle": "Validar proceso de login y tokens", "comandos": ["POST {{base_url}}/api/login", "Body: {\"username\":\"test\",\"password\":\"test\"}", "Extraer token de response"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar endpoints funcionales", "detalle": "Probar operaciones CRUD principales", "comandos": ["GET {{base_url}}/api/users (con Authorization header)", "POST {{base_url}}/api/users (crear usuario)", "Validar responses y status codes"], "source_comandos": "IA"}], "checklist": ["Colección Postman configurada", "Endpoint health validado", "Autenticación funcionando", "Endpoints CRUD probados", "Status codes correctos", "Reporte de validación generado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-F339', NULL, 0.3, 0.0, '2026-03-21 18:53:47.425211+00', NULL, NULL, '[]', '2026-03-21 18:53:47.425211+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-33CF', 'Testing APIs y códigos HTTP de respuesta', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 75, "contexto_cmdb": {"items": [{"campo": "APIs a probar", "valor": "REST, SOAP, GraphQL", "source": "IA"}, {"campo": "Herramientas testing", "valor": "curl, Postman, newman", "source": "IA"}, {"campo": "Códigos HTTP", "valor": "2xx (success), 4xx (client), 5xx (server)", "source": "IA"}, {"campo": "Formatos response", "valor": "JSON, XML, HTML", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Testing con curl", "detalle": "Probar APIs usando comandos curl", "comandos": ["curl -X GET http://api.example.com/users -H ''Accept: application/json''", "curl -X POST http://api.example.com/users -d ''{\"name\":\"test\"}'' -H ''Content-Type: application/json''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar códigos de respuesta", "detalle": "Verificar status codes para diferentes escenarios", "comandos": ["curl -w ''%{http_code}'' -s -o /dev/null http://api.example.com/users", "curl -X GET http://api.example.com/nonexistent (expect 404)"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Testing automatizado", "detalle": "Ejecutar suite de pruebas con newman", "comandos": ["newman run api_collection.json -e environment.json", "newman run api_collection.json --reporters cli,json"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Análisis de respuestas", "detalle": "Validar estructura y contenido de responses", "comandos": ["curl -s http://api.example.com/users | jq ''.data | length''", "curl -s http://api.example.com/health | jq ''.status''"], "source_comandos": "IA"}], "checklist": ["APIs probadas con curl", "Códigos HTTP validados", "Suite automatizada ejecutada", "Respuestas JSON analizadas", "Errores documentados", "Reporte de testing completado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-F339', NULL, 0.4, 0.0, '2026-03-21 18:53:47.420267+00', NULL, NULL, '[]', '2026-03-21 18:53:47.420267+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-AA95', 'Validación y cierre - Documentar resolución', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Backend APIs", "source": "IA"}, {"campo": "Documentación", "valor": "Confluence/SharePoint", "source": "IA"}, {"campo": "Template", "valor": "Plantilla resolución incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar información de resolución", "detalle": "Revisar todas las acciones realizadas en tarjetas anteriores", "comandos": ["Revisar logs de actividad del ticket", "Compilar timeline de acciones"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Documentar causa raíz", "detalle": "Identificar y documentar la causa raíz del problema", "comandos": ["Análisis de causa raíz (RCA)", "Documentar en template estándar"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Documentar solución aplicada", "detalle": "Detallar paso a paso la solución implementada", "comandos": ["Documentar comandos ejecutados", "Adjuntar evidencias (screenshots, logs)"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar funcionamiento", "detalle": "Confirmar que el servicio funciona correctamente", "comandos": ["Ejecutar pruebas funcionales", "Verificar métricas de rendimiento"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cerrar ticket", "detalle": "Actualizar ticket con resolución y cerrar", "comandos": ["Actualizar estado a ''Resuelto''", "Notificar a usuario final"], "source_comandos": "IA"}], "checklist": ["Causa raíz identificada y documentada", "Solución detallada paso a paso", "Evidencias adjuntadas al ticket", "Funcionamiento validado", "Usuario final notificado", "Ticket cerrado correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260321-B278', NULL, 0.2, 0.0, '2026-03-21 19:01:53.512506+00', NULL, NULL, '[]', '2026-03-21 19:01:53.512506+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-4D21', 'Análisis de logs de errores backend', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor Backend", "valor": "SRV-API-PRO-01", "source": "IA"}, {"campo": "Ruta logs", "valor": "/var/log/api-backend/", "source": "IA"}, {"campo": "Log principal", "valor": "application.log", "source": "IA"}, {"campo": "Log errores", "valor": "error.log", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor backend", "detalle": "Conectar por SSH al servidor", "comandos": ["ssh admin@srv-api-pro-01", "cd /var/log/api-backend/"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs de errores recientes", "detalle": "Analizar errores de las últimas 24 horas", "comandos": ["tail -n 500 error.log", "grep -i ''error\\|exception\\|failed'' application.log | tail -50", "journalctl -u api-backend --since ''24 hours ago'' --no-pager"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar patrones de error", "detalle": "Buscar errores recurrentes y timestamps", "comandos": ["grep -c ''ERROR'' application.log", "awk ''/ERROR/ {print $1, $2, $NF}'' application.log | sort | uniq -c", "grep -E ''(OutOfMemory|Connection|Timeout)'' *.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar stack traces", "detalle": "Revisar stack traces completos de excepciones", "comandos": ["grep -A 10 -B 2 ''Exception'' application.log", "grep -A 15 ''at java'' application.log", "less +G application.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de análisis", "detalle": "Documentar hallazgos y recomendaciones", "comandos": ["echo ''Análisis completado:'' > /tmp/analisis_logs.txt", "grep -c ERROR *.log >> /tmp/analisis_logs.txt", "cat /tmp/analisis_logs.txt"], "source_comandos": "IA"}], "checklist": ["Acceso SSH al servidor confirmado", "Logs de errores revisados (últimas 24h)", "Patrones de error identificados", "Stack traces analizados", "Reporte de análisis generado", "Recomendaciones documentadas"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-B278', NULL, 0.4, 0.0, '2026-03-21 19:01:53.506644+00', NULL, NULL, '[]', '2026-03-21 19:01:53.506644+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-C07E', 'Testing APIs con Postman - Identificar endpoints fallidos', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "API Base URL", "valor": "http://srv-api-pro-01:8080/api", "source": "IA"}, {"campo": "Endpoints principales", "valor": "/users, /orders, /products", "source": "IA"}, {"campo": "Método auth", "valor": "Bearer Token/API Key", "source": "IA"}, {"campo": "Postman Collection", "valor": "API_Backend_Tests.json", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["Abrir Postman", "Importar colección API_Backend_Tests.json", "Configurar variables: {{base_url}} = http://srv-api-pro-01:8080/api"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar endpoints básicos", "detalle": "Ejecutar requests GET principales", "comandos": ["GET {{base_url}}/health", "GET {{base_url}}/users", "GET {{base_url}}/products"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar endpoints fallidos", "detalle": "Documentar respuestas con error", "comandos": ["Revisar status codes != 200", "Capturar response body de errores", "Anotar tiempo de respuesta > 5000ms"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar endpoints con datos", "detalle": "Ejecutar POST/PUT con payloads", "comandos": ["POST {{base_url}}/users con JSON body", "PUT {{base_url}}/users/1 con datos", "DELETE {{base_url}}/users/test"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de testing", "detalle": "Exportar resultados y crear resumen", "comandos": ["Export > Test Results", "Generar Newman report", "Documentar endpoints fallidos en Excel/CSV"], "source_comandos": "IA"}], "checklist": ["Postman configurado con colección", "Endpoints básicos probados", "Endpoints fallidos identificados y documentados", "Requests POST/PUT/DELETE ejecutados", "Reporte de testing generado", "Tiempos de respuesta documentados"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-011', NULL, 'INC-20260321-B278', NULL, 0.4, 0.0, '2026-03-21 19:01:53.500399+00', NULL, NULL, '[]', '2026-03-21 19:01:53.500399+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-7DDD', 'Diagnóstico inicial - Verificar estado APIs y conectividad', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Servidor API", "valor": "SRV-API-PRO-01", "source": "IA"}, {"campo": "Puerto API", "valor": "8080", "source": "IA"}, {"campo": "Health endpoint", "valor": "/api/health", "source": "IA"}, {"campo": "Load balancer", "valor": "LB-PRO-01 (por verificar)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado del servidor", "detalle": "Comprobar disponibilidad y recursos del servidor", "comandos": ["ping srv-api-pro-01", "ssh admin@srv-api-pro-01", "uptime", "df -h", "free -m"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar servicios API", "detalle": "Comprobar que los servicios estén ejecutándose", "comandos": ["systemctl status api-backend", "ps aux | grep java", "netstat -tlnp | grep 8080", "lsof -i :8080"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar conectividad API", "detalle": "Ejecutar requests básicos a endpoints", "comandos": ["curl -I http://srv-api-pro-01:8080/api/health", "curl -X GET http://srv-api-pro-01:8080/api/status", "telnet srv-api-pro-01 8080"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar logs de aplicación", "detalle": "Revisar logs recientes para errores", "comandos": ["tail -n 50 /var/log/api-backend/application.log", "grep -i ''error\\|exception'' /var/log/api-backend/application.log | tail -10", "journalctl -u api-backend --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar estado inicial", "detalle": "Crear resumen del diagnóstico inicial", "comandos": ["echo ''Diagnóstico inicial:'' > /tmp/diagnostico.txt", "systemctl is-active api-backend >> /tmp/diagnostico.txt", "curl -s -o /dev/null -w ''%{http_code}'' http://localhost:8080/api/health >> /tmp/diagnostico.txt"], "source_comandos": "IA"}], "checklist": ["Servidor accesible y con recursos suficientes", "Servicios API ejecutándose correctamente", "Endpoints básicos respondiendo", "Logs revisados sin errores críticos", "Estado inicial documentado", "Conectividad de red verificada"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', 'FTE-112', NULL, 'INC-20260321-B278', NULL, 0.3, 0.0, '2026-03-21 19:01:53.490018+00', NULL, NULL, '[]', '2026-03-21 19:01:53.490018+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-36C4', 'Aplicar fix en configuración SMS gateway', '{"silo": "Middleware", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Backup de configuración creado", "Fix aplicado correctamente", "Sintaxis XML validada", "Servicio reiniciado sin errores", "Fix verificado en runtime", "Logs sin errores post-cambio"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Config SMS", "valor": "/etc/sms-gateway/config.xml", "source": "IA"}, {"campo": "Backup config", "valor": "/etc/sms-gateway/backup/", "source": "IA"}, {"campo": "Usuario servicio", "valor": "sms-gateway", "source": "IA"}, {"campo": "Puerto config", "valor": "8080 (management)", "source": "IA"}, {"campo": "Restart command", "valor": "systemctl restart sms-gateway", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Crear backup de configuración", "detalle": "Respaldar config actual antes de cambios", "comandos": ["sudo cp /etc/sms-gateway/config.xml /etc/sms-gateway/backup/config_$(date +%Y%m%d_%H%M%S).xml", "ls -la /etc/sms-gateway/backup/"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Aplicar fix de configuración", "detalle": "Implementar corrección identificada", "comandos": ["sudo nano /etc/sms-gateway/config.xml", "# Aplicar cambios según fix definido"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar sintaxis XML", "detalle": "Verificar que el XML sea válido", "comandos": ["xmllint --noout /etc/sms-gateway/config.xml", "echo $? # Debe retornar 0"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Reiniciar servicio SMS Gateway", "detalle": "Aplicar nueva configuración", "comandos": ["sudo systemctl restart sms-gateway", "sudo systemctl status sms-gateway"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar aplicación del fix", "detalle": "Confirmar que el fix está activo", "comandos": ["curl -s http://localhost:8080/config | grep [PARAMETRO_FIX]", "tail -f /var/log/sms-gateway/gateway.log"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-35D1', NULL, 6.0, 0.0, '2026-03-22 19:06:44.880665+00', NULL, NULL, '[]', '2026-03-22 19:06:44.880665+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-8D05', 'Validación funcional y cierre incidencia', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Validación y cierre", "source": "IA"}, {"campo": "Criticidad", "valor": "Media", "source": "IA"}, {"campo": "Entorno", "valor": "Producción", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Validar resolución de incidencia", "detalle": "Verificar que la funcionalidad reportada como fallida ahora opera correctamente", "comandos": ["curl -I http://servicio/health", "telnet servidor puerto"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Confirmar con usuario reportante", "detalle": "Contactar al usuario que reportó la incidencia para validación funcional", "comandos": ["Llamada telefónica", "Email de confirmación"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Documentar resolución", "detalle": "Actualizar ticket con causa raíz y solución aplicada", "comandos": ["Actualizar campo ''Resolución''", "Adjuntar evidencias"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado a ''Resuelto'' y asignar categoría de cierre", "comandos": ["Estado: Resuelto", "Categoría: Problema resuelto"], "source_comandos": "IA"}], "checklist": ["Funcionalidad validada operativa", "Usuario confirma resolución", "Causa raíz documentada", "Solución documentada", "Ticket cerrado correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-010', NULL, 'INC-20260321-C465', NULL, 0.2, 0.0, '2026-03-21 19:09:57.883721+00', NULL, NULL, '[]', '2026-03-21 19:09:57.883721+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-B9A8', 'Restaurar servicio scoring y dependencias', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servicio", "valor": "Scoring", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080", "source": "IA"}, {"campo": "Puerto BD", "valor": "1521", "source": "IA"}, {"campo": "Ruta logs", "valor": "/var/log/scoring/", "source": "IA"}, {"campo": "Usuario servicio", "valor": "scoring", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar dependencias de BD", "detalle": "Comprobar conectividad y estado de base de datos", "comandos": ["sqlplus scoring/password@localhost:1521/PROD", "SELECT 1 FROM dual;"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Iniciar servicio scoring", "detalle": "Levantar el servicio principal de scoring", "comandos": ["sudo systemctl start scoring", "sudo systemctl status scoring"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar logs de inicio", "detalle": "Revisar logs para confirmar inicio exitoso", "comandos": ["tail -f /var/log/scoring/application.log", "grep ERROR /var/log/scoring/application.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar funcionalidad", "detalle": "Ejecutar pruebas básicas del servicio scoring", "comandos": ["curl -X POST http://localhost:8080/scoring/test", "curl http://localhost:8080/scoring/health"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Restaurar servicios dependientes", "detalle": "Iniciar servicios que dependen del scoring", "comandos": ["sudo systemctl start scoring-worker", "sudo systemctl start scoring-api"], "source_comandos": "IA"}], "checklist": ["Base de datos accesible", "Servicio scoring iniciado", "Logs sin errores críticos", "Funcionalidad básica operativa", "Servicios dependientes restaurados", "Monitoreo confirmado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-C465', NULL, 0.8, 0.0, '2026-03-21 19:09:57.880065+00', NULL, NULL, '[]', '2026-03-21 19:09:57.880065+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-1F85', 'Diagnóstico BD - Consultas estado y conexiones', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Motor BD", "valor": "Oracle", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "SID", "valor": "PROD", "source": "IA"}, {"campo": "Usuario admin", "valor": "system", "source": "IA"}, {"campo": "Ruta alert log", "valor": "/u01/app/oracle/diag/rdbms/prod/PROD/trace/alert_PROD.log", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a la base de datos", "detalle": "Establecer sesión como DBA para diagnóstico", "comandos": ["sqlplus / as sysdba", "SELECT instance_name, status FROM v$instance;"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar conexiones activas", "detalle": "Revisar sesiones y procesos conectados", "comandos": ["SELECT count(*) FROM v$session;", "SELECT username, count(*) FROM v$session GROUP BY username;"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar consultas en ejecución", "detalle": "Identificar queries de larga duración o bloqueantes", "comandos": ["SELECT sql_text, elapsed_time FROM v$sql WHERE elapsed_time > 60000;", "SELECT * FROM v$session_wait WHERE wait_time = 0;"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar bloqueos", "detalle": "Detectar locks y sesiones bloqueadas", "comandos": ["SELECT * FROM v$lock WHERE block > 0;", "SELECT s1.username||''@''||s1.machine||'' (SID=''||s1.sid||'') is blocking ''||s2.username||''@''||s2.machine||'' (SID=''||s2.sid||'')'' FROM v$lock l1, v$session s1, v$lock l2, v$session s2 WHERE s1.sid=l1.sid AND s2.sid=l2.sid AND l1.BLOCK=1 AND l2.request > 0 AND l1.id1 = l2.id1 AND l2.id2 = l2.id2;"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar tablespaces", "detalle": "Comprobar espacio disponible en tablespaces", "comandos": ["SELECT tablespace_name, round(sum(bytes)/1024/1024,2) MB FROM dba_free_space GROUP BY tablespace_name;"], "source_comandos": "IA"}], "checklist": ["Instancia BD accesible", "Número conexiones verificado", "Consultas lentas identificadas", "Bloqueos analizados", "Espacio tablespaces verificado", "Diagnóstico documentado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-035', NULL, 'INC-20260321-C465', NULL, 1.0, 0.0, '2026-03-21 19:09:57.875694+00', NULL, NULL, '[]', '2026-03-21 19:09:57.875694+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-8A8C', 'Verificar procesos Linux y recursos sistema', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "SO", "valor": "Linux", "source": "IA"}, {"campo": "Distribución", "valor": "RHEL/CentOS", "source": "IA"}, {"campo": "Servicios críticos", "valor": "httpd, mysqld, scoring", "source": "IA"}, {"campo": "Ruta logs sistema", "valor": "/var/log/messages", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar carga del sistema", "detalle": "Revisar load average y uso de CPU", "comandos": ["uptime", "top -n 1", "cat /proc/loadavg"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Comprobar memoria", "detalle": "Analizar uso de RAM y swap", "comandos": ["free -h", "cat /proc/meminfo | grep -E ''MemTotal|MemFree|MemAvailable|SwapTotal|SwapFree''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar espacio en disco", "detalle": "Verificar uso de filesystems", "comandos": ["df -h", "du -sh /var/log/*", "lsof | grep deleted"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar procesos críticos", "detalle": "Comprobar estado de servicios principales", "comandos": ["systemctl status httpd", "systemctl status mysqld", "systemctl status scoring", "ps aux | grep -E ''httpd|mysql|scoring''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar logs del sistema", "detalle": "Buscar errores recientes en logs", "comandos": ["journalctl -xe --since ''1 hour ago''", "tail -100 /var/log/messages | grep -i error"], "source_comandos": "IA"}], "checklist": ["Load average dentro de límites", "Memoria disponible suficiente", "Espacio en disco adecuado", "Servicios críticos activos", "Logs revisados sin errores críticos", "Recursos sistema estables"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-060', NULL, 'INC-20260321-C465', NULL, 0.6, 0.0, '2026-03-21 19:09:57.87234+00', NULL, NULL, '[]', '2026-03-21 19:09:57.87234+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-CD7E', 'Análisis logs aplicación y errores backend', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 75, "contexto_cmdb": {"items": [{"campo": "Aplicación", "valor": "Backend API", "source": "IA"}, {"campo": "Ruta logs app", "valor": "/var/log/application/", "source": "IA"}, {"campo": "Ruta logs error", "valor": "/var/log/application/error.log", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080", "source": "IA"}, {"campo": "Framework", "valor": "Java Spring Boot", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Localizar archivos de log", "detalle": "Identificar ubicación y estructura de logs", "comandos": ["find /var/log -name ''*application*'' -type f", "ls -la /var/log/application/", "ls -ltr /var/log/application/*.log"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar errores recientes", "detalle": "Revisar errores de las últimas 2 horas", "comandos": ["grep -i error /var/log/application/error.log | tail -50", "grep -i exception /var/log/application/application.log | tail -20"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar patrones de error", "detalle": "Buscar errores frecuentes y stack traces", "comandos": ["grep -c ''ERROR'' /var/log/application/error.log", "grep -A 10 -B 2 ''Exception'' /var/log/application/application.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de conexión BD", "detalle": "Verificar errores de conectividad a base de datos", "comandos": ["grep -i ''connection'' /var/log/application/application.log | tail -20", "grep -i ''timeout\\|refused'' /var/log/application/error.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Analizar performance", "detalle": "Buscar indicadores de lentitud o timeouts", "comandos": ["grep -i ''slow\\|timeout\\|performance'' /var/log/application/application.log", "awk ''/ERROR/ {print $1, $2, $NF}'' /var/log/application/error.log | sort | uniq -c"], "source_comandos": "IA"}], "checklist": ["Archivos de log localizados", "Errores recientes identificados", "Patrones de error analizados", "Conectividad BD verificada", "Issues de performance detectados", "Análisis documentado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-028', NULL, 'INC-20260321-C465', NULL, 0.8, 0.0, '2026-03-21 19:09:57.867767+00', NULL, NULL, '[]', '2026-03-21 19:09:57.867767+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-0D77', 'Diagnóstico inicial - Verificar estado servicios y conectividad', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Tipo diagnóstico", "valor": "Inicial - Triaje", "source": "IA"}, {"campo": "Servicios principales", "valor": "Web, BD, Aplicación", "source": "IA"}, {"campo": "Puertos estándar", "valor": "80, 443, 1521, 8080", "source": "IA"}, {"campo": "Prioridad", "valor": "Alta", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Probar acceso SSH y ping a servidores principales", "comandos": ["ping -c 4 servidor-web", "ping -c 4 servidor-bd", "ssh usuario@servidor-web ''uptime''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Comprobar puertos principales", "detalle": "Verificar que servicios estén escuchando", "comandos": ["nmap -p 80,443,8080,1521 servidor-principal", "telnet servidor-web 80", "telnet servidor-bd 1521"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar servicios críticos", "detalle": "Comprobar estado de servicios principales", "comandos": ["systemctl status httpd", "systemctl status oracle", "systemctl status application"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Prueba funcional básica", "detalle": "Ejecutar health checks de aplicaciones", "comandos": ["curl -I http://servidor-web/health", "curl http://servidor-app:8080/status"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar logs iniciales", "detalle": "Buscar errores evidentes en logs principales", "comandos": ["tail -20 /var/log/messages", "journalctl -xe --since ''30 minutes ago'' | grep -i error"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Puertos principales accesibles", "Servicios críticos activos", "Health checks exitosos", "Logs revisados", "Estado general determinado"], "enriched": true}', 'RUN', 'Crítica', 'Code Review', 'FTE-037', NULL, 'INC-20260321-C465', NULL, 0.6, 0.0, '2026-03-21 19:09:57.858671+00', '2026-03-21 19:31:30.410857+00', NULL, '[{"columna": "Code Review", "timestamp": "2026-03-21T19:31:30.410915"}, {"columna": "En Progreso", "timestamp": "2026-03-21T19:31:32.345278"}, {"columna": "Code Review", "timestamp": "2026-03-21T19:31:33.569919"}]', '2026-03-21 19:09:57.858671+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-2C01', 'Verificar conexión Backend a Base de Datos', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Backend Server", "valor": "App server con conexión BD", "source": "IA"}, {"campo": "Database", "valor": "MySQL/PostgreSQL/Oracle", "source": "IA"}, {"campo": "Puerto BD", "valor": "3306/5432/1521", "source": "IA"}, {"campo": "Connection Pool", "valor": "HikariCP/c3p0", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar que el backend puede alcanzar la BD", "comandos": ["telnet db-server.domain.com 3306", "nc -zv db-server.domain.com 3306"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar autenticación BD", "detalle": "Verificar credenciales desde el servidor backend", "comandos": ["mysql -h db-server.domain.com -u app_user -p -e ''SELECT 1;''", "psql -h db-server.domain.com -U app_user -d app_db -c ''SELECT 1;''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar pool de conexiones", "detalle": "Verificar configuración del connection pool", "comandos": ["grep -r ''datasource\\|connection'' /opt/app/config/", "cat /opt/app/config/database.properties"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear conexiones activas", "detalle": "Verificar conexiones desde la BD", "comandos": ["mysql -e ''SHOW PROCESSLIST;'' | grep app_user", "SELECT * FROM pg_stat_activity WHERE usename=''app_user'';"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar consulta funcional", "detalle": "Ejecutar query de prueba desde backend", "comandos": ["curl -X GET http://localhost:8080/api/health/database", "tail -f /var/log/app/database.log"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada", "Autenticación BD exitosa", "Pool de conexiones configurado", "Conexiones activas monitoreadas", "Query funcional ejecutada"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-096', NULL, 'INC-20260321-882C', NULL, 0.5, 0.0, '2026-03-21 19:32:46.098081+00', NULL, NULL, '[]', '2026-03-21 19:32:46.098081+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-A854', 'Testing APIs con Postman - Validar endpoints críticos', '{"tipo": "RUN", "silo": "Testing", "sla_tarea_minutos": 150, "contexto_cmdb": {"items": [{"campo": "API Base URL", "valor": "https://api.domain.com/v1", "source": "IA"}, {"campo": "Endpoints críticos", "valor": "/auth, /users, /orders, /payments", "source": "IA"}, {"campo": "Herramientas", "valor": "Postman, Newman CLI", "source": "IA"}, {"campo": "Autenticación", "valor": "JWT/OAuth2/API Key", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar entorno Postman", "detalle": "Preparar colección y variables de entorno", "comandos": ["postman login", "newman --version"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar autenticación", "detalle": "Validar endpoint de login y obtener token", "comandos": ["curl -X POST https://api.domain.com/v1/auth/login -H ''Content-Type: application/json'' -d ''{\"username\":\"test\",\"password\":\"test123\"}''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar tests endpoints críticos", "detalle": "Probar GET, POST, PUT, DELETE en endpoints principales", "comandos": ["newman run api-tests.postman_collection.json -e production.postman_environment.json", "curl -H ''Authorization: Bearer TOKEN'' https://api.domain.com/v1/users"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar respuestas y tiempos", "detalle": "Verificar status codes, estructura JSON y performance", "comandos": ["newman run api-tests.postman_collection.json --reporters cli,json --reporter-json-export results.json"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de testing", "detalle": "Documentar resultados y fallos encontrados", "comandos": ["newman run api-tests.postman_collection.json --reporters htmlextra --reporter-htmlextra-export report.html"], "source_comandos": "IA"}], "checklist": ["Entorno Postman configurado", "Autenticación API exitosa", "Endpoints críticos probados", "Tiempos de respuesta validados", "Reporte de testing generado", "Fallos documentados"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-882C', NULL, 0.4, 0.0, '2026-03-21 19:32:46.08485+00', NULL, NULL, '[]', '2026-03-21 19:32:46.08485+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-96EF', 'Diagnóstico inicial - Verificar estado APIs y conectividad', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "APIs", "valor": "Servicios REST/GraphQL", "source": "IA"}, {"campo": "Puertos", "valor": "80, 443, 8080, 8443", "source": "IA"}, {"campo": "Load Balancer", "valor": "nginx/HAProxy/AWS ALB", "source": "IA"}, {"campo": "Monitoreo", "valor": "Prometheus, Grafana, Pingdom", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado servicios", "detalle": "Comprobar que los servicios API estén ejecutándose", "comandos": ["systemctl status api-service", "ps aux | grep -i api", "netstat -tlnp | grep :8080"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conectividad básica", "detalle": "Verificar respuesta HTTP de endpoints principales", "comandos": ["curl -I https://api.domain.com/health", "curl -I https://api.domain.com/v1/status", "ping -c 4 api.domain.com"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar balanceador de carga", "detalle": "Comprobar que el load balancer distribuye tráfico", "comandos": ["curl -H ''Host: api.domain.com'' http://load-balancer-ip/health", "nginx -t", "systemctl status nginx"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de acceso", "detalle": "Verificar tráfico reciente y errores", "comandos": ["tail -50 /var/log/nginx/access.log", "tail -50 /var/log/api/application.log", "journalctl -u api-service --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar métricas de rendimiento", "detalle": "Verificar CPU, memoria y tiempos de respuesta", "comandos": ["top -b -n1 | grep api", "free -h", "curl -w ''@curl-format.txt'' -s -o /dev/null https://api.domain.com/health"], "source_comandos": "IA"}], "checklist": ["Servicios API ejecutándose", "Conectividad HTTP verificada", "Load balancer operativo", "Logs revisados sin errores críticos", "Métricas de rendimiento normales"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', 'FTE-028', NULL, 'INC-20260321-882C', NULL, 0.3, 0.0, '2026-03-21 19:32:46.071466+00', NULL, NULL, '[]', '2026-03-21 19:32:46.071466+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-000B', 'Validación y cierre de incidencia', '{"tipo": "RUN", "silo": "General", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Validación y cierre", "source": "IA"}, {"campo": "Herramientas", "valor": "Sistema ticketing, monitoreo", "source": "IA"}, {"campo": "Documentación", "valor": "Plantilla cierre incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución completa", "detalle": "Validar que la incidencia reportada está completamente resuelta", "comandos": ["Revisar logs de la solución aplicada", "Verificar métricas de rendimiento"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Confirmar con usuario/cliente", "detalle": "Contactar al reportante para validar funcionamiento", "comandos": ["Llamada/email de confirmación", "Solicitar pruebas funcionales"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Documentar solución", "detalle": "Registrar causa raíz y solución aplicada", "comandos": ["Actualizar knowledge base", "Documentar lecciones aprendidas"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cerrar ticket formalmente", "detalle": "Actualizar estado y categorizar cierre", "comandos": ["Cambiar estado a ''Resuelto''", "Asignar código de resolución"], "source_comandos": "IA"}], "checklist": ["Incidencia completamente resuelta", "Usuario confirma funcionamiento", "Causa raíz documentada", "Solución registrada en KB", "Ticket cerrado correctamente"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-028', NULL, 'INC-20260321-882C', NULL, 0.2, 0.0, '2026-03-21 19:32:46.112294+00', NULL, NULL, '[]', '2026-03-21 19:32:46.112294+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-06CE', 'Restaurar servicio y configuración Cloud', '{"tipo": "RUN", "silo": "Cloud", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Plataforma", "valor": "AWS/Azure/GCP", "source": "IA"}, {"campo": "Servicios", "valor": "EC2, RDS, Load Balancer", "source": "IA"}, {"campo": "Herramientas", "valor": "AWS CLI, Terraform, kubectl", "source": "IA"}, {"campo": "Backup", "valor": "Snapshots automatizados", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Evaluar estado actual", "detalle": "Verificar qué servicios están caídos o degradados", "comandos": ["aws ec2 describe-instances --filters ''Name=instance-state-name,Values=stopped''", "kubectl get pods --all-namespaces"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Restaurar instancias", "detalle": "Levantar servicios principales desde backups", "comandos": ["aws ec2 start-instances --instance-ids i-1234567890abcdef0", "kubectl scale deployment app-deployment --replicas=3"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad", "detalle": "Comprobar red y balanceadores", "comandos": ["aws elbv2 describe-target-health --target-group-arn arn:aws:elasticloadbalancing", "ping -c 4 load-balancer.domain.com"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Restaurar configuración", "detalle": "Aplicar configuraciones desde IaC", "comandos": ["terraform apply -auto-approve", "ansible-playbook restore-config.yml"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar servicios", "detalle": "Verificar que todos los servicios respondan", "comandos": ["curl -I https://api.domain.com/health", "aws rds describe-db-instances --query ''DBInstances[*].DBInstanceStatus''"], "source_comandos": "IA"}], "checklist": ["Instancias cloud restauradas", "Conectividad de red verificada", "Configuración aplicada correctamente", "Balanceadores funcionando", "APIs respondiendo", "Monitoreo activo"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-096', NULL, 'INC-20260321-882C', NULL, 0.2, 0.0, '2026-03-21 19:32:46.106832+00', NULL, NULL, '[]', '2026-03-21 19:32:46.106832+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-AF17', 'Análisis de logs de errores Backend', '{"tipo": "RUN", "silo": "Backend", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "Backend application server", "source": "IA"}, {"campo": "Logs path", "valor": "/var/log/app/ y /opt/app/logs/", "source": "IA"}, {"campo": "Tecnología", "valor": "Java/Node.js/Python", "source": "IA"}, {"campo": "Herramientas", "valor": "grep, awk, ELK Stack", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Localizar logs de errores", "detalle": "Identificar archivos de log relevantes", "comandos": ["find /var/log/app -name ''*.log'' -mtime -1", "ls -la /opt/app/logs/ | grep error"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Filtrar errores críticos", "detalle": "Extraer errores de las últimas 24h", "comandos": ["grep -i ''error\\|exception\\|fatal'' /var/log/app/application.log | tail -100", "journalctl -u app-service --since ''24 hours ago'' --grep ''ERROR''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar patrones", "detalle": "Identificar errores recurrentes y timestamps", "comandos": ["awk ''/ERROR/ {print $1, $2, $NF}'' /var/log/app/application.log | sort | uniq -c", "grep -c ''OutOfMemoryError\\|ConnectionTimeout\\|SQLException'' /var/log/app/*.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Correlacionar con métricas", "detalle": "Verificar uso de recursos durante errores", "comandos": ["top -b -n1 | head -20", "free -h", "df -h"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte", "detalle": "Documentar hallazgos y recomendaciones", "comandos": ["echo ''Análisis completado'' > /tmp/error_analysis_$(date +%Y%m%d).txt"], "source_comandos": "IA"}], "checklist": ["Logs de errores localizados", "Errores críticos identificados", "Patrones de error analizados", "Correlación con recursos verificada", "Reporte de análisis generado"], "enriched": true}', 'RUN', 'Crítica', 'Backlog', 'FTE-112', NULL, 'INC-20260321-882C', NULL, 0.4, 0.0, '2026-03-21 19:32:46.102676+00', NULL, NULL, '[]', '2026-03-21 19:32:46.102676+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-C4E9', 'Diagnóstico inicial - Verificar estado Citrix y conectividad', '{"tipo": "RUN", "silo": "INFRAESTRUCTURA", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Hostname", "valor": "vdi-farm.pro", "source": "CMDB"}, {"campo": "VLAN", "valor": "VLAN 20 - SERVIDORES-PRO", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.20.1", "source": "CMDB"}, {"campo": "Sesiones concurrentes", "valor": "300", "source": "CMDB"}, {"campo": "Hosts", "valor": "8", "source": "CMDB"}, {"campo": "Puerto Citrix", "valor": "1494, 2598 (ICA/HDX)", "source": "IA"}, {"campo": "Puerto RDP", "valor": "3389", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad de red", "detalle": "Comprobar acceso al servidor Citrix y dependencias críticas", "comandos": ["ping 10.0.20.50", "telnet 10.0.20.50 1494", "telnet 10.0.20.50 2598", "nslookup vdi-farm.pro"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar servicios Citrix", "detalle": "Conectar al servidor y revisar estado de servicios críticos", "comandos": ["Get-Service -Name ''Citrix*'' | Format-Table Name, Status", "Get-Service -Name ''BrokerAgent'' | Format-Table Name, Status", "Get-Service -Name ''SessionSharing'' | Format-Table Name, Status"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar dependencias críticas", "detalle": "Comprobar conectividad con SAN y Active Directory", "comandos": ["Test-NetConnection -ComputerName STO-PRO-001 -Port 445", "Test-NetConnection -ComputerName SRV-PRO-005 -Port 389", "nltest /dsgetdc:domain.local"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Revisar logs de eventos", "detalle": "Analizar logs de Citrix y sistema para identificar errores", "comandos": ["Get-EventLog -LogName Application -Source ''Citrix*'' -Newest 50", "Get-EventLog -LogName System -EntryType Error -Newest 20"], "source_comandos": "IA"}], "checklist": ["Conectividad de red verificada (ping, telnet)", "Servicios Citrix en estado Running", "Dependencias SAN y AD operativas", "Logs revisados sin errores críticos", "Estado inicial documentado en ticket"], "enriched": true}', 'RUN', 'Baja', 'En Progreso', 'FTE-006', NULL, 'INC-20260321-7D95', NULL, 7.2, 0.0, '2026-03-21 22:01:37.429551+00', NULL, NULL, '[]', '2026-03-21 22:01:37.429551+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-1391', 'Análisis de conectividad con proveedores de datos financieros', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 75, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-APP-COT-01", "source": "IA"}, {"campo": "IP interna", "valor": "192.168.50.10", "source": "IA"}, {"campo": "Gateway", "valor": "192.168.50.1", "source": "IA"}, {"campo": "Proveedores", "valor": "Bloomberg:api.bloomberg.com, Reuters:api.reuters.com", "source": "IA"}, {"campo": "Puertos", "valor": "443 (HTTPS), 80 (HTTP)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Probar conectividad desde servidor de cotizaciones", "comandos": ["ping -c 4 8.8.8.8", "ping -c 4 192.168.50.1", "traceroute 8.8.8.8"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conectividad con Bloomberg", "detalle": "Verificar acceso a API de Bloomberg", "comandos": ["nslookup api.bloomberg.com", "telnet api.bloomberg.com 443", "curl -I https://api.bloomberg.com --connect-timeout 10"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar conectividad con Reuters", "detalle": "Verificar acceso a API de Reuters", "comandos": ["nslookup api.reuters.com", "telnet api.reuters.com 443", "curl -I https://api.reuters.com --connect-timeout 10"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar configuración de red", "detalle": "Revisar configuración de interfaces y rutas", "comandos": ["ip addr show", "ip route show", "netstat -rn", "cat /etc/resolv.conf"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar firewall y proxy", "detalle": "Revisar reglas de firewall y configuración de proxy", "comandos": ["iptables -L -n", "firewall-cmd --list-all", "env | grep -i proxy", "cat /etc/environment | grep -i proxy"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte de conectividad", "detalle": "Documentar resultados de pruebas", "comandos": ["echo ''Reporte Conectividad - KT-1391'' > /tmp/connectivity_report.txt", "date >> /tmp/connectivity_report.txt", "echo ''Proveedores testeados: Bloomberg, Reuters'' >> /tmp/connectivity_report.txt"], "source_comandos": "IA"}], "checklist": ["Conectividad básica verificada", "Acceso a Bloomberg probado", "Acceso a Reuters probado", "Configuración de red revisada", "Firewall y proxy analizados", "Reporte de conectividad generado"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-067', NULL, 'INC-20260322-40DB', NULL, 4.0, 0.0, '2026-03-22 11:10:25.657073+00', NULL, NULL, '[]', '2026-03-22 11:10:25.657073+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-1B3E', 'Analizar recursos del servidor Citrix y sesiones activas', '{"tipo": "RUN", "silo": "INFRAESTRUCTURA", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Sesiones máximas", "valor": "300", "source": "CMDB"}, {"campo": "Hosts en farm", "valor": "8", "source": "CMDB"}, {"campo": "GPU", "valor": "NVIDIA T4", "source": "CMDB"}, {"campo": "Puerto Studio", "valor": "80, 443", "source": "IA"}, {"campo": "Puerto Director", "valor": "8080", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Analizar recursos del sistema", "detalle": "Revisar CPU, memoria y disco en el servidor Citrix", "comandos": ["Get-Counter ''\\Processor(_Total)\\% Processor Time''", "Get-Counter ''\\Memory\\Available MBytes''", "Get-WmiObject -Class Win32_LogicalDisk | Select-Object DeviceID, @{Name=''Size(GB)'';Expression={[math]::Round($_.Size/1GB,2)}}, @{Name=''FreeSpace(GB)'';Expression={[math]::Round($_.FreeSpace/1GB,2)}}"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar sesiones activas", "detalle": "Obtener información detallada de sesiones de usuarios", "comandos": ["Get-BrokerSession | Select-Object UserName, SessionState, StartTime, ClientName | Format-Table", "Get-BrokerSession | Group-Object SessionState | Select-Object Name, Count"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar carga por host", "detalle": "Revisar distribución de carga entre los 8 hosts del farm", "comandos": ["Get-BrokerMachine | Select-Object MachineName, LoadIndex, SessionCount, RegistrationState | Format-Table", "Get-BrokerLoadEvaluator | Format-Table"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar recursos GPU", "detalle": "Comprobar utilización de GPU NVIDIA T4 para VDI", "comandos": ["nvidia-smi", "Get-Counter ''\\GPU Engine(*)\\Utilization Percentage''"], "source_comandos": "CMDB"}], "checklist": ["Recursos de sistema analizados (CPU, RAM, disco)", "Sesiones activas inventariadas y clasificadas", "Carga distribuida entre hosts verificada", "Utilización GPU documentada", "Métricas de rendimiento capturadas", "Reporte de análisis generado"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-096', NULL, 'INC-20260321-7D95', NULL, 14.4, 0.0, '2026-03-21 22:01:37.435883+00', NULL, NULL, '[]', '2026-03-21 22:01:37.435883+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-B0DD', 'Optimizar configuración Citrix y limpiar cache', '{"tipo": "RUN", "silo": "INFRAESTRUCTURA", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Hosts", "valor": "8", "source": "CMDB"}, {"campo": "Ruta cache ICA", "valor": "C:\\Users\\%USERNAME%\\AppData\\Local\\Citrix\\ICA Client\\Cache", "source": "IA"}, {"campo": "Ruta logs Citrix", "valor": "C:\\Windows\\System32\\LogFiles\\Citrix", "source": "IA"}, {"campo": "Registro Citrix", "valor": "HKEY_LOCAL_MACHINE\\SOFTWARE\\Citrix", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Backup de configuración actual", "detalle": "Respaldar configuración antes de optimizaciones", "comandos": ["Export-BrokerSite -FilePath ''C:\\Backup\\CitrixConfig_$(Get-Date -Format yyyyMMdd).zip''", "reg export HKLM\\SOFTWARE\\Citrix C:\\Backup\\CitrixRegistry_$(Get-Date -Format yyyyMMdd).reg"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Limpiar cache del sistema", "detalle": "Eliminar archivos temporales y cache acumulado", "comandos": ["Remove-Item -Path ''C:\\Windows\\Temp\\*'' -Recurse -Force -ErrorAction SilentlyContinue", "Remove-Item -Path ''C:\\Users\\*\\AppData\\Local\\Citrix\\ICA Client\\Cache\\*'' -Recurse -Force -ErrorAction SilentlyContinue", "Remove-Item -Path ''C:\\ProgramData\\Citrix\\Logs\\*'' -Include ''*.log'' -Recurse -Force -ErrorAction SilentlyContinue"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Optimizar configuración de sesión", "detalle": "Ajustar parámetros de rendimiento y timeout", "comandos": ["Set-BrokerSite -ConnectionLeaseTimeout 00:15:00", "Set-BrokerAccessPolicyRule -Name ''Direct Access'' -IncludedUsers @() -AllowedConnections ViaAG", "Set-BrokerSessionLinger -Enabled $true -MaxAverageLoadThreshold 75"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Reiniciar servicios optimizados", "detalle": "Reiniciar servicios Citrix para aplicar cambios", "comandos": ["Restart-Service -Name ''BrokerAgent'' -Force", "Restart-Service -Name ''Citrix Independent Management Architecture'' -Force", "Start-Sleep -Seconds 30"], "source_comandos": "IA"}], "checklist": ["Backup de configuración completado", "Cache del sistema limpiado", "Parámetros de sesión optimizados", "Servicios Citrix reiniciados correctamente", "Configuración aplicada sin errores", "Optimizaciones documentadas"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-031', NULL, 'INC-20260321-7D95', NULL, 16.8, 0.0, '2026-03-21 22:01:37.437987+00', NULL, NULL, '[]', '2026-03-21 22:01:37.437987+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-122F', 'Verificar rendimiento post-optimización', '{"tipo": "RUN", "silo": "INFRAESTRUCTURA", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Sesiones objetivo", "valor": "300", "source": "CMDB"}, {"campo": "Hosts", "valor": "8", "source": "CMDB"}, {"campo": "Métricas clave", "valor": "Logon time, Session responsiveness, Resource utilization", "source": "IA"}, {"campo": "Umbrales", "valor": "Logon <30s, CPU <80%, RAM <85%", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Medir tiempos de logon", "detalle": "Verificar mejora en tiempos de inicio de sesión", "comandos": ["Get-BrokerSession | Where-Object {$_.StartTime -gt (Get-Date).AddHours(-2)} | Select-Object UserName, StartTime, @{Name=''LogonDuration'';Expression={(Get-Date) - $_.StartTime}}", "Measure-Command { Start-Process ''C:\\Program Files\\Citrix\\ICA Client\\wfcrun32.exe'' }"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar recursos post-optimización", "detalle": "Comparar métricas de rendimiento antes y después", "comandos": ["Get-Counter ''\\Processor(_Total)\\% Processor Time'' -SampleInterval 5 -MaxSamples 12", "Get-Counter ''\\Memory\\Available MBytes'' -SampleInterval 5 -MaxSamples 12", "Get-Counter ''\\PhysicalDisk(_Total)\\% Disk Time'' -SampleInterval 5 -MaxSamples 12"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar conectividad de usuarios", "detalle": "Simular conexiones de usuario para validar mejoras", "comandos": ["Test-NetConnection -ComputerName 10.0.20.50 -Port 1494", "Test-NetConnection -ComputerName 10.0.20.50 -Port 2598", "Get-BrokerSession | Where-Object {$_.SessionState -eq ''Active''} | Measure-Object"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Generar reporte de rendimiento", "detalle": "Documentar mejoras obtenidas con las optimizaciones", "comandos": ["Get-BrokerSite | Select-Object Name, @{Name=''TotalSessions'';Expression={(Get-BrokerSession | Measure-Object).Count}}", "Get-BrokerMachine | Select-Object MachineName, LoadIndex, SessionCount | Export-Csv -Path ''C:\\Reports\\PostOptimization_$(Get-Date -Format yyyyMMdd).csv''"], "source_comandos": "IA"}], "checklist": ["Tiempos de logon medidos y mejorados", "Recursos del sistema dentro de umbrales", "Conectividad de usuarios validada", "Sesiones activas funcionando correctamente", "Reporte de mejoras generado", "Comparativa antes/después documentada"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-041', NULL, 'INC-20260321-7D95', NULL, 7.2, 0.0, '2026-03-21 22:01:37.441565+00', NULL, NULL, '[]', '2026-03-21 22:01:37.441565+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-9D58', 'Validación y cierre - Documentar solución', '{"tipo": "RUN", "silo": "INFRAESTRUCTURA", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Criticidad", "valor": "ALTA", "source": "CMDB"}, {"campo": "Responsable", "valor": "Beatriz Castaño Villar", "source": "CMDB"}, {"campo": "Plantilla doc", "valor": "Template_Solucion_Infraestructura_v2.1", "source": "IA"}, {"campo": "KB interno", "valor": "KB-CITRIX-OPT-001", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar evidencias finales", "detalle": "Capturar estado final del sistema y métricas", "comandos": ["Get-BrokerSite | Export-Clixml -Path ''C:\\Evidence\\FinalState_$(Get-Date -Format yyyyMMdd).xml''", "Get-EventLog -LogName Application -Source ''Citrix*'' -After (Get-Date).AddHours(-4) | Export-Csv -Path ''C:\\Evidence\\CitrixLogs_Final.csv''"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Documentar solución aplicada", "detalle": "Crear documento técnico con pasos realizados y resultados", "comandos": ["# Crear documento con: Problema inicial, Pasos ejecutados, Configuraciones modificadas, Mejoras obtenidas", "# Incluir: Screenshots, logs relevantes, métricas antes/después"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Actualizar base de conocimiento", "detalle": "Registrar solución en KB para futuros casos similares", "comandos": ["# Crear entrada KB-CITRIX-OPT-001: ''Optimización rendimiento Citrix VDI''", "# Tags: Citrix, VDI, Performance, Cache, Optimization"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validación final y cierre", "detalle": "Confirmar resolución con usuario y cerrar incidencia", "comandos": ["# Enviar resumen de solución al responsable técnico", "# Solicitar confirmación de funcionamiento correcto", "# Actualizar estado del ticket a ''Resuelto''"], "source_comandos": "IA"}], "checklist": ["Evidencias finales capturadas y almacenadas", "Documento de solución completado", "Base de conocimiento actualizada", "Responsable técnico notificado", "Usuario confirma resolución", "Ticket cerrado correctamente"], "enriched": true}', 'RUN', 'Baja', 'Análisis', 'FTE-010', NULL, 'INC-20260321-7D95', NULL, 2.4, 0.0, '2026-03-21 22:01:37.443961+00', NULL, NULL, '[{"columna": "Análisis", "timestamp": "2026-03-21T22:09:05.009433"}]', '2026-03-21 22:01:37.443961+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-4CA1', 'Validación y cierre de incidencia', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 30, "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Sistema de Cotizaciones", "source": "IA"}, {"campo": "Servidor", "valor": "SRV-APP-COT-01", "source": "IA"}, {"campo": "IP", "valor": "192.168.50.10", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080", "source": "IA"}, {"campo": "Base de datos", "valor": "Oracle 19c", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución de incidencia", "detalle": "Confirmar que el sistema de cotizaciones funciona correctamente", "comandos": ["curl -I http://192.168.50.10:8080/cotizaciones/health", "systemctl status cotizaciones-app"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar funcionalidad end-to-end", "detalle": "Ejecutar casos de prueba de cotizaciones", "comandos": ["./test_cotizaciones.sh --smoke-test", "tail -f /var/log/cotizaciones/app.log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar métricas de rendimiento", "detalle": "Confirmar que los tiempos de respuesta están dentro de SLA", "comandos": ["grep ''response_time'' /var/log/cotizaciones/performance.log | tail -20"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar cierre", "detalle": "Actualizar ticket con evidencias de resolución", "comandos": ["echo ''Incidencia resuelta - Sistema operativo'' >> /tmp/cierre_KT-4CA1.txt"], "source_comandos": "IA"}], "checklist": ["Sistema de cotizaciones responde correctamente", "Casos de prueba ejecutados exitosamente", "Métricas de rendimiento dentro de SLA", "Logs sin errores críticos", "Ticket actualizado con evidencias", "Cierre formal documentado"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-087', NULL, 'INC-20260322-40DB', NULL, 1.0, 0.0, '2026-03-22 11:10:25.6701+00', NULL, NULL, '[]', '2026-03-22 11:10:25.6701+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-1F37', 'Verificación de precisión de cotizaciones post-fix', '{"tipo": "RUN", "silo": "BBDD", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c RAC", "source": "IA"}, {"campo": "Servidor BD", "valor": "SRV-DB-COT-01", "source": "IA"}, {"campo": "IP BD", "valor": "192.168.40.15", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Schema", "valor": "COTIZACIONES", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos", "detalle": "Acceder al schema de cotizaciones", "comandos": ["sqlplus cotizaciones/password@192.168.40.15:1521/COTDB"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar datos de cotizaciones recientes", "detalle": "Validar precisión de cotizaciones post-fix", "comandos": ["SELECT symbol, price, timestamp FROM cotizaciones WHERE timestamp > SYSDATE - 1/24 ORDER BY timestamp DESC;"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Comparar con fuentes externas", "detalle": "Verificar precisión contra proveedores de referencia", "comandos": ["SELECT c.symbol, c.price as internal_price, r.price as reference_price, ABS(c.price - r.price) as diff FROM cotizaciones c JOIN reference_prices r ON c.symbol = r.symbol WHERE c.timestamp > SYSDATE - 1/24;"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Generar reporte de precisión", "detalle": "Documentar desviaciones encontradas", "comandos": ["spool /tmp/precision_report_KT-1F37.txt", "SELECT COUNT(*) as total_quotes, AVG(ABS(price_diff)) as avg_deviation FROM precision_check;", "spool off"], "source_comandos": "IA"}], "checklist": ["Conexión a BD establecida", "Cotizaciones recientes extraídas", "Comparación con fuentes de referencia realizada", "Desviaciones documentadas", "Reporte de precisión generado", "Resultados validados por supervisor"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-40DB', NULL, 1.5, 0.0, '2026-03-22 11:10:25.668469+00', NULL, NULL, '[]', '2026-03-22 11:10:25.668469+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-E591', 'Corrección de configuración o reinicio de servicios', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 90, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-APP-COT-02", "source": "IA"}, {"campo": "IP", "valor": "192.168.50.11", "source": "IA"}, {"campo": "SO", "valor": "Red Hat Enterprise Linux 8", "source": "IA"}, {"campo": "Servicios", "valor": "cotizaciones-engine, data-collector", "source": "IA"}, {"campo": "Config path", "valor": "/opt/cotizaciones/config/", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado de servicios", "detalle": "Revisar servicios de cotizaciones", "comandos": ["systemctl status cotizaciones-engine", "systemctl status data-collector", "ps aux | grep cotizaciones"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar configuración actual", "detalle": "Validar archivos de configuración", "comandos": ["cat /opt/cotizaciones/config/app.properties", "ls -la /opt/cotizaciones/config/", "grep -i error /opt/cotizaciones/config/*.log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Aplicar corrección de configuración", "detalle": "Corregir parámetros identificados como problemáticos", "comandos": ["cp /opt/cotizaciones/config/app.properties /opt/cotizaciones/config/app.properties.bak", "vi /opt/cotizaciones/config/app.properties", "chown cotizaciones:cotizaciones /opt/cotizaciones/config/app.properties"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Reiniciar servicios", "detalle": "Reinicio controlado de servicios afectados", "comandos": ["systemctl stop cotizaciones-engine", "systemctl stop data-collector", "sleep 10", "systemctl start data-collector", "systemctl start cotizaciones-engine"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar funcionamiento", "detalle": "Verificar que los servicios funcionan correctamente", "comandos": ["systemctl is-active cotizaciones-engine", "tail -f /var/log/cotizaciones/app.log", "curl -s http://localhost:8080/health"], "source_comandos": "IA"}], "checklist": ["Estado inicial de servicios documentado", "Configuración respaldada", "Corrección aplicada correctamente", "Servicios reiniciados sin errores", "Funcionamiento post-reinicio validado", "Logs monitoreados por 10 minutos"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-40DB', NULL, 2.0, 0.0, '2026-03-22 11:10:25.665501+00', NULL, NULL, '[]', '2026-03-22 11:10:25.665501+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-3586', 'Revisión de logs del sistema de cotizaciones', '{"tipo": "RUN", "silo": "Unix", "sla_tarea_minutos": 45, "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-APP-COT-01", "source": "IA"}, {"campo": "IP", "valor": "192.168.50.10", "source": "IA"}, {"campo": "Logs path", "valor": "/var/log/cotizaciones/", "source": "IA"}, {"campo": "App logs", "valor": "app.log, error.log, access.log", "source": "IA"}, {"campo": "Rotación", "valor": "Diaria - logrotate", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor", "detalle": "Conectar vía SSH al servidor de cotizaciones", "comandos": ["ssh admin@192.168.50.10"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs de aplicación", "detalle": "Analizar logs recientes del sistema de cotizaciones", "comandos": ["cd /var/log/cotizaciones/", "ls -la", "tail -100 app.log", "grep -i error app.log | tail -20"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs de errores", "detalle": "Identificar errores críticos y patrones", "comandos": ["tail -50 error.log", "grep -i ''exception\\|fatal\\|critical'' error.log | tail -10", "awk ''{print $1, $2}'' error.log | sort | uniq -c | sort -nr"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de acceso", "detalle": "Verificar patrones de tráfico y respuestas", "comandos": ["tail -30 access.log", "grep '' 5[0-9][0-9] '' access.log | tail -10", "awk ''{print $9}'' access.log | sort | uniq -c | sort -nr"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar resumen de análisis", "detalle": "Documentar hallazgos principales", "comandos": ["echo ''Análisis de logs - KT-3586'' > /tmp/log_analysis.txt", "echo ''Fecha: $(date)'' >> /tmp/log_analysis.txt", "grep -c ERROR /var/log/cotizaciones/*.log >> /tmp/log_analysis.txt"], "source_comandos": "IA"}], "checklist": ["Acceso SSH establecido", "Logs de aplicación revisados", "Errores críticos identificados", "Patrones de acceso analizados", "Resumen de hallazgos documentado", "Recomendaciones de acción definidas"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-036', NULL, 'INC-20260322-40DB', NULL, 3.0, 0.0, '2026-03-22 11:10:25.660719+00', NULL, NULL, '[]', '2026-03-22 11:10:25.660719+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-ADF7', 'Diagnóstico inicial - Verificar fuentes de datos de cotización', '{"tipo": "RUN", "silo": "Aplicaciones", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Sistema de Cotizaciones", "source": "IA"}, {"campo": "Servidor", "valor": "SRV-APP-COT-01", "source": "IA"}, {"campo": "IP", "valor": "192.168.50.10", "source": "IA"}, {"campo": "Fuentes de datos", "valor": "Bloomberg API, Reuters API, Yahoo Finance", "source": "IA"}, {"campo": "Config file", "valor": "/opt/cotizaciones/config/datasources.xml", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado del sistema", "detalle": "Revisar estado general del sistema de cotizaciones", "comandos": ["systemctl status cotizaciones-app", "ps aux | grep cotizaciones", "netstat -tlnp | grep :8080"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar configuración de fuentes", "detalle": "Analizar configuración de proveedores de datos", "comandos": ["cat /opt/cotizaciones/config/datasources.xml", "grep -i ''bloomberg\\|reuters\\|yahoo'' /opt/cotizaciones/config/*.xml"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Probar conectividad a fuentes", "detalle": "Verificar acceso a cada proveedor de datos", "comandos": ["curl -s -o /dev/null -w ''%{http_code}'' https://api.bloomberg.com", "curl -s -o /dev/null -w ''%{http_code}'' https://api.reuters.com", "curl -s -o /dev/null -w ''%{http_code}'' https://query1.finance.yahoo.com"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar logs de conexión", "detalle": "Revisar logs de conexiones a fuentes de datos", "comandos": ["grep -i ''datasource\\|connection'' /var/log/cotizaciones/app.log | tail -20", "grep -i ''bloomberg\\|reuters\\|yahoo'' /var/log/cotizaciones/app.log | tail -10"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar obtención de datos", "detalle": "Ejecutar prueba de obtención de cotizaciones", "comandos": ["cd /opt/cotizaciones/bin", "./test_datasources.sh", "tail -f /var/log/cotizaciones/datasource.log"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar diagnóstico inicial", "detalle": "Documentar hallazgos del diagnóstico", "comandos": ["echo ''Diagnóstico Inicial - KT-ADF7'' > /tmp/diagnostic_report.txt", "echo ''Sistema: Cotizaciones'' >> /tmp/diagnostic_report.txt", "echo ''Fuentes verificadas: Bloomberg, Reuters, Yahoo'' >> /tmp/diagnostic_report.txt"], "source_comandos": "IA"}], "checklist": ["Estado del sistema verificado", "Configuración de fuentes revisada", "Conectividad a proveedores probada", "Logs de conexión analizados", "Prueba de obtención ejecutada", "Diagnóstico inicial documentado"], "enriched": true}', 'RUN', 'Baja', 'En Progreso', 'FTE-067', NULL, 'INC-20260322-40DB', NULL, 2.0, 0.0, '2026-03-22 11:10:25.650504+00', NULL, NULL, '[]', '2026-03-22 11:10:25.650504+00');
