INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-5B43', 'Corrección configuración de rutas', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 120, "contexto_cmdb": {"items": [{"campo": "Configuración", "valor": "Tablas de enrutamiento", "source": "IA"}, {"campo": "Protocolos", "valor": "OSPF, BGP, rutas estáticas", "source": "IA"}, {"campo": "Backup config", "valor": "running-config respaldado", "source": "IA"}, {"campo": "Ventana mantenimiento", "valor": "Según change management", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Respaldar configuración actual", "detalle": "Guardar configuración antes de realizar cambios", "comandos": ["copy running-config startup-config", "copy running-config tftp://backup-server/config-backup-$(date +%Y%m%d).cfg"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Aplicar corrección de rutas", "detalle": "Implementar cambios en configuración de enrutamiento", "comandos": ["configure terminal", "router ospf 1", "network [red_corregida] [wildcard] area [area_id]", "exit"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar cambios aplicados", "detalle": "Confirmar que las rutas se han actualizado correctamente", "comandos": ["show ip route", "show ip ospf database", "show ip ospf neighbor"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar conectividad post-cambio", "detalle": "Validar conectividad end-to-end tras la corrección", "comandos": ["ping [destino_critico_1]", "ping [destino_critico_2]", "traceroute [red_afectada]"], "source_comandos": "IA"}], "checklist": ["Configuración respaldada exitosamente", "Cambios de rutas aplicados", "Tablas de enrutamiento actualizadas", "Conectividad end-to-end verificada", "Vecinos OSPF/BGP estables", "Documentación de cambios actualizada"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-018', NULL, 'INC-20260322-7C5D', NULL, 2.0, 0.0, '2026-03-22 12:33:46.14486+00', NULL, NULL, '[]', '2026-03-22 12:33:46.14486+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-69B0', 'Verificación post-corrección', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 60, "contexto_cmdb": {"items": [{"campo": "Verificación", "valor": "Post-implementación cambios", "source": "IA"}, {"campo": "Métricas", "valor": "Latencia, pérdida paquetes, throughput", "source": "IA"}, {"campo": "Herramientas", "valor": "ping, traceroute, iperf", "source": "IA"}, {"campo": "Baseline", "valor": "Métricas pre-cambio", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estabilidad de rutas", "detalle": "Confirmar que las rutas corregidas permanecen estables", "comandos": ["show ip route | grep [red_corregida]", "show ip ospf neighbor detail", "show ip route summary"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Medir rendimiento de red", "detalle": "Comparar métricas actuales con baseline pre-cambio", "comandos": ["ping -c 100 [destino_critico] | tail -4", "traceroute -n [destino_critico]", "iperf3 -c [servidor_test] -t 30"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar redundancia y failover", "detalle": "Probar mecanismos de respaldo y recuperación", "comandos": ["show ip route backup", "show standby brief", "show track brief"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear por periodo extendido", "detalle": "Observar comportamiento durante 30 minutos", "comandos": ["watch -n 60 ''show ip ospf neighbor | grep Full''", "tail -f /var/log/routing.log"], "source_comandos": "IA"}], "checklist": ["Estabilidad de rutas confirmada", "Métricas de rendimiento dentro de parámetros", "Mecanismos de redundancia operativos", "Monitoreo extendido completado", "Comparación con baseline satisfactoria", "Sin alertas críticas generadas"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-146', NULL, 'INC-20260322-7C5D', NULL, 1.0, 0.0, '2026-03-22 12:33:46.148822+00', NULL, NULL, '[]', '2026-03-22 12:33:46.148822+00');
