INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-D24F', 'Corrección de configuración de rutas', '{"tipo": "RUN", "silo": "Redes", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Tipo dispositivo", "valor": "Router/Switch de red", "source": "IA"}, {"campo": "Protocolo", "valor": "OSPF/BGP/Static routes", "source": "IA"}, {"campo": "Puerto gestión", "valor": "22 (SSH) / 23 (Telnet)", "source": "IA"}, {"campo": "Backup config", "valor": "/tftp/backups/ o startup-config", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Respaldar configuración actual", "detalle": "Crear backup antes de realizar cambios", "comandos": ["copy running-config tftp://[servidor]/backup_[fecha].cfg", "show running-config > backup_local.txt"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Acceder al dispositivo de red", "detalle": "Conectar vía SSH/Telnet al equipo afectado", "comandos": ["ssh admin@[IP_dispositivo]", "telnet [IP_dispositivo]"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar tabla de rutas actual", "detalle": "Revisar rutas existentes y identificar conflictos", "comandos": ["show ip route", "show ip route summary", "show running-config | section router"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Aplicar corrección de rutas", "detalle": "Configurar rutas correctas según diseño de red", "comandos": ["configure terminal", "ip route [red_destino] [máscara] [gateway]", "no ip route [ruta_incorrecta]", "exit", "write memory"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar conectividad", "detalle": "Probar rutas corregidas", "comandos": ["ping [destinos_críticos]", "traceroute [rutas_principales]", "show ip route | include [red_corregida]"], "source_comandos": "IA"}], "checklist": ["Backup de configuración realizado", "Acceso al dispositivo establecido", "Rutas incorrectas identificadas", "Configuración aplicada correctamente", "Conectividad validada", "Cambios guardados permanentemente"], "enriched": true}', 'RUN', 'Baja', 'Backlog', 'FTE-139', NULL, 'INC-20260322-D849', NULL, 6.0, 0.0, '2026-03-22 12:47:04.908054+00', NULL, NULL, '[]', '2026-03-22 12:47:04.908054+00');
