INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-1D8F', 'Aplicar fix en configuración sistema seguros', '{"silo": "Unix/Linux", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Backup de configuración creado", "Servicio detenido correctamente", "Fix aplicado según especificaciones", "Configuración validada sin errores", "Servicio reiniciado exitosamente", "Health check positivo"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-SEG-PRO-01", "source": "IA"}, {"campo": "Archivo config", "valor": "/opt/seguros/config/application.properties", "source": "IA"}, {"campo": "Usuario servicio", "valor": "seguros", "source": "IA"}, {"campo": "Backup config", "valor": "/opt/seguros/backup/", "source": "IA"}, {"campo": "Servicio", "valor": "seguros-app", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Crear backup de configuración", "detalle": "Respaldar configuración actual antes de aplicar cambios", "comandos": ["sudo cp /opt/seguros/config/application.properties /opt/seguros/backup/application.properties.$(date +%Y%m%d_%H%M%S)", "sudo chown seguros:seguros /opt/seguros/backup/application.properties.*"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Detener servicio de seguros", "detalle": "Parar el servicio para aplicar cambios de forma segura", "comandos": ["sudo systemctl stop seguros-app", "sudo systemctl status seguros-app"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Aplicar fix de configuración", "detalle": "Modificar parámetros según especificaciones del fix", "comandos": ["sudo nano /opt/seguros/config/application.properties", "# Aplicar cambios según documentación del fix", "sudo chown seguros:seguros /opt/seguros/config/application.properties"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Validar sintaxis de configuración", "detalle": "Verificar que el archivo de configuración sea válido", "comandos": ["sudo -u seguros java -jar /opt/seguros/bin/config-validator.jar /opt/seguros/config/application.properties"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Reiniciar servicio", "detalle": "Iniciar el servicio con la nueva configuración", "comandos": ["sudo systemctl start seguros-app", "sudo systemctl status seguros-app", "sleep 30 && curl -I http://localhost:8080/health"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'Backlog', 'FTE-001', NULL, 'INC-20260322-F652', NULL, 4.0, 0.0, '2026-03-22 16:46:24.829785+00', NULL, NULL, '[]', '2026-03-22 16:46:24.829785+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-BB44', 'Diagnóstico inicial - Revisar logs sistema seguros', '{"silo": "Unix/Linux", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Conexión SSH establecida correctamente", "Estado de servicios verificado", "Logs de aplicación revisados", "Conectividad BD comprobada", "Errores documentados en ticket", "Recomendaciones iniciales definidas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-SEG-PRO-01", "source": "IA"}, {"campo": "IP", "valor": "192.168.20.45", "source": "IA"}, {"campo": "Puerto aplicación", "valor": "8080, 8443 (HTTPS)", "source": "IA"}, {"campo": "Ruta logs", "valor": "/var/log/seguros/", "source": "IA"}, {"campo": "Usuario servicio", "valor": "seguros", "source": "IA"}, {"campo": "Base de datos", "valor": "PostgreSQL puerto 5432", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar al servidor de seguros", "detalle": "Establecer conexión SSH al servidor principal", "comandos": ["ssh seguros@192.168.20.45"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar estado de servicios", "detalle": "Comprobar que los servicios críticos estén activos", "comandos": ["systemctl status seguros-app", "systemctl status postgresql", "ps aux | grep seguros"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar logs de aplicación", "detalle": "Analizar logs recientes para identificar errores", "comandos": ["tail -100 /var/log/seguros/application.log", "grep -i error /var/log/seguros/application.log | tail -20", "journalctl -u seguros-app --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar conectividad de base de datos", "detalle": "Comprobar conexión a PostgreSQL", "comandos": ["sudo -u postgres psql -c ''\\l''", "netstat -an | grep 5432", "tail -50 /var/log/postgresql/postgresql.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos", "detalle": "Registrar errores encontrados y estado general", "comandos": ["echo ''Diagnóstico completado: $(date)'' >> /tmp/diagnostico_seguros.txt"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'En Progreso', 'FTE-001', NULL, 'INC-20260322-F652', NULL, 2.0, 0.0, '2026-03-22 16:46:24.816023+00', NULL, NULL, '[]', '2026-03-22 16:46:24.816023+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-041D', 'Verificar conectividad con plataforma seguros', '{"silo": "Redes", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Ping al servidor exitoso", "Puertos 8080 y 8443 accesibles", "Endpoint de salud responde", "Firewall configurado correctamente", "Conectividad BD verificada", "Latencia de red documentada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor origen", "valor": "SRV-APP-PRO-01", "source": "IA"}, {"campo": "Servidor destino", "valor": "SRV-SEG-PRO-01 (192.168.20.45)", "source": "IA"}, {"campo": "Puertos críticos", "valor": "8080, 8443, 5432, 22", "source": "IA"}, {"campo": "VLAN", "valor": "VLAN 120 - Aplicaciones", "source": "IA"}, {"campo": "Gateway", "valor": "192.168.20.1", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Comprobar alcance de red al servidor de seguros", "comandos": ["ping -c 4 192.168.20.45", "traceroute 192.168.20.45"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar puertos de aplicación", "detalle": "Verificar que los puertos estén abiertos y respondiendo", "comandos": ["telnet 192.168.20.45 8080", "telnet 192.168.20.45 8443", "nmap -p 8080,8443,5432,22 192.168.20.45"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad desde aplicación", "detalle": "Probar conexión desde el servidor de aplicaciones", "comandos": ["curl -I http://192.168.20.45:8080/health", "curl -k -I https://192.168.20.45:8443/health"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar configuración de firewall", "detalle": "Verificar reglas de firewall que puedan afectar", "comandos": ["iptables -L | grep 192.168.20.45", "firewall-cmd --list-all"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar conectividad BD", "detalle": "Verificar acceso a base de datos de seguros", "comandos": ["telnet 192.168.20.45 5432", "psql -h 192.168.20.45 -U seguros_user -d seguros_db -c ''SELECT 1;''"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Baja', 'Backlog', 'FTE-001', NULL, 'INC-20260322-F652', NULL, 1.0, 0.0, '2026-03-22 16:46:24.822841+00', NULL, NULL, '[]', '2026-03-22 16:46:24.822841+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-20DC', 'Coordinar con área Seguros - Validar proceso contratación', '{"silo": "Coordinación", "tipo": "BUILD", "orden": 3, "enriched": true, "checklist": ["Documentación de proceso preparada", "Sesión de validación agendada", "Casos de prueba ejecutados", "Feedback del área registrado", "Acta de validación firmada", "Estado actualizado en proyecto"], "area_negocio": "Seguros", "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Plataforma Seguros - Módulo Contratación", "source": "IA"}, {"campo": "Stakeholder", "valor": "Área de Seguros - Jefe de Contratación", "source": "IA"}, {"campo": "Proceso", "valor": "Flujo de contratación de pólizas", "source": "IA"}, {"campo": "Entregable", "valor": "Acta de validación de proceso", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Preparar documentación de proceso", "detalle": "Compilar documentación técnica del proceso de contratación", "comandos": ["# Revisar especificaciones funcionales", "# Preparar casos de prueba", "# Documentar flujo actual vs esperado"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Agendar sesión de validación", "detalle": "Coordinar reunión con responsables del área de Seguros", "comandos": ["# Enviar invitación de calendario", "# Incluir agenda y documentación previa", "# Confirmar asistencia de stakeholders clave"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar validación funcional", "detalle": "Realizar pruebas del proceso con el área usuaria", "comandos": ["# Demostrar flujo de contratación", "# Ejecutar casos de prueba definidos", "# Documentar observaciones y feedback"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Registrar hallazgos", "detalle": "Documentar resultados de la validación", "comandos": ["# Crear acta de validación", "# Registrar issues identificados", "# Definir acciones correctivas si aplica"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Obtener aprobación formal", "detalle": "Conseguir sign-off del área de Seguros", "comandos": ["# Solicitar firma del acta", "# Actualizar estado en sistema de seguimiento", "# Notificar a equipo de proyecto"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": true, "sla_tarea_minutos": 120}', 'RUN', 'Baja', 'Backlog', 'FTE-131', NULL, 'INC-20260322-F652', NULL, 3.0, 0.0, '2026-03-22 16:46:24.82698+00', NULL, NULL, '[]', '2026-03-22 16:46:24.82698+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-DADA', 'Verificar funcionalidad post-fix', '{"silo": "Testing", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Sistema responde correctamente", "Casos de prueba críticos exitosos", "Integración BD funcionando", "Flujo de contratación operativo", "Logs sin errores críticos", "Funcionalidad post-fix validada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Plataforma Seguros", "source": "IA"}, {"campo": "URL testing", "valor": "https://192.168.20.45:8443", "source": "IA"}, {"campo": "Base de datos", "valor": "PostgreSQL seguros_db", "source": "IA"}, {"campo": "Casos de prueba", "valor": "Suite de regresión seguros", "source": "IA"}, {"campo": "Usuario pruebas", "valor": "test_seguros", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar disponibilidad del sistema", "detalle": "Comprobar que el sistema esté operativo tras el fix", "comandos": ["curl -I https://192.168.20.45:8443/health", "curl -I https://192.168.20.45:8443/api/status", "ping -c 3 192.168.20.45"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Ejecutar casos de prueba críticos", "detalle": "Probar funcionalidades principales del sistema", "comandos": ["# Login de usuario", "curl -X POST https://192.168.20.45:8443/api/login -d ''{\"user\":\"test_seguros\",\"pass\":\"test123\"}''", "# Consulta de pólizas", "curl -H ''Authorization: Bearer TOKEN'' https://192.168.20.45:8443/api/polizas"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validar integración con base de datos", "detalle": "Verificar que las operaciones de BD funcionen correctamente", "comandos": ["psql -h 192.168.20.45 -U seguros_user -d seguros_db -c ''SELECT COUNT(*) FROM polizas;''", "psql -h 192.168.20.45 -U seguros_user -d seguros_db -c ''SELECT * FROM audit_log ORDER BY fecha DESC LIMIT 5;''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar flujo de contratación", "detalle": "Ejecutar proceso completo de contratación de póliza", "comandos": ["# Crear nueva póliza de prueba", "curl -X POST https://192.168.20.45:8443/api/polizas -H ''Content-Type: application/json'' -d ''{\"cliente\":\"TEST\",\"tipo\":\"AUTO\"}''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar logs post-ejecución", "detalle": "Verificar que no hay errores en logs tras las pruebas", "comandos": ["tail -50 /var/log/seguros/application.log", "grep -i error /var/log/seguros/application.log | tail -10", "journalctl -u seguros-app --since ''10 minutes ago''"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 75}', 'RUN', 'Baja', 'Backlog', 'FTE-102', NULL, 'INC-20260322-F652', NULL, 2.0, 0.0, '2026-03-22 16:46:24.833928+00', NULL, NULL, '[]', '2026-03-22 16:46:24.833928+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-66AC', 'Validación final con área Seguros y cierre', '{"silo": "Cierre", "tipo": "BUILD", "orden": 6, "enriched": true, "checklist": ["Documentación de cierre preparada", "Sesión de cierre ejecutada", "Resultados presentados al área", "Aceptación formal obtenida", "Incidente cerrado en sistema", "Stakeholders notificados"], "area_negocio": "Seguros", "contexto_cmdb": {"items": [{"campo": "Proyecto", "valor": "Fix Sistema Seguros", "source": "IA"}, {"campo": "Stakeholder", "valor": "Área Seguros - Gerencia", "source": "IA"}, {"campo": "Entregables", "valor": "Acta de cierre, Documentación técnica", "source": "IA"}, {"campo": "Estado sistema", "valor": "Productivo post-fix", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Preparar documentación de cierre", "detalle": "Compilar todos los entregables del proyecto", "comandos": ["# Acta de cierre del incidente", "# Resumen ejecutivo de cambios aplicados", "# Documentación técnica actualizada", "# Reporte de pruebas realizadas"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Agendar sesión de cierre", "detalle": "Coordinar reunión final con área de Seguros", "comandos": ["# Enviar invitación con agenda de cierre", "# Incluir documentación para revisión previa", "# Confirmar asistencia de stakeholders"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Presentar resultados", "detalle": "Exponer resumen de trabajos realizados y resultados", "comandos": ["# Presentar fix aplicado", "# Mostrar resultados de pruebas", "# Demostrar funcionalidad restaurada", "# Revisar métricas de rendimiento"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Obtener aceptación formal", "detalle": "Conseguir sign-off final del área usuaria", "comandos": ["# Solicitar aprobación de entregables", "# Firmar acta de cierre", "# Registrar conformidad en sistema"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cerrar incidente/proyecto", "detalle": "Actualizar estado y notificar cierre", "comandos": ["# Actualizar ticket a estado CERRADO", "# Notificar a equipo de proyecto", "# Archivar documentación en repositorio", "# Actualizar CMDB si aplica"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": true, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'Backlog', 'FTE-028', NULL, 'INC-20260322-F652', NULL, 1.0, 0.0, '2026-03-22 16:46:24.836775+00', NULL, NULL, '[]', '2026-03-22 16:46:24.836775+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-46C2', 'Validación y cierre con negocio', '{"silo": "NEGOCIO", "tipo": "BUILD", "orden": 5, "enriched": true, "checklist": ["Documentación de validación completa", "Reunión de validación ejecutada", "Sign-off del negocio obtenido", "Observaciones documentadas", "Estado proyecto actualizado", "Stakeholders notificados"], "area_negocio": "Seguros", "contexto_cmdb": {"items": [{"campo": "Sistema", "valor": "Aplicaciones de Seguros", "source": "IA"}, {"campo": "Entorno", "valor": "Producción", "source": "IA"}, {"campo": "Stakeholders", "valor": "Área de Seguros + IT", "source": "IA"}, {"campo": "Criticidad", "valor": "Alta - Impacto negocio", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Preparar documentación de validación", "detalle": "Recopilar evidencias técnicas y funcionales del proyecto", "comandos": ["Revisar logs de pruebas", "Compilar reportes de testing", "Documentar configuraciones aplicadas"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Coordinar sesión de validación", "detalle": "Agendar reunión con usuarios clave del área de seguros", "comandos": ["Enviar convocatoria con agenda", "Preparar demo funcional", "Incluir criterios de aceptación"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar validación funcional", "detalle": "Demostrar funcionalidades implementadas", "comandos": ["Mostrar casos de uso principales", "Validar flujos críticos", "Registrar feedback"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar aceptación formal", "detalle": "Obtener sign-off del negocio", "comandos": ["Acta de aceptación firmada", "Registro de observaciones", "Plan de resolución pendientes"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cierre administrativo", "detalle": "Actualizar estado del proyecto", "comandos": ["Actualizar dashboard proyecto", "Notificar cierre a stakeholders", "Archivar documentación"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": true, "sla_tarea_minutos": 180}', 'RUN', 'Baja', 'Backlog', 'FTE-011', NULL, 'INC-20260322-7FFC', NULL, 2.0, 0.0, '2026-03-22 16:56:48.054959+00', NULL, NULL, '[]', '2026-03-22 16:56:48.054959+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-CBBF', 'Coordinación con área de Seguros', '{"silo": "COORDINACION", "tipo": "BUILD", "orden": 3, "enriched": true, "checklist": ["Stakeholders identificados", "Reunión coordinación ejecutada", "Estado técnico presentado", "Requerimientos documentados", "Plan de acción definido", "Responsabilidades asignadas"], "area_negocio": "Seguros", "contexto_cmdb": {"items": [{"campo": "Stakeholder Principal", "valor": "Área de Seguros", "source": "IA"}, {"campo": "Responsable Técnico", "valor": "Diana Sánchez Alonso", "source": "CMDB"}, {"campo": "Sistemas Involucrados", "valor": "WAF + Aplicaciones Seguros", "source": "IA"}, {"campo": "Criticidad", "valor": "Crítica", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Identificar interlocutores clave", "detalle": "Mapear stakeholders del área de seguros", "comandos": ["Revisar organigrama área seguros", "Identificar product owners", "Contactar responsables funcionales"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Agendar reunión de coordinación", "detalle": "Planificar sesión de trabajo conjunto", "comandos": ["Enviar convocatoria con agenda", "Incluir Diana Sánchez (responsable técnico)", "Preparar documentación técnica"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Presentar estado técnico", "detalle": "Exponer configuración actual y propuestas", "comandos": ["Mostrar configuración WAF", "Explicar políticas de seguridad", "Presentar roadmap técnico"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Recopilar requerimientos negocio", "detalle": "Documentar necesidades funcionales", "comandos": ["Registrar casos de uso", "Identificar gaps funcionales", "Priorizar requerimientos"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Definir plan de acción conjunto", "detalle": "Establecer hitos y responsabilidades", "comandos": ["Crear cronograma conjunto", "Asignar responsabilidades", "Definir puntos de control"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "contacto_negocio": {"area": "Banca Empresas", "cargo": "Directora de Banca Empresas", "email": "elena.garcia@bcc.test", "nombre": "Elena García Romero", "telefono": "+34 612 001 056"}, "requiere_negocio": true, "sla_tarea_minutos": 240}', 'RUN', 'Baja', 'Backlog', 'FTE-112', NULL, 'INC-20260322-7FFC', NULL, 3.0, 0.0, '2026-03-22 16:56:48.046342+00', NULL, NULL, '[]', '2026-03-22 16:56:48.046342+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-32F8', 'Revisar aplicación seguros en oficina', '{"silo": "APLICACIONES", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Conectividad verificada", "Autenticación probada", "Funcionalidades core revisadas", "Integraciones validadas", "Hallazgos documentados", "Reporte generado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Ubicación", "valor": "Oficina - Entorno local", "source": "IA"}, {"campo": "Aplicación", "valor": "Módulo Seguros", "source": "IA"}, {"campo": "Protección WAF", "valor": "NET-WAF-001 activo", "source": "CMDB"}, {"campo": "Acceso", "valor": "Red corporativa", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad aplicación", "detalle": "Comprobar acceso desde estación de trabajo", "comandos": ["ping app-seguros.empresa.com", "telnet app-seguros.empresa.com 443", "nslookup app-seguros.empresa.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar autenticación y acceso", "detalle": "Validar login y permisos de usuario", "comandos": ["Acceder con credenciales test", "Verificar roles y permisos", "Comprobar sesión SSO"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar funcionalidades core", "detalle": "Probar módulos principales de seguros", "comandos": ["Consulta pólizas", "Emisión cotizaciones", "Gestión siniestros"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar integración sistemas", "detalle": "Comprobar conectividad con sistemas backend", "comandos": ["Verificar conexión BD seguros", "Probar APIs externas", "Validar servicios web"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos", "detalle": "Registrar estado funcional y incidencias", "comandos": ["Capturar pantallas funcionales", "Documentar errores encontrados", "Generar reporte de revisión"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 180}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-7FFC', NULL, 4.0, 0.0, '2026-03-22 16:56:48.041898+00', NULL, NULL, '[]', '2026-03-22 16:56:48.041898+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-A38C', 'Diagnóstico inicial - Verificar sistema seguros', '{"silo": "INFRAESTRUCTURA", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Estado infraestructura verificado", "Servicios críticos revisados", "Logs analizados", "Conectividad backend comprobada", "Diagnóstico generado", "Recomendaciones documentadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "WAF Principal", "valor": "NET-WAF-001 - F5 BIG-IP", "source": "CMDB"}, {"campo": "Versión", "valor": "17.1", "source": "CMDB"}, {"campo": "Estado", "valor": "OPERATIVO", "source": "CMDB"}, {"campo": "Criticidad", "valor": "CRÍTICA", "source": "CMDB"}, {"campo": "Responsable", "valor": "Diana Sánchez Alonso", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado infraestructura", "detalle": "Comprobar salud general del sistema", "comandos": ["tmsh show sys hardware", "tmsh show sys performance", "tmsh show sys memory"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar servicios críticos", "detalle": "Validar estado de servicios principales", "comandos": ["tmsh show sys service", "tmsh show ltm virtual", "tmsh show asm policy-stats"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs del sistema", "detalle": "Revisar eventos recientes y errores", "comandos": ["tmsh show sys log ltm", "tmsh show asm events", "tail -f /var/log/ltm"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar conectividad backend", "detalle": "Comprobar conexiones a servidores aplicación", "comandos": ["tmsh show ltm pool members", "tmsh show ltm node", "tmsh show net route"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar diagnóstico inicial", "detalle": "Compilar hallazgos y recomendaciones", "comandos": ["tmsh generate sys report", "Documentar métricas performance", "Crear resumen ejecutivo"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 150}', 'RUN', 'Baja', 'En Progreso', 'FTE-087', NULL, 'INC-20260322-7FFC', NULL, 2.0, 0.0, '2026-03-22 16:56:48.007042+00', NULL, NULL, '[]', '2026-03-22 16:56:48.007042+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-E3DB', 'Verificar conectividad y comunicaciones', '{"silo": "Redes", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Conectividad de red establecida", "Comunicación bancaria exitosa", "Latencia dentro de parámetros", "Certificados SSL válidos", "Transacción de prueba aprobada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Protocolos", "valor": "TCP/IP, SSL/TLS", "source": "IA"}, {"campo": "Puertos estándar", "valor": "443, 8443, 80", "source": "IA"}, {"campo": "Servidores destino", "valor": "Host bancario, Servidores adquirente", "source": "IA"}, {"campo": "Tipos conectividad", "valor": "WiFi, Ethernet, GSM/GPRS", "source": "IA"}, {"campo": "Herramientas diagnóstico", "valor": "Ping, Telnet, Traceroute", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificación de conectividad básica", "detalle": "Probar conectividad de red del datáfono", "comandos": ["Menú > Diagnósticos > Test Red", "Verificar asignación de IP", "Probar ping a gateway"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Prueba de conectividad bancaria", "detalle": "Verificar comunicación con servidores del banco", "comandos": ["Test de conexión al host bancario", "Verificar respuesta en puerto 443", "Comprobar certificados SSL"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Diagnóstico de latencia", "detalle": "Medir tiempos de respuesta", "comandos": ["Ejecutar test de latencia", "Verificar tiempo < 5 segundos", "Documentar tiempos de respuesta"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Prueba transaccional", "detalle": "Validar comunicación end-to-end", "comandos": ["Ejecutar transacción de prueba", "Verificar respuesta del autorizador", "Confirmar recepción de voucher"], 