mpresión de comprobantes"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Inventario Activos", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Media', 'Backlog', 'FTE-028', NULL, 'INC-20260322-4602', NULL, 2.0, 0.0, '2026-03-22 17:07:40.296767+00', NULL, NULL, '[]', '2026-03-22 17:07:40.296767+00');
