INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-2959', 'Verificar sesiones activas y recursos del servidor Citrix', '{"silo": "INFRAESTRUCTURA", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Conexión al servidor establecida", "Sesiones activas inventariadas", "Recursos del sistema monitoreados", "Dependencias SAN y AD verificadas", "Reporte de estado generado", "Datos exportados para análisis"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Capacidad máxima", "valor": "300 sesiones concurrentes", "source": "CMDB"}, {"campo": "Hosts disponibles", "valor": "8", "source": "CMDB"}, {"campo": "GPU", "valor": "NVIDIA T4", "source": "CMDB"}, {"campo": "Dependencias", "valor": "SAN NetApp, Active Directory", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar al servidor Citrix", "detalle": "Establecer conexión administrativa al farm principal", "comandos": ["mstsc /v:10.0.20.50 /admin", "ping 10.0.20.50"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar sesiones activas", "detalle": "Obtener listado completo de sesiones de usuario activas", "comandos": ["query session", "quser /server:vdi-farm.pro", "Get-BrokerSession | Select-Object UserName, MachineName, SessionState"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Monitorear recursos del sistema", "detalle": "Verificar CPU, memoria, GPU y almacenamiento en todos los hosts", "comandos": ["Get-Counter ''\\Processor(_Total)\\% Processor Time''", "Get-Counter ''\\Memory\\Available MBytes''", "nvidia-smi", "Get-WmiObject -Class Win32_LogicalDisk"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar conectividad dependencias", "detalle": "Comprobar conexión con SAN NetApp y Active Directory", "comandos": ["ping STO-PRO-001", "ping SRV-PRO-005", "nltest /dsgetdc:domain"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Generar reporte de estado", "detalle": "Documentar estado actual de sesiones y recursos", "comandos": ["# Export session data to CSV", "Get-BrokerSession | Export-Csv sessions.csv"], "source_comandos": "IA"}], "skill_requerida": "AD: Reset Password", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'Backlog', 'FTE-044', NULL, 'INC-20260322-F36E', NULL, 3.0, 0.0, '2026-03-22 19:21:22.361453+00', NULL, NULL, '[]', '2026-03-22 19:21:22.361453+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-BA41', 'Diagnóstico inicial - Análisis de rendimiento Citrix', '{"silo": "INFRAESTRUCTURA", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Información del problema recopilada", "Conectividad básica verificada", "Logs del sistema analizados", "Métricas de rendimiento capturadas", "Estado de servicios documentado", "Reporte inicial completado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "VLAN", "valor": "VLAN 20 - SERVIDORES-PRO", "source": "CMDB"}, {"campo": "Criticidad", "valor": "ALTA", "source": "CMDB"}, {"campo": "Responsable", "valor": "Beatriz Castaño Villar", "source": "CMDB"}, {"campo": "Logs Citrix", "valor": "C:\\Windows\\System32\\LogFiles\\CitrixLogs", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar información inicial", "detalle": "Obtener detalles del problema reportado y síntomas", "comandos": ["# Revisar ticket original", "# Contactar usuario afectado"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar conectividad básica", "detalle": "Comprobar accesibilidad del servidor Citrix", "comandos": ["ping 10.0.20.50", "telnet 10.0.20.50 1494", "telnet 10.0.20.50 2598"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Analizar logs del sistema", "detalle": "Revisar Event Viewer y logs específicos de Citrix", "comandos": ["Get-EventLog -LogName System -Newest 50", "Get-EventLog -LogName Application -Source Citrix*", "Get-ChildItem C:\\Windows\\System32\\LogFiles\\CitrixLogs"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear rendimiento", "detalle": "Capturar métricas de CPU, memoria y red durante 10 minutos", "comandos": ["perfmon", "Get-Counter ''\\Processor(_Total)\\% Processor Time'' -SampleInterval 30 -MaxSamples 20", "Get-Counter ''\\Network Interface(*)\\Bytes Total/sec''"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar servicios Citrix", "detalle": "Comprobar estado de todos los servicios críticos", "comandos": ["Get-Service -Name ''Citrix*''", "sc query CitrixPrintManagerService", "qfarm /load"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Documentar hallazgos iniciales", "detalle": "Crear reporte preliminar con evidencias encontradas", "comandos": ["# Capturar screenshots de errores", "# Documentar métricas anormales"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Baja', 'En Progreso', 'FTE-044', NULL, 'INC-20260322-F36E', NULL, 2.0, 0.0, '2026-03-22 19:21:22.331187+00', NULL, NULL, '[]', '2026-03-22 19:21:22.331187+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-59C0', 'Diagnóstico inicial conectividad Redsys', '{"silo": "REDES", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Ping a Redsys exitoso", "Puerto 443 accesible", "Rutas de red correctas", "Interfaces operativas", "DNS resolviendo correctamente"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Gateway Principal", "valor": "172.16.40.1", "source": "CMDB"}, {"campo": "VLAN DMZ", "valor": "VLAN 40 - DMZ-PUBLICA", "source": "CMDB"}, {"campo": "Subred DMZ", "valor": "172.16.40.0/24", "source": "CMDB"}, {"campo": "Redsys IP", "valor": "194.224.207.69 (TPV Virtual)", "source": "IA"}, {"campo": "Puerto Redsys", "valor": "443 (HTTPS)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Comprobar conectividad desde gateway DMZ hacia Redsys", "comandos": ["ping -c 4 194.224.207.69", "telnet 194.224.207.69 443"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar rutas de red", "detalle": "Comprobar tabla de rutas y next-hop hacia Redsys", "comandos": ["traceroute 194.224.207.69", "ip route get 194.224.207.69"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar estado interfaces", "detalle": "Verificar estado de interfaces de red críticas", "comandos": ["ip link show", "ip addr show", "netstat -i"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Comprobar DNS", "detalle": "Verificar resolución DNS de dominios Redsys", "comandos": ["nslookup sis.redsys.es", "dig +trace redsys.es"], "source_comandos": "IA"}], "skill_requerida": "Redes: Ping", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Crítica', 'En Progreso', 'FTE-050', NULL, 'INC-20260322-17AD', NULL, 0.5, 0.0, '2026-03-22 22:11:48.888055+00', NULL, NULL, '[]', '2026-03-22 22:11:48.888055+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-91DE', 'Validación y cierre de incidencia', '{"silo": "Soporte", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Usuario confirma resolución del problema", "SLA cumplido dentro del tiempo establecido", "Documentación de resolución completa", "Causa raíz documentada", "Estado cambiado a cerrado", "Notificaciones enviadas a stakeholders"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Tipo tarea", "valor": "Validación y cierre", "source": "IA"}, {"campo": "Sistema", "valor": "Sistema de gestión de incidencias", "source": "IA"}, {"campo": "Prioridad", "valor": "Normal", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Revisar estado actual de la incidencia", "detalle": "Verificar que todas las acciones correctivas han sido implementadas", "comandos": ["Revisar historial completo en ITSM", "Verificar logs de actividad"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar resolución con usuario", "detalle": "Contactar al usuario reportante para confirmar que el problema está resuelto", "comandos": ["Llamada telefónica o email de validación", "Documentar respuesta del usuario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar métricas de SLA", "detalle": "Confirmar que la incidencia se resuelve dentro del SLA establecido", "comandos": ["Revisar tiempo transcurrido vs SLA", "Documentar cumplimiento"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Actualizar documentación", "detalle": "Completar la resolución con detalles técnicos y lecciones aprendidas", "comandos": ["Actualizar campo de resolución", "Agregar causa raíz identificada"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cerrar incidencia", "detalle": "Cambiar estado a cerrado y notificar a stakeholders", "comandos": ["Cambiar estado a ''Cerrado''", "Enviar notificación automática"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Media', 'Backlog', 'FTE-013', NULL, 'INC-20260322-F414', NULL, 0.5, 0.0, '2026-03-22 17:15:38.867739+00', NULL, NULL, '[]', '2026-03-22 17:15:38.867739+00');
