INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-FB48', 'Diagnóstico inicial del escáner de valijas', '{"silo": "Soporte Técnico", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Síntomas documentados completamente", "Inspección visual realizada", "Pruebas eléctricas completadas", "Autodiagnóstico ejecutado", "Reporte inicial generado", "Próximos pasos definidos"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Equipo", "valor": "Escáner de valijas", "source": "IA"}, {"campo": "Tipo diagnóstico", "valor": "Inicial - Identificación de fallas", "source": "IA"}, {"campo": "Herramientas", "valor": "Multímetro, software de diagnóstico", "source": "IA"}, {"campo": "Documentación", "valor": "Manual técnico del fabricante", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilación de síntomas", "detalle": "Documentar todos los síntomas reportados y observables", "comandos": ["Entrevistar al operador", "Revisar logs de sistema", "Documentar errores en pantalla"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Inspección visual inicial", "detalle": "Examinar el equipo externamente en busca de daños evidentes", "comandos": ["Revisar integridad de carcasa", "Verificar conexiones externas", "Comprobar indicadores LED"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Pruebas eléctricas básicas", "detalle": "Verificar alimentación y continuidad de circuitos principales", "comandos": ["Medir voltaje de entrada (220V/110V)", "Verificar fusibles principales", "Comprobar continuidad de cables"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Diagnóstico por software", "detalle": "Ejecutar rutinas de autodiagnóstico del sistema", "comandos": ["Acceder a menú de diagnóstico", "Ejecutar test de componentes", "Revisar códigos de error generados"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Análisis y reporte inicial", "detalle": "Compilar hallazgos y generar diagnóstico preliminar", "comandos": ["Analizar resultados de pruebas", "Identificar componentes sospechosos", "Generar reporte de diagnóstico inicial"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Diagnóstico Fuente", "requiere_negocio": false, "sla_tarea_minutos": 150}', 'RUN', 'Media', 'En Progreso', 'FTE-013', NULL, 'INC-20260322-F414', NULL, 1.5, 0.0, '2026-03-22 17:15:38.851372+00', NULL, NULL, '[]', '2026-03-22 17:15:38.851372+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-8BA4', 'Restauración servicio Redsys', '{"silo": "APLICACION", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Estado de pods verificado", "Servicio reiniciado correctamente", "Configuración Kong validada", "Conectividad restaurada", "Logs sin errores", "Health check OK"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "API Gateway", "valor": "172.16.40.12 (Kong Enterprise 3.5)", "source": "CMDB"}, {"campo": "Cluster K8S", "valor": "K8S-PRO-001", "source": "CMDB"}, {"campo": "Rutas API", "valor": "340 rutas configuradas", "source": "CMDB"}, {"campo": "Servicio Redsys", "valor": "/api/v1/payments/redsys", "source": "IA"}, {"campo": "Namespace", "valor": "payments-prod", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado del servicio", "detalle": "Comprobar estado de pods y servicios Redsys", "comandos": ["kubectl get pods -n payments-prod | grep redsys", "kubectl get svc -n payments-prod | grep redsys"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Reiniciar servicio Redsys", "detalle": "Realizar restart controlado del servicio", "comandos": ["kubectl rollout restart deployment/redsys-service -n payments-prod", "kubectl rollout status deployment/redsys-service -n payments-prod"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar configuración Kong", "detalle": "Comprobar rutas y plugins de Kong para Redsys", "comandos": ["curl -s http://172.16.40.12:8001/routes | jq ''.data[] | select(.name | contains(\"redsys\"))''", "curl -s http://172.16.40.12:8001/services | jq ''.data[] | select(.name | contains(\"redsys\"))''"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Test de conectividad", "detalle": "Probar endpoint Redsys desde API Gateway", "comandos": ["curl -I http://172.16.40.12:8443/api/v1/payments/redsys/health", "curl -X POST http://172.16.40.12:8443/api/v1/payments/redsys/test"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Verificar logs de aplicación", "detalle": "Revisar logs para confirmar restauración", "comandos": ["kubectl logs -n payments-prod deployment/redsys-service --tail=50", "kubectl logs -n payments-prod -l app=api-gateway --tail=20"], "source_comandos": "IA"}], "skill_requerida": "Redes: IP/Gateway", "requiere_negocio": false, "sla_tarea_minutos": 180}', 'RUN', 'Crítica', 'Backlog', 'FTE-050', NULL, 'INC-20260322-17AD', NULL, 1.5, 0.0, '2026-03-22 22:11:48.911536+00', NULL, NULL, '[]', '2026-03-22 22:11:48.911536+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-26A9', 'Diagnóstico inicial del torno bloqueado', '{"silo": "HARDWARE", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Estado visual documentado con fotos", "Alimentación eléctrica verificada", "Códigos de error registrados", "Sistema de control evaluado", "Componentes mecánicos inspeccionados", "Informe diagnóstico completado", "Siguiente acción recomendada definida"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Equipo", "valor": "Torno industrial bloqueado", "source": "IA"}, {"campo": "Ubicación", "valor": "Planta producción", "source": "IA"}, {"campo": "Tipo fallo", "valor": "Bloqueo mecánico/software", "source": "IA"}, {"campo": "Prioridad", "valor": "ALTA - Parada producción", "source": "IA"}, {"campo": "Acceso requerido", "valor": "Seguridad Física + Técnico", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Evaluación visual inicial", "detalle": "Inspeccionar el torno sin tocar controles", "comandos": ["Revisar panel de control", "Verificar luces de estado", "Comprobar mensajes de error en pantalla"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar alimentación eléctrica", "detalle": "Comprobar suministro eléctrico y protecciones", "comandos": ["Verificar interruptor principal", "Revisar fusibles/magnetotérmicos", "Medir tensión con multímetro"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Diagnóstico sistema control", "detalle": "Evaluar PLC y sistema de control", "comandos": ["Acceder a diagnósticos PLC", "Revisar log de eventos", "Verificar comunicación HMI-PLC"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Evaluación mecánica", "detalle": "Inspeccionar componentes mecánicos", "comandos": ["Verificar mordazas y sujeción", "Comprobar ejes X/Y/Z", "Revisar sistema hidráulico/neumático"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos", "detalle": "Registrar diagnóstico inicial", "comandos": ["Fotografiar estado actual", "Anotar códigos de error", "Completar checklist diagnóstico"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Diagnóstico Fuente", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Media', 'En Progreso', 'FTE-087', NULL, 'INC-20260322-9564', NULL, 1.0, 0.0, '2026-03-22 17:18:58.840317+00', NULL, NULL, '[]', '2026-03-22 17:18:58.840317+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-5F8D', 'Verificación estado usuarios AD en torno', '{"silo": "SEGURIDAD", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Conexión a Azure AD establecida", "Usuarios del torno identificados", "Estado de cuentas verificado", "Permisos y grupos revisados", "Políticas Conditional Access validadas", "Log de eventos consultado", "Informe de estado AD completado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema AD", "valor": "Azure AD Premium P2", "source": "CMDB"}, {"campo": "Usuarios totales", "valor": "850", "source": "CMDB"}, {"campo": "Conditional Access", "valor": "Habilitado", "source": "CMDB"}, {"campo": "PIM", "valor": "Habilitado", "source": "CMDB"}, {"campo": "Responsable", "valor": "Beatriz Castaño Villar", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a Azure AD", "detalle": "Acceder al portal de administración", "comandos": ["Connect-AzureAD", "Get-AzureADTenantDetail"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Identificar usuarios del torno", "detalle": "Buscar cuentas relacionadas con equipos industriales", "comandos": ["Get-AzureADUser -Filter \"Department eq ''Produccion''\"", "Get-AzureADUser -SearchString ''torno''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado de cuentas", "detalle": "Comprobar si las cuentas están activas y sin bloqueos", "comandos": ["Get-AzureADUser -ObjectId <user> | Select AccountEnabled,UserPrincipalName", "Get-AzureADAuditSignInLogs -Filter \"userPrincipalName eq ''<user>''\""], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar permisos y grupos", "detalle": "Verificar membresía en grupos de acceso al torno", "comandos": ["Get-AzureADUserMembership -ObjectId <user>", "Get-AzureADGroup -Filter \"displayName eq ''Torno_Operators''\""], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar Conditional Access", "detalle": "Comprobar políticas que afecten al acceso", "comandos": ["Get-AzureADMSConditionalAccessPolicy", "Get-AzureADMSNamedLocationPolicy"], "source_comandos": "IA"}], "skill_requerida": "AD: Reset Password", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Media', 'Backlog', 'FTE-038', NULL, 'INC-20260322-9564', NULL, 0.5, 0.0, '2026-03-22 17:18:58.850514+00', NULL, NULL, '[]', '2026-03-22 17:18:58.850514+00');
