INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-0EDA', 'Verificación funcional post-reparación', '{"silo": "HARDWARE", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Sistemas iniciales verificados", "Arranque sin alarmas completado", "Movimiento ejes validado", "Ciclo de prueba ejecutado correctamente", "Pieza test dentro de tolerancias", "Documentación pruebas completada", "Torno listo para producción"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Equipo", "valor": "Torno industrial reparado", "source": "IA"}, {"campo": "Tipo verificación", "valor": "Funcional post-reparación", "source": "IA"}, {"campo": "Criterios aceptación", "valor": "Funcionamiento normal sin errores", "source": "IA"}, {"campo": "Programa prueba", "valor": "Ciclo completo mecanizado", "source": "IA"}, {"campo": "Tolerancias", "valor": "Según especificaciones fabricante", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificación inicial sistemas", "detalle": "Comprobar todos los sistemas antes de arranque", "comandos": ["Verificar conexiones eléctricas", "Comprobar niveles fluidos", "Revisar sistema seguridad"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Arranque controlado", "detalle": "Iniciar el torno de forma gradual", "comandos": ["Encender sistema control", "Ejecutar rutina inicialización", "Verificar ausencia alarmas"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Pruebas movimiento ejes", "detalle": "Verificar movimiento correcto de todos los ejes", "comandos": ["Mover eje X en modo manual", "Mover eje Z en modo manual", "Verificar precisión posicionamiento"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Ciclo de prueba completo", "detalle": "Ejecutar programa de prueba con pieza test", "comandos": ["Cargar programa prueba CNC", "Montar pieza de prueba", "Ejecutar ciclo completo"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validación final", "detalle": "Verificar calidad y documentar resultados", "comandos": ["Medir dimensiones pieza test", "Verificar acabado superficial", "Documentar resultados prueba"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Inventario Activos", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Media', 'Backlog', 'FTE-013', NULL, 'INC-20260322-9564', NULL, 1.0, 0.0, '2026-03-22 17:18:58.864676+00', NULL, NULL, '[]', '2026-03-22 17:18:58.864676+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-7003', 'Análisis logs aplicación web y base de datos', '{"silo": "BBDD", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Logs aplicación extraídos y revisados", "Logs base de datos obtenidos", "Errores críticos identificados", "Correlación temporal analizada", "Reporte de hallazgos generado", "Recomendaciones documentadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Aplicación", "valor": "Portal del Empleado (APP-PRO-017)", "source": "CMDB"}, {"campo": "Namespace K8s", "valor": "portal-inmobiliario", "source": "IA"}, {"campo": "Base de datos", "valor": "PostgreSQL (estimado)", "source": "IA"}, {"campo": "Puerto BD", "valor": "5432", "source": "IA"}, {"campo": "Logs BD", "valor": "/var/log/postgresql/", "source": "IA"}, {"campo": "Logs App", "valor": "kubectl logs", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Extraer logs aplicación web", "detalle": "Obtener logs detallados de los pods del portal", "comandos": ["kubectl logs -n portal-inmobiliario -l app=portal-inmobiliario --since=24h > app_logs.txt", "kubectl logs -n portal-inmobiliario -l app=portal-inmobiliario --previous > app_logs_previous.txt"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Identificar pod de base de datos", "detalle": "Localizar el pod o servicio de BD asociado", "comandos": ["kubectl get pods -n portal-inmobiliario | grep -E ''(postgres|mysql|oracle)''", "kubectl get svc -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Extraer logs base de datos", "detalle": "Obtener logs de BD según el motor identificado", "comandos": ["kubectl logs -n portal-inmobiliario -l app=postgresql --since=24h > db_logs.txt", "kubectl exec -n portal-inmobiliario [POD-BD] -- tail -n 500 /var/log/postgresql/postgresql.log"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar errores críticos", "detalle": "Buscar patrones de error en ambos logs", "comandos": ["grep -i ''error\\|exception\\|failed\\|timeout'' app_logs.txt", "grep -i ''error\\|fatal\\|connection'' db_logs.txt"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Correlacionar timestamps", "detalle": "Identificar coincidencias temporales entre errores", "comandos": ["awk ''{print $1, $2, $0}'' app_logs.txt | sort", "awk ''{print $1, $2, $0}'' db_logs.txt | sort"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte de análisis", "detalle": "Documentar hallazgos y recomendaciones", "comandos": ["echo ''REPORTE LOGS - $(date)'' > analisis_logs.txt"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Crítica', 'Backlog', 'FTE-139', NULL, 'INC-20260322-A177', NULL, 0.8, 0.0, '2026-03-22 18:04:21.95325+00', NULL, NULL, '[]', '2026-03-22 18:04:21.95325+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-1B50', 'Verificar infraestructura y conectividad', '{"silo": "REDES", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Resolución DNS verificada", "Conectividad externa comprobada", "Estado cluster K8s revisado", "Servicios de red validados", "Conectividad interna probada", "Certificados SSL verificados", "Resultados documentados"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Cluster K8s", "valor": "K8S-PRO-001", "source": "CMDB"}, {"campo": "Aplicación", "valor": "Portal del Empleado", "source": "CMDB"}, {"campo": "Red interna", "valor": "10.0.0.0/16 (estimada)", "source": "IA"}, {"campo": "Load Balancer", "valor": "192.168.100.10 (estimado)", "source": "IA"}, {"campo": "DNS", "valor": "portal-inmobiliario.empresa.com", "source": "IA"}, {"campo": "Puertos", "valor": "80, 443, 5432", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución DNS", "detalle": "Comprobar que el FQDN resuelve correctamente", "comandos": ["nslookup portal-inmobiliario.empresa.com", "dig portal-inmobiliario.empresa.com +short"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Probar conectividad externa", "detalle": "Verificar acceso desde diferentes segmentos de red", "comandos": ["telnet portal-inmobiliario.empresa.com 443", "curl -I https://portal-inmobiliario.empresa.com --connect-timeout 10"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado cluster Kubernetes", "detalle": "Comprobar salud de nodos y servicios K8s", "comandos": ["kubectl get nodes", "kubectl get pods --all-namespaces | grep -v Running"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar servicios de red K8s", "detalle": "Verificar servicios, ingress y load balancers", "comandos": ["kubectl get svc -n portal-inmobiliario", "kubectl get ingress -n portal-inmobiliario", "kubectl describe svc -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Probar conectividad interna", "detalle": "Verificar comunicación entre pods", "comandos": ["kubectl exec -n portal-inmobiliario [POD-APP] -- nc -zv [IP-BD] 5432", "kubectl get endpoints -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Verificar certificados SSL", "detalle": "Comprobar validez y expiración de certificados", "comandos": ["openssl s_client -connect portal-inmobiliario.empresa.com:443 -servername portal-inmobiliario.empresa.com"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Escalado Nivel", "requiere_negocio": false, "sla_tarea_minutos": 75}', 'RUN', 'Crítica', 'Backlog', 'FTE-068', NULL, 'INC-20260322-A177', NULL, 0.5, 0.0, '2026-03-22 18:04:21.956983+00', NULL, NULL, '[]', '2026-03-22 18:04:21.956983+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-14CD', 'Diagnóstico inicial - Verificar estado portal inmobiliario', '{"silo": "APLICACIONES", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Portal accesible desde navegador verificado", "Estado pods Kubernetes revisado", "Logs de aplicación analizados", "Servicios K8s verificados", "Hallazgos documentados en ticket"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Aplicación", "valor": "Portal del Empleado (APP-PRO-017)", "source": "CMDB"}, {"campo": "Entorno", "valor": "PRODUCCION", "source": "CMDB"}, {"campo": "Ubicación", "valor": "K8S-PRO-001", "source": "CMDB"}, {"campo": "Pods", "valor": "2", "source": "CMDB"}, {"campo": "URL Portal", "valor": "https://portal-inmobiliario.empresa.com", "source": "IA"}, {"campo": "Puerto HTTPS", "valor": "443", "source": "IA"}, {"campo": "Namespace K8s", "valor": "portal-inmobiliario", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar acceso externo al portal", "detalle": "Comprobar disponibilidad desde navegador y curl", "comandos": ["curl -I https://portal-inmobiliario.empresa.com", "nslookup portal-inmobiliario.empresa.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar estado pods Kubernetes", "detalle": "Revisar estado de los pods del portal", "comandos": ["kubectl get pods -n portal-inmobiliario", "kubectl describe pods -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar servicios y endpoints", "detalle": "Comprobar servicios K8s y conectividad interna", "comandos": ["kubectl get svc -n portal-inmobiliario", "kubectl get endpoints -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de aplicación", "detalle": "Obtener logs recientes para identificar errores", "comandos": ["kubectl logs -n portal-inmobiliario -l app=portal-inmobiliario --tail=100"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos", "detalle": "Registrar estado actual y problemas identificados", "comandos": ["echo ''Estado: [OK/ERROR] - Detalles: [descripción]'' >> diagnostico.txt"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Crítica', 'En Progreso', 'FTE-087', NULL, 'INC-20260322-A177', NULL, 0.5, 0.0, '2026-03-22 18:04:21.943712+00', NULL, NULL, '[]', '2026-03-22 18:04:21.943712+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-9A6F', 'Restaurar servicio portal inmobiliario', '{"silo": "APLICACIONES", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Estado actual evaluado", "Pods aplicación reiniciados", "Base de datos verificada", "Escalado correcto confirmado", "Servicios externos operativos", "Prueba funcional exitosa", "Estabilidad monitoreada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Aplicación", "valor": "Portal del Empleado (APP-PRO-017)", "source": "CMDB"}, {"campo": "Entorno", "valor": "PRODUCCION", "source": "CMDB"}, {"campo": "Ubicación", "valor": "K8S-PRO-001", "source": "CMDB"}, {"campo": "Pods objetivo", "valor": "2", "source": "CMDB"}, {"campo": "Namespace", "valor": "portal-inmobiliario", "source": "IA"}, {"campo": "Imagen Docker", "valor": "portal-inmobiliario:latest", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Evaluar estado actual", "detalle": "Verificar qué componentes están caídos", "comandos": ["kubectl get pods -n portal-inmobiliario", "kubectl get svc -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Reiniciar pods aplicación", "detalle": "Realizar restart controlado de los pods", "comandos": ["kubectl rollout restart deployment/portal-inmobiliario -n portal-inmobiliario", "kubectl rollout status deployment/portal-inmobiliario -n portal-inmobiliario"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar base de datos", "detalle": "Comprobar y restaurar servicio de BD si es necesario", "comandos": ["kubectl get pods -n portal-inmobiliario | grep postgres", "kubectl logs -n portal-inmobiliario [POD-BD] --tail=50"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Escalar pods si es necesario", "detalle": "Asegurar que hay 2 pods corriendo", "comandos": ["kubectl scale deployment portal-inmobiliario --replicas=2 -n portal-inmobiliario", "kubectl get pods -n portal-inmobiliario -w"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar servicios externos", "detalle": "Comprobar ingress, load balancer y DNS", "comandos": ["kubectl get ingress -n portal-inmobiliario", "curl -I https://portal-inmobiliario.empresa.com"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Prueba funcional básica", "detalle": "Verificar que el portal responde correctamente", "comandos": ["curl -s https://portal-inmobiliario.empresa.com | grep -i ''title\\|error''"], "source_comandos": "IA"}, {"paso": 7, "titulo": "Monitorear estabilidad", "detalle": "Observar logs por 10 minutos para confirmar estabilidad", "comandos": ["kubectl logs -n portal-inmobiliario -l app=portal-inmobiliario -f --tail=20"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Escalado Nivel", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Crítica', 'Backlog', 'FTE-127', NULL, 'INC-20260322-A177', NULL, 1.5, 0.0, '2026-03-22 18:04:21.961567+00', NULL, NULL, '[]', '2026-03-22 18:04:21.961567+00');
