INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-CEF8', 'Verificación de contenido y configuración', '{"silo": "Aplicaciones", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Integridad de archivos verificada", "Configuración web validada", "Puertos y servicios activos", "Logs revisados sin errores críticos", "Conectividad BD confirmada", "Contenido dinámico funcional"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor web", "valor": "Apache/Nginx", "source": "IA"}, {"campo": "Base de datos", "valor": "MySQL/PostgreSQL", "source": "IA"}, {"campo": "Ruta contenido", "valor": "/var/www/html/ o /opt/app/content/", "source": "IA"}, {"campo": "Archivos config", "valor": "/etc/httpd/conf/ o /etc/nginx/", "source": "IA"}, {"campo": "Puerto web", "valor": "80, 443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar integridad del contenido", "detalle": "Revisar archivos y estructura de directorios", "comandos": ["find /var/www/html -type f -name ''*.html'' -exec ls -la {} \\;", "md5sum /path/to/critical/files", "du -sh /var/www/html/*"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar configuración del servidor web", "detalle": "Revisar archivos de configuración y sintaxis", "comandos": ["nginx -t", "apache2ctl configtest", "cat /etc/nginx/nginx.conf | grep -v ''^#''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad y puertos", "detalle": "Comprobar que los servicios estén activos y accesibles", "comandos": ["netstat -tlnp | grep :80", "netstat -tlnp | grep :443", "curl -I http://localhost", "systemctl status nginx"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de errores", "detalle": "Analizar logs para identificar problemas", "comandos": ["tail -50 /var/log/nginx/error.log", "tail -50 /var/log/apache2/error.log", "grep ERROR /var/log/nginx/access.log"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar contenido dinámico", "detalle": "Verificar conexión a base de datos y scripts", "comandos": ["mysql -u user -p -e ''SHOW DATABASES;''", "php -m | grep mysql", "curl -X GET http://localhost/api/health"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'Backlog', 'FTE-148', NULL, 'INC-20260322-1656', NULL, 2.0, 0.0, '2026-03-22 19:01:34.712793+00', NULL, NULL, '[]', '2026-03-22 19:01:34.712793+00');
