aciones automáticas", "Definir frecuencia de status meetings"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar acuerdos y compromisos", "detalle": "Formalizar lo acordado en documentación oficial", "comandos": ["Crear documento de coordinación", "Obtener firmas/aprobaciones", "Distribuir a todos los stakeholders"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Escalado Nivel", "contacto_negocio": {"area": "Banca Digital", "cargo": "Directora de Banca Digital", "email": "isabel.moreno@bcc.test", "nombre": "Isabel Moreno Castro", "telefono": "+34 612 001 052"}, "requiere_negocio": true, "sla_tarea_minutos": 180}', 'RUN', 'Baja', 'Backlog', 'FTE-112', NULL, 'INC-20260322-1656', NULL, 3.0, 0.0, '2026-03-22 19:01:34.710266+00', NULL, NULL, '[]', '2026-03-22 19:01:34.710266+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-7285', 'Validación y cierre de incidencia', '{"silo": "Operaciones", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Incidencia técnicamente validada", "Usuario confirma resolución", "Documentación actualizada en KB", "Métricas SLA cumplidas", "Ticket cerrado formalmente", "Notificaciones enviadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema ticketing", "valor": "ServiceNow/ITSM", "source": "IA"}, {"campo": "Base conocimiento", "valor": "Confluence/SharePoint", "source": "IA"}, {"campo": "Dashboard monitoreo", "valor": "Nagios/Zabbix", "source": "IA"}, {"campo": "Métricas SLA", "valor": "Portal gestión incidencias", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Revisar estado actual de la incidencia", "detalle": "Acceder al sistema de tickets y verificar historial completo", "comandos": ["Abrir ticket en ITSM", "Revisar timeline de acciones", "Verificar logs de cambios"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar resolución técnica", "detalle": "Confirmar que la solución implementada funciona correctamente", "comandos": ["Ejecutar tests de validación", "Revisar métricas post-resolución", "Confirmar estabilidad del servicio"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar satisfacción del usuario", "detalle": "Contactar al usuario reportante para confirmar resolución", "comandos": ["Llamar/email al usuario", "Documentar feedback recibido", "Actualizar ticket con confirmación"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Documentar lecciones aprendidas", "detalle": "Registrar conocimiento para futuras incidencias similares", "comandos": ["Crear/actualizar artículo KB", "Documentar root cause", "Registrar tiempo de resolución"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cerrar formalmente la incidencia", "detalle": "Completar cierre siguiendo procedimientos ITIL", "comandos": ["Cambiar estado a ''Resuelto''", "Completar campos obligatorios", "Notificar cierre a stakeholders"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Escalado Nivel", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'Backlog', 'FTE-028', NULL, 'INC-20260322-1656', NULL, 1.0, 0.0, '2026-03-22 19:01:34.716433+00', NULL, NULL, '[]', '2026-03-22 19:01:34.716433+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-328E', 'Revisión técnica de plataformas RRSS', '{"silo": "Aplicaciones", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Conectividad APIs verificada", "Tokens válidos y vigentes", "Configuración app correcta", "Tests funcionales pasados", "Logs revisados sin errores", "Métricas dentro de límites"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "APIs RRSS", "valor": "Facebook Graph API, Twitter API v2, Instagram API", "source": "IA"}, {"campo": "Servidor aplicación", "valor": "Node.js/Python/Java", "source": "IA"}, {"campo": "Base datos", "valor": "MongoDB/PostgreSQL", "source": "IA"}, {"campo": "Tokens/Keys", "valor": "Vault/KeyVault para credenciales", "source": "IA"}, {"campo": "Puerto API", "valor": "3000, 8080, 8443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad APIs RRSS", "detalle": "Probar conexión a cada plataforma social", "comandos": ["curl -H ''Authorization: Bearer TOKEN'' https://graph.facebook.com/v18.0/me", "curl -H ''Authorization: Bearer TOKEN'' https://api.twitter.com/2/users/me", "curl -H ''Authorization: Bearer TOKEN'' https://graph.instagram.com/me"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Validar tokens y credenciales", "detalle": "Verificar vigencia y permisos de tokens de acceso", "comandos": ["curl -X GET ''https://graph.facebook.com/debug_token?input_token=TOKEN''", "node -e ''console.log(jwt.decode(process.env.TWITTER_TOKEN))''", "python -c ''import jwt; print(jwt.decode(token, verify=False))''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar configuración de aplicación", "detalle": "Verificar parámetros y variables de entorno", "comandos": ["cat /opt/app/config/social.json", "env | grep -E ''(FACEBOOK|TWITTER|INSTAGRAM)''", "systemctl status social-media-app"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar funcionalidades principales", "detalle": "Ejecutar tests de publicación y lectura", "comandos": ["npm test -- --grep ''social media''", "python -m pytest tests/test_social_apis.py", "curl -X POST localhost:3000/api/test-publish"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Analizar logs y métricas", "detalle": "Revisar logs de errores y rendimiento", "comandos": ["tail -100 /var/log/social-app/error.log", "grep -i ''rate limit'' /var/log/social-app/api.log", "curl localhost:3000/metrics | grep social"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Baja', 'Backlog', 'FTE-025', NULL, 'INC-20260322-1656', NULL, 4.0, 0.0, '2026-03-22 19:01:34.706529+00', NULL, NULL, '[]', '2026-03-22 19:01:34.706529+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-0B76', 'Diagnóstico inicial del error de publicación', '{"silo": "Aplicaciones", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Información del error recopilada", "Logs del sistema analizados", "Estado de servicios verificado", "Error reproducido exitosamente", "Hallazgos documentados", "Ticket actualizado con diagnóstico"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema publicación", "valor": "CMS/WordPress/Drupal", "source": "IA"}, {"campo": "Servidor web", "valor": "Apache/Nginx", "source": "IA"}, {"campo": "Base datos", "valor": "MySQL/MariaDB", "source": "IA"}, {"campo": "Logs aplicación", "valor": "/var/log/apache2/ o /var/log/nginx/", "source": "IA"}, {"campo": "Puerto web", "valor": "80, 443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Recopilar información del error", "detalle": "Obtener detalles del problema reportado", "comandos": ["Revisar ticket de incidencia", "Contactar usuario afectado", "Documentar síntomas observados"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs del sistema", "detalle": "Analizar logs para identificar errores", "comandos": ["tail -200 /var/log/apache2/error.log | grep -i error", "tail -200 /var/log/nginx/error.log", "journalctl -u apache2 -f --since ''1 hour ago''"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado de servicios", "detalle": "Comprobar que todos los servicios estén activos", "comandos": ["systemctl status apache2", "systemctl status mysql", "ps aux | grep -E ''(apache|nginx|mysql)''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar funcionalidad de publicación", "detalle": "Intentar reproducir el error paso a paso", "comandos": ["curl -I http://localhost/admin/publish", "mysql -u root -p -e ''SHOW PROCESSLIST;''", "tail -f /var/log/mysql/error.log &"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos iniciales", "detalle": "Registrar evidencias para análisis posterior", "comandos": ["Capturar screenshots de errores", "Exportar logs relevantes", "Actualizar ticket con diagnóstico inicial"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'En Progreso', 'FTE-006', NULL, 'INC-20260322-1656', NULL, 2.0, 0.0, '2026-03-22 19:01:34.700366+00', NULL, NULL, '[]', '2026-03-22 19:01:34.700366+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-3626', 'Revisar logs del sistema de autenticación OTP', '{"silo": "Seguridad", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Logs de autenticación revisados", "Errores de generación OTP identificados", "Integración SMS Gateway verificada", "Métricas de rendimiento analizadas", "Patrones de fallos documentados", "Recomendaciones de solución preparadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema OTP", "valor": "No identificado en CMDB", "source": "CMDB"}, {"campo": "Logs OTP", "valor": "/var/log/auth-otp/", "source": "IA"}, {"campo": "Puerto OTP", "valor": "8443 (HTTPS)", "source": "IA"}, {"campo": "Base datos", "valor": "PostgreSQL puerto 5432", "source": "IA"}, {"campo": "Redis cache", "valor": "Puerto 6379", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor de autenticación", "detalle": "Conectar al sistema OTP", "comandos": ["ssh admin@auth-otp-server", "sudo su - otp-service"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs de autenticación", "detalle": "Analizar intentos fallidos y errores", "comandos": ["tail -f /var/log/auth-otp/authentication.log", "grep -i ''failed\\|error\\|timeout'' /var/log/auth-otp/authentication.log | tail -50"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar logs de generación OTP", "detalle": "Comprobar proceso de generación de tokens", "comandos": ["grep ''OTP_GENERATE'' /var/log/auth-otp/otp-generator.log | tail -20", "grep ''SMS_SEND'' /var/log/auth-otp/sms-integration.log | tail -20"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar métricas de rendimiento", "detalle": "Revisar tiempos de respuesta y throughput", "comandos": ["grep ''response_time'' /var/log/auth-otp/performance.log | tail -30", "cat /var/log/auth-otp/metrics.log | grep $(date +%Y-%m-%d)"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar integración con SMS Gateway", "detalle": "Comprobar comunicación entre sistemas", "comandos": ["grep ''SMS_GATEWAY'' /var/log/auth-otp/integration.log | tail -15", "curl -s http://sms-gateway:8080/status"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "contacto_negocio": {"area": "Operaciones Bancarias", "cargo": "Directora de Operaciones Bancarias", "email": "carmen.ruiz@bcc.test", "nombre": "Carmen Ruiz Delgado", "telefono": "+34 612 001 050"}, "requiere_negocio": true, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'Backlog', 'FTE-112', NULL, 'INC-20260322-35D1', NULL, 4.0, 0.0, '2026-03-22 19:06:44.867791+00', NULL, NULL, '[]', '2026-03-22 19:06:44.867791+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-2643', 'Coordinar con área de Operaciones Bancarias', '{"silo": "PMO", "tipo": "BUILD", "orden": 4, "enriched": true, "checklist": ["Contactos de Operaciones identificados", "Contexto técnico preparado", "Reunión agendada y realizada", "Acuerdos documentados", "Plan de acción definido", "Seguimiento programado"], "area_negocio": "Operaciones Bancarias", "contexto_cmdb": {"items": [{"campo": "Stakeholder", "valor": "Operaciones Bancarias", "source": "IA"}, {"campo": "Canal comunicación", "valor": "Teams/Email", "source": "IA"}, {"campo": "Documentos", "valor": "Actas de reunión", "source": "IA"}, {"campo": "SLA coordinación", "valor": "24 horas", "source": "IA"}, {"campo": "Escalamiento", "valor": "Gerencia TI", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Identificar contactos clave", "detalle": "Localizar responsables de Operaciones Bancarias", "comandos": ["Consultar directorio corporativo", "Revisar matriz RACI del proyecto"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Preparar contexto técnico", "detalle": "Documentar hallazgos técnicos para negocio", "comandos": ["Compilar resultados de diagnóstico", "Preparar resumen ejecutivo"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Agendar reunión de coordinación", "detalle": "Convocar a stakeholders necesarios", "comandos": ["Enviar invitación Outlook/Teams", "Incluir agenda y documentos previos"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Facilitar sesión de trabajo", "detalle": "Conducir reunión con Operaciones", "comandos": ["Presentar situación actual", "Definir plan de acción conjunto"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar acuerdos", "detalle": "Registrar compromisos y plazos", "comandos": ["Elaborar acta de reunión", "Distribuir plan de acción"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "contacto_negocio": {"area": "Operaciones Bancarias", "cargo": "Directora de Operaciones Bancarias", "email": "carmen.ruiz@bcc.test", "nombre": "Carmen Ruiz Delgado", "telefono": "+34 612 001 050"}, "requiere_negocio": true, "sla_tarea_minutos": 180}', 'RUN', 'Baja', 'Backlog', 'FTE-101', NULL, 'INC-20260322-35D1', NULL, 2.0, 0.0, '2026-03-22 19:06:44.876946+00', NULL, NULL, '[]', '2026-03-22 19:06:44.876946+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-8E4A', 'Validación y cierre', '{"silo": "PMO", "tipo": "RUN", "orden": 6, "enriched": true, "checklist": ["Pruebas de validación exitosas", "Solución documentada completamente", "Stakeholders notificados", "Base de conocimiento actualizada", "Incidencia cerrada formalmente", "Métricas SLA registradas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Sistema SMS", "valor": "Gateway SMS + OTP", "source": "IA"}, {"campo": "Documentación", "valor": "Informe de incidencia", "source": "IA"}, {"campo": "Stakeholders", "valor": "Operaciones + Negocio", "source": "IA"}, {"campo": "Métricas SLA", "valor": "Tiempo resolución", "source": "IA"}, {"campo": "Estado final", "valor": "Operativo", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Ejecutar pruebas de validación", "detalle": "Confirmar funcionamiento end-to-end", "comandos": ["Ejecutar test de envío SMS", "Validar generación OTP", "Verificar autenticación completa"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Documentar solución implementada", "detalle": "Registrar fix aplicado y resultados", "comandos": ["Actualizar ticket con solución", "Documentar pasos de resolución", "Adjuntar evidencias técnicas"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Notificar a stakeholders", "detalle": "Comunicar resolución a involucrados", "comandos": ["Enviar email de cierre", "Actualizar dashboard de incidencias", "Notificar a Operaciones Bancarias"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Actualizar base de conocimiento", "detalle": "Registrar solución para futuros casos", "comandos": ["Crear artículo en KB", "Etiquetar con palabras clave", "Vincular a procedimientos"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Cerrar formalmente la incidencia", "detalle": "Completar proceso de cierre", "comandos": ["Cambiar estado a ''Resuelto''", "Asignar categoría de cierre", "Confirmar satisfacción del usuario"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'Backlog', 'FTE-006', NULL, 'INC-20260322-35D1', NULL, 1.0, 0.0, '2026-03-22 19:06:44.886005+00', NULL, NULL, '[]', '2026-03-22 19:06:44.886005+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('BLD-8C3445', 'Compliance y seguridad', '{"skill": "Seguridad", "fase": "Análisis y Diseño", "enriched": false}', 'BUILD', 'Media', 'Backlog', 'FTE-143', 'OPENSHIFT-2026', NULL, NULL, 56.0, 0.0, '2026-03-23 12:53:58.404139+00', NULL, NULL, '[]', '2026-03-23 12:53:58.404139+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('BLD-BF4A63', 'Diseño OpenShift', '{"skill": "DevOps", "fase": "Análisis y Diseño", "enriched": false}', 'BUILD', 'Media', 'Backlog', 'FTE-015', 'OPENSHIFT-2026', NULL, NULL, 96.0, 0.0, '2026-03-23 12:53:58.408776+00', NULL, NULL, '[]', '2026-03-23 12:53:58.408776+00');
