INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-3172', 'Diagnóstico inicial - Verificar estado gateway SMS', '{"silo": "Middleware", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Servicio SMS Gateway activo", "Puerto SMPP 2775 escuchando", "Conectividad con proveedor verificada", "Logs sin errores críticos", "Configuración SMPP validada", "Health check respondiendo OK"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Gateway SMS", "valor": "No identificado en CMDB", "source": "CMDB"}, {"campo": "Puerto SMS", "valor": "2775 (SMPP default)", "source": "IA"}, {"campo": "Logs SMS", "valor": "/var/log/sms-gateway/", "source": "IA"}, {"campo": "Config SMS", "valor": "/etc/sms-gateway/config.xml", "source": "IA"}, {"campo": "Monitoreo", "valor": "Puerto 8080 (health check)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado del servicio SMS Gateway", "detalle": "Comprobar si el servicio está activo y escuchando", "comandos": ["systemctl status sms-gateway", "netstat -tulpn | grep :2775", "ps aux | grep sms"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar conectividad SMPP", "detalle": "Verificar conexión con proveedor SMS", "comandos": ["telnet proveedor-sms.com 2775", "curl -I http://localhost:8080/health"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar logs recientes", "detalle": "Buscar errores en últimas 2 horas", "comandos": ["tail -f /var/log/sms-gateway/gateway.log", "grep -i error /var/log/sms-gateway/gateway.log | tail -20"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar configuración", "detalle": "Validar parámetros de conexión SMPP", "comandos": ["cat /etc/sms-gateway/config.xml | grep -A5 smpp", "ls -la /etc/sms-gateway/"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'En Progreso', 'FTE-087', NULL, 'INC-20260322-35D1', NULL, 2.0, 0.0, '2026-03-22 19:06:44.858111+00', NULL, NULL, '[]', '2026-03-22 19:06:44.858111+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-595B', 'Verificación gateway y routing', '{"silo": "REDES", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Gateway DMZ operativo", "Rutas hacia Redsys configuradas", "Protocolos routing activos", "NAT funcionando correctamente", "Conectividad end-to-end OK", "Latencia dentro de SLA"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Gateway DMZ", "valor": "172.16.40.1", "source": "CMDB"}, {"campo": "API Gateway", "valor": "172.16.40.12 (api-gw.dmz)", "source": "CMDB"}, {"campo": "VLAN Producción", "valor": "VLAN 40 - DMZ-PUBLICA", "source": "CMDB"}, {"campo": "Router Core", "valor": "192.168.1.1 (default)", "source": "IA"}, {"campo": "Firewall", "valor": "192.168.1.254", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar gateway principal", "detalle": "Comprobar estado y configuración del gateway DMZ", "comandos": ["ping -c 5 172.16.40.1", "arp -a | grep 172.16.40.1"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Revisar tabla de rutas", "detalle": "Analizar rutas estáticas y dinámicas hacia Redsys", "comandos": ["ip route show", "route -n", "netstat -rn"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar routing BGP/OSPF", "detalle": "Comprobar protocolos de routing dinámico", "comandos": ["vtysh -c ''show ip route''", "vtysh -c ''show ip bgp summary''"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Comprobar NAT/PAT", "detalle": "Verificar traducción de direcciones hacia exterior", "comandos": ["iptables -t nat -L -n -v", "conntrack -L | grep 194.224"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Test conectividad end-to-end", "detalle": "Probar conectividad completa desde API Gateway", "comandos": ["curl -I https://sis.redsys.es", "mtr --report-cycles 10 194.224.207.69"], "source_comandos": "IA"}], "skill_requerida": "Redes: IP/Gateway", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Crítica', 'Backlog', 'FTE-090', NULL, 'INC-20260322-17AD', NULL, 0.8, 0.0, '2026-03-22 22:11:48.897832+00', NULL, NULL, '[]', '2026-03-22 22:11:48.897832+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-66BF', 'Análisis trazas de red', '{"silo": "REDES", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Captura de tráfico iniciada", "Tráfico de prueba generado", "Handshake SSL analizado", "Logs de firewall revisados", "Trazas analizadas con Wireshark", "Patrones anómalos identificados"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "API Gateway IP", "valor": "172.16.40.12", "source": "CMDB"}, {"campo": "VLAN DMZ", "valor": "40 - DMZ-PUBLICA", "source": "CMDB"}, {"campo": "Switch Core", "valor": "SW-CORE-01 (192.168.1.10)", "source": "IA"}, {"campo": "Firewall", "valor": "FW-DMZ-01 (172.16.40.254)", "source": "IA"}, {"campo": "Herramienta Captura", "valor": "tcpdump / Wireshark", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Configurar captura de tráfico", "detalle": "Iniciar captura en interfaz DMZ hacia Redsys", "comandos": ["tcpdump -i eth0 -w redsys_trace.pcap host 194.224.207.69", "tcpdump -i any -s 0 port 443 and host 194.224.207.69"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Generar tráfico de prueba", "detalle": "Ejecutar transacciones hacia Redsys para capturar trazas", "comandos": ["curl -v https://sis.redsys.es/sis/realizarPago", "wget --debug --server-response https://sis.redsys.es"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Analizar handshake SSL/TLS", "detalle": "Revisar establecimiento de conexión segura", "comandos": ["openssl s_client -connect sis.redsys.es:443 -showcerts", "nmap --script ssl-enum-ciphers -p 443 sis.redsys.es"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar logs de firewall", "detalle": "Analizar logs de firewall para tráfico Redsys", "comandos": ["grep -i redsys /var/log/iptables.log", "journalctl -u firewalld | grep 194.224"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Análisis con Wireshark", "detalle": "Abrir captura y analizar patrones de tráfico", "comandos": ["wireshark redsys_trace.pcap &", "tshark -r redsys_trace.pcap -Y ''tcp.port==443''"], "source_comandos": "IA"}], "skill_requerida": "Redes: Tracert", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Crítica', 'Backlog', 'FTE-014', NULL, 'INC-20260322-17AD', NULL, 0.5, 0.0, '2026-03-22 22:11:48.901833+00', NULL, NULL, '[]', '2026-03-22 22:11:48.901833+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-E9CF', 'Revisión conexiones activas', '{"silo": "REDES", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Conexiones activas listadas", "Pool de conexiones verificado", "Estados TIME_WAIT revisados", "Nuevas conexiones monitoreadas", "Conexiones dentro de límites"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "API Gateway", "valor": "172.16.40.12 (api-gw.dmz)", "source": "CMDB"}, {"campo": "Puerto API", "valor": "8443 (Kong Enterprise)", "source": "CMDB"}, {"campo": "Conexiones Máx", "valor": "25000 req/sec", "source": "CMDB"}, {"campo": "Redsys Endpoint", "valor": "sis.redsys.es:443", "source": "IA"}, {"campo": "Timeout", "valor": "30 segundos", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Listar conexiones activas", "detalle": "Revisar conexiones TCP establecidas hacia Redsys", "comandos": ["netstat -an | grep 194.224", "ss -tuln | grep :443"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar pool de conexiones", "detalle": "Comprobar estado del pool en API Gateway", "comandos": ["curl -s http://172.16.40.12:8001/status | jq ''.database''", "netstat -an | grep 172.16.40.12 | wc -l"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Revisar conexiones TIME_WAIT", "detalle": "Identificar conexiones en estado de cierre", "comandos": ["netstat -an | grep TIME_WAIT | grep 443", "ss -o state time-wait | grep redsys"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitorear nuevas conexiones", "detalle": "Observar establecimiento de nuevas conexiones", "comandos": ["watch -n 2 ''netstat -an | grep 194.224 | wc -l''", "tcpdump -i any -c 20 ''host 194.224.207.69 and tcp[tcpflags] & tcp-syn != 0''"], "source_comandos": "IA"}], "skill_requerida": "Redes: Netstat", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Backlog', 'FTE-023', NULL, 'INC-20260322-17AD', NULL, 0.5, 0.0, '2026-03-22 22:11:48.907284+00', NULL, NULL, '[]', '2026-03-22 22:11:48.907284+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-71B1', 'Coordinación con área Medios de Pago', '{"silo": "COORDINACION", "tipo": "BUILD", "orden": 6, "enriched": true, "checklist": ["Contacto establecido con Medios de Pago", "Estado actual comunicado", "Timeline compartido", "Pruebas coordinadas", "Canal de comunicación activo"], "area_negocio": "Medios de Pago", "contexto_cmdb": {"items": [{"campo": "Stakeholder Principal", "valor": "Área Medios de Pago", "source": "IA"}, {"campo": "Tipo Incidencia", "valor": "Conectividad Redsys", "source": "IA"}, {"campo": "Criticidad", "valor": "CRITICA - Impacto en pagos", "source": "IA"}, {"campo": "Canal Comunicación", "valor": "Teams / Email / Teléfono", "source": "IA"}, {"campo": "Escalamiento", "valor": "Manager Medios de Pago", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Contacto inicial", "detalle": "Establecer comunicación con responsable de Medios de Pago", "comandos": ["Llamar a extensión 2450 (Medios de Pago)", "Enviar email a mediosdepago@empresa.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Informar estado actual", "detalle": "Comunicar situación y acciones en curso", "comandos": ["Actualizar ticket con estado actual", "Compartir timeline de resolución estimado"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Coordinar pruebas", "detalle": "Planificar pruebas funcionales con el área", "comandos": ["Agendar sesión de pruebas", "Preparar casos de prueba TPV"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Seguimiento continuo", "detalle": "Mantener comunicación durante la resolución", "comandos": ["Enviar updates cada 30 minutos", "Confirmar disponibilidad para pruebas"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": true, "sla_tarea_minutos": 60}', 'RUN', 'Crítica', 'Backlog', 'FTE-050', NULL, 'INC-20260322-17AD', NULL, 0.3, 0.0, '2026-03-22 22:11:48.916951+00', NULL, NULL, '[]', '2026-03-22 22:11:48.916951+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-7C9F', 'Coordinación con área de Comercio Exterior', '{"silo": "NEGOCIO", "tipo": "RUN", "orden": 6, "enriched": true, "checklist": ["Contacto establecido con Comercio Exterior", "Estado de red TPVs verificado", "Reporte de transacciones generado", "Plan de acción definido", "Próximos pasos documentados"], "area_negocio": "Comercio Exterior", "contexto_cmdb": {"items": [{"campo": "Red TPVs", "valor": "TPV-001", "source": "CMDB"}, {"campo": "Gateway TPV", "valor": "10.0.80.20", "source": "CMDB"}, {"campo": "VLAN", "valor": "VLAN 80 - ATM-RED", "source": "CMDB"}, {"campo": "Protocolo", "valor": "ISO 8583", "source": "CMDB"}, {"campo": "Terminales", "valor": "12000 activas", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Contactar responsable Comercio Exterior", "detalle": "Establecer comunicación con el área para coordinar acciones", "comandos": ["outlook.exe /c ipm.note /m comercio.exterior@empresa.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar estado red TPVs", "detalle": "Verificar conectividad de terminales de comercio exterior", "comandos": ["ping -c 4 10.0.80.20", "telnet 10.0.80.20 8583"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Generar reporte de transacciones", "detalle": "Extraer datos de liquidaciones de comercio exterior", "comandos": ["sqlplus liquidacion_user/password@PROD", "SELECT COUNT(*) FROM transacciones WHERE tipo_comercio=''EXTERIOR'' AND fecha=TRUNC(SYSDATE);"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Coordinar plan de acción", "detalle": "Definir pasos a seguir con el área de negocio", "comandos": ["teams.exe --join-meeting comercio-exterior-coordination"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": true, "sla_tarea_minutos": 90}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 0.5, 0.0, '2026-03-24 22:09:45.868151+00', '2026-04-01 18:31:53.999976+00', '2026-04-01 18:31:59.412195+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:54.000016"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.412258"}]', '2026-03-24 22:09:45.868151+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-E573', 'Corrección de datos de liquidación', '{"silo": "BBDD", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Conexión a BD establecida", "Registros erróneos identificados", "Backup de datos realizado", "Correcciones aplicadas exitosamente", "Validación de integridad completada", "Commit de transacciones ejecutado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Liquidaciones", "source": "IA"}, {"campo": "Esquema", "valor": "LIQUIDACION_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Servidor BD", "valor": "srv-db-liquidacion-01", "source": "IA"}, {"campo": "Tablespace", "valor": "LIQUIDACION_DATA", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos", "detalle": "Acceder al esquema de liquidaciones", "comandos": ["sqlplus liquidacion_user/password@srv-db-liquidacion-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Identificar registros erróneos", "detalle": "Localizar datos de liquidación con inconsistencias", "comandos": ["SELECT * FROM liquidaciones WHERE estado=''ERROR'' AND fecha >= TRUNC(SYSDATE-1);", "SELECT liquidacion_id, monto, estado FROM liquidaciones WHERE monto < 0 OR monto IS NULL;"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Realizar backup de datos", "detalle": "Respaldar registros antes de corrección", "comandos": ["CREATE TABLE liquidaciones_backup_$(date +%Y%m%d) AS SELECT * FROM liquidaciones WHERE liquidacion_id IN (lista_ids);"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Ejecutar correcciones", "detalle": "Aplicar las correcciones necesarias en los datos", "comandos": ["UPDATE liquidaciones SET monto = valor_correcto WHERE liquidacion_id = id_especifico;", "UPDATE liquidaciones SET estado = ''PROCESADO'' WHERE estado = ''ERROR'' AND condicion_correccion;"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar correcciones", "detalle": "Verificar que las correcciones se aplicaron correctamente", "comandos": ["SELECT COUNT(*) FROM liquidaciones WHERE estado=''ERROR'';", "SELECT SUM(monto) FROM liquidaciones WHERE fecha = TRUNC(SYSDATE);"], "source_comandos": "IA"}], "skill_requerida": "SQL: Update", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 2.0, 0.0, '2026-03-24 22:09:45.862913+00', '2026-04-01 18:31:54.025453+00', '2026-04-01 18:31:59.431017+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:54.025497"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.431081"}]', '2026-03-24 22:09:45.862913+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260324-C04E', 'Consulta estado de remesas en base de datos', '{"silo": "BBDD", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Conexión a BD de remesas establecida", "Estado general consultado", "Remesas pendientes identificadas", "Reporte detallado generado", "Inconsistencias documentadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Remesas", "source": "IA"}, {"campo": "Esquema", "valor": "REMESAS_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Servidor BD", "valor": "srv-db-remesas-01", "source": "IA"}, {"campo": "Vista principal", "valor": "V_ESTADO_REMESAS", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos de remesas", "detalle": "Acceder al esquema de remesas", "comandos": ["sqlplus remesas_user/password@srv-db-remesas-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Consultar estado general", "detalle": "Revisar estado actual de todas las remesas", "comandos": ["SELECT estado, COUNT(*) FROM remesas GROUP BY estado;", "SELECT * FROM V_ESTADO_REMESAS WHERE fecha >= TRUNC(SYSDATE);"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar remesas pendientes", "detalle": "Localizar remesas en estado pendiente o con errores", "comandos": ["SELECT remesa_id, estado, fecha_creacion, monto FROM remesas WHERE estado IN (''PENDIENTE'', ''ERROR'') ORDER BY fecha_creacion;"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Generar reporte detallado", "detalle": "Crear reporte con estado de remesas por período", "comandos": ["SELECT TO_CHAR(fecha_creacion, ''YYYY-MM-DD'') as fecha, estado, COUNT(*) as cantidad, SUM(monto) as total FROM remesas WHERE fecha_creacion >= TRUNC(SYSDATE-30) GROUP BY TO_CHAR(fecha_creacion, ''YYYY-MM-DD''), estado ORDER BY fecha, estado;"], "source_comandos": "IA"}], "skill_requerida": "SQL: Select Simple", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Alta', 'Completado', NULL, NULL, 'INC-20260324-C657', NULL, 1.0, 0.0, '2026-03-24 22:09:45.853373+00', '2026-04-01 18:31:54.06502+00', '2026-04-01 18:31:59.466968+00', '[{"columna": "Completado", "timestamp": "2026-04-01T18:31:54.065066"}, {"columna": "Completado", "timestamp": "2026-04-01T18:31:59.467024"}]', '2026-03-24 22:09:45.853373+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260325-E9AC', 'Diagnóstico inicial - Análisis rendimiento Citrix', '{"silo": "VIRTUALIZACION", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Acceso a Citrix Director verificado", "Estado del farm documentado", "Número de sesiones activas registrado", "Recursos de hosts monitoreados", "Logs de rendimiento revisados", "Baseline de performance establecido"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Hostname", "valor": "vdi-farm.pro", "source": "CMDB"}, {"campo": "VLAN", "valor": "VLAN 20 - SERVIDORES-PRO", "source": "CMDB"}, {"campo": "Hosts", "valor": "8 hosts", "source": "CMDB"}, {"campo": "Sesiones concurrentes", "valor": "300", "source": "CMDB"}, {"campo": "GPU", "valor": "NVIDIA T4", "source": "CMDB"}, {"campo": "Puerto Citrix", "valor": "1494, 2598 (ICA/HDX)", "source": "IA"}, {"campo": "Consola Studio", "valor": "https://10.0.20.50/Director", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceso a Citrix Director", "detalle": "Conectar a la consola de administración para análisis inicial", "comandos": ["https://10.0.20.50/Director", "Credenciales: dominio\\usuario_admin"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar estado general del farm", "detalle": "Revisar dashboard principal y alertas activas", "comandos": ["Get-BrokerSite | fl", "Get-BrokerController | ft Name,State,ActiveSiteServices"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Análisis de sesiones activas", "detalle": "Revisar número de sesiones y distribución por host", "comandos": ["Get-BrokerSession | Group-Object MachineName | ft Count,Name", "Get-BrokerSession | Where {$_.SessionState -eq ''Active''} | Measure-Object"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitoreo de recursos por host", "detalle": "Verificar CPU, memoria y GPU en cada host VDI", "comandos": ["Get-BrokerMachine | ft MachineName,LoadIndex,InMaintenanceMode", "Get-Counter ''\\Processor(_Total)\\% Processor Time'' -ComputerName vdi-host*"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Revisar logs de rendimiento", "detalle": "Analizar eventos recientes relacionados con performance", "comandos": ["Get-WinEvent -LogName ''Citrix Desktop Service'' -MaxEvents 50", "Get-WinEvent -FilterHashtable @{LogName=''System'';Level=2,3} -MaxEvents 20"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Baja', 'En Progreso', 'FTE-091', NULL, 'INC-20260325-CE97', NULL, 2.0, 0.0, '2026-03-25 12:46:54.047471+00', NULL, NULL, '[]', '2026-03-25 12:46:54.047471+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260325-A97E', 'Verificar estado sesiones y recursos Citrix', '{"silo": "VIRTUALIZACION", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Estado de sesiones documentado", "Recursos por sesión verificados", "Conectividad ICA/HDX comprobada", "Estado de VMs registrado", "Dependencias AD y SAN verificadas", "Informe de estado generado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Sesiones máximas", "valor": "300 concurrentes", "source": "CMDB"}, {"campo": "Hosts disponibles", "valor": "8 hosts", "source": "CMDB"}, {"campo": "Dependencia AD", "valor": "SRV-PRO-005 (DC1)", "source": "CMDB"}, {"campo": "Dependencia SAN", "valor": "STO-PRO-001 (NetApp)", "source": "CMDB"}, {"campo": "Puerto ICA", "valor": "1494", "source": "IA"}, {"campo": "Puerto HDX", "valor": "2598", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado de sesiones activas", "detalle": "Revisar todas las sesiones conectadas y su estado", "comandos": ["Get-BrokerSession | ft UserName,MachineName,SessionState,StartTime", "Get-BrokerSession | Group-Object SessionState | ft Count,Name"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar recursos por sesión", "detalle": "Verificar consumo de CPU y memoria por sesión activa", "comandos": ["Get-BrokerSession | Where {$_.SessionState -eq ''Active''} | ft UserName,@{n=''LoadIndex'';e={(Get-BrokerMachine -MachineName $_.MachineName).LoadIndex}}", "Get-Process -Name ''winlogon'' -ComputerName vdi-host* | ft ProcessName,CPU,WorkingSet,MachineName"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar conectividad de red", "detalle": "Comprobar latencia y conectividad ICA/HDX", "comandos": ["Test-NetConnection -ComputerName 10.0.20.50 -Port 1494", "Test-NetConnection -ComputerName 10.0.20.50 -Port 2598", "Get-BrokerSession | Where {$_.ClientName -ne $null} | ft UserName,ClientName,ClientAddress"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Revisar estado de máquinas virtuales", "detalle": "Verificar que todos los hosts VDI estén operativos", "comandos": ["Get-BrokerMachine | ft MachineName,RegistrationState,PowerState,InMaintenanceMode", "Get-BrokerMachine | Where {$_.RegistrationState -ne ''Registered''} | fl"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar dependencias críticas", "detalle": "Comprobar conectividad con AD y SAN", "comandos": ["Test-NetConnection -ComputerName SRV-PRO-005 -Port 389", "nltest /dsgetdc:dominio.local", "Get-BrokerServiceStatus | ft ServiceName,ServiceState"], "source_comandos": "CMDB"}], "skill_requerida": "AD: Reset Password", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Baja', 'Backlog', 'FTE-091', NULL, 'INC-20260325-CE97', NULL, 3.0, 0.0, '2026-03-25 12:46:54.071646+00', NULL, NULL, '[]', '2026-03-25 12:46:54.071646+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260325-D853', 'Revisar configuración perfil usuario afectado', '{"silo": "VIRTUALIZACION", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Usuario afectado identificado", "Configuración de perfil revisada", "Permisos NTFS verificados", "GPOs aplicadas documentadas", "Logs de perfil analizados", "Problema de perfil diagnosticado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "AD Controller", "valor": "SRV-PRO-005", "source": "CMDB"}, {"campo": "Ruta perfiles", "valor": "\\\\STO-PRO-001\\profiles$", "source": "IA"}, {"campo": "Ruta GPO", "valor": "\\\\SRV-PRO-005\\SYSVOL", "source": "IA"}, {"campo": "Puerto LDAP", "valor": "389", "source": "IA"}, {"campo": "Puerto SMB", "valor": "445", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Identificar usuario afectado", "detalle": "Localizar el usuario con problemas de perfil en Citrix", "comandos": ["Get-BrokerSession | Where {$_.UserName -like ''*usuario_afectado*''} | fl", "Get-BrokerUser -Name ''dominio\\usuario_afectado'' | fl"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar configuración de perfil", "detalle": "Verificar ruta y estado del perfil de usuario", "comandos": ["Get-ADUser usuario_afectado -Properties ProfilePath,HomeDirectory,ScriptPath", "Test-Path ''\\\\STO-PRO-001\\profiles$\\usuario_afectado''", "Get-ChildItem ''\\\\STO-PRO-001\\profiles$\\usuario_afectado'' -Force"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Verificar permisos en perfil", "detalle": "Comprobar permisos NTFS en la carpeta del perfil", "comandos": ["Get-Acl ''\\\\STO-PRO-001\\profiles$\\usuario_afectado'' | fl", "icacls ''\\\\STO-PRO-001\\profiles$\\usuario_afectado'' /T /C"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Revisar políticas de grupo aplicadas", "detalle": "Verificar GPOs que afectan al usuario", "comandos": ["gpresult /user usuario_afectado /r", "Get-GPResultantSetOfPolicy -User ''dominio\\usuario_afectado'' -Computer vdi-host01"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar logs de perfil", "detalle": "Revisar eventos relacionados con carga de perfil", "comandos": ["Get-WinEvent -FilterHashtable @{LogName=''Application'';ProviderName=''User Profile Service''} | Where {$_.Message -like ''*usuario_afectado*''}", "Get-WinEvent -FilterHashtable @{LogName=''System'';ID=1530,1533,1534} -MaxEvents 10"], "source_comandos": "IA"}], "skill_requerida": "AD: Deshabilitar Usuario", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Baja', 'Backlog', 'FTE-115', NULL, 'INC-20260325-CE97', NULL, 2.0, 0.0, '2026-03-25 12:46:54.075613+00', NULL, NULL, '[]', '2026-03-25 12:46:54.075613+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260325-F97C', 'Optimización y ajustes configuración Citrix', '{"silo": "VIRTUALIZACION", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Backup de configuración realizado", "Parámetros HDX optimizados", "Configuración GPU ajustada", "Políticas de sesión configuradas", "Servicios reiniciados correctamente", "Cambios verificados y documentados"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "GPU", "valor": "NVIDIA T4", "source": "CMDB"}, {"campo": "Hosts", "valor": "8 hosts VDI", "source": "CMDB"}, {"campo": "Archivo config", "valor": "C:\\Program Files\\Citrix\\Virtual Delivery Agent\\BrokerAgent.exe.config", "source": "IA"}, {"campo": "Registro HDX", "valor": "HKLM\\SOFTWARE\\Citrix\\HDX3D", "source": "IA"}, {"campo": "Puerto Studio", "valor": "80/443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Backup configuración actual", "detalle": "Respaldar configuración antes de realizar cambios", "comandos": ["Export-BrokerSite -FilePath C:\\Backup\\CitrixSite_$(Get-Date -f yyyyMMdd).zip", "reg export HKLM\\SOFTWARE\\Citrix C:\\Backup\\CitrixRegistry_$(Get-Date -f yyyyMMdd).reg"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Optimizar configuración HDX", "detalle": "Ajustar parámetros de HDX para mejor rendimiento", "comandos": ["Set-BrokerSite -ColorDepth TwentyFourBit", "Set-BrokerAccessPolicyRule -Name ''Default'' -HDXSslEnabled $true", "New-ItemProperty -Path ''HKLM:\\SOFTWARE\\Citrix\\HDX3D'' -Name ''EnableGPUSharing'' -Value 1 -PropertyType DWORD"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Configurar optimizaciones de GPU", "detalle": "Ajustar configuración para aprovechar NVIDIA T4", "comandos": ["Set-ItemProperty -Path ''HKLM:\\SOFTWARE\\Citrix\\HDX3D'' -Name ''MaxSharedGpuUsers'' -Value 4", "Set-ItemProperty -Path ''HKLM:\\SOFTWARE\\Citrix\\HDX3D'' -Name ''EnableHardwareEncoding'' -Value 1", "nvidia-smi -q -d UTILIZATION"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Ajustar políticas de sesión", "detalle": "Optimizar timeouts y límites de sesión", "comandos": ["Set-BrokerAccessPolicyRule -Name ''Default'' -SessionSharingEnabled $false", "Set-BrokerPowerTimeScheme -Name ''Weekdays'' -PeakBufferSizePercent 20", "Set-BrokerEntitlementPolicyRule -Name ''Default'' -MaxTotalInstances 300"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Aplicar configuración y reiniciar servicios", "detalle": "Aplicar cambios y reiniciar servicios necesarios", "comandos": ["Restart-Service ''Citrix Desktop Service''", "Restart-Service ''Citrix Broker Service''", "Get-BrokerController | Test-BrokerDBConnection"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Verificar aplicación de cambios", "detalle": "Comprobar que las optimizaciones se aplicaron correctamente", "comandos": ["Get-BrokerSite | fl ColorDepth,HDXSslEnabled", "Get-ItemProperty -Path ''HKLM:\\SOFTWARE\\Citrix\\HDX3D'' | fl", "Get-BrokerAccessPolicyRule | fl Name,SessionSharingEnabled"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Priorización", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Baja', 'Backlog', 'FTE-115', NULL, 'INC-20260325-CE97', NULL, 4.0, 0.0, '2026-03-25 12:46:54.078938+00', NULL, NULL, '[]', '2026-03-25 12:46:54.078938+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260325-5D18', 'Validación y cierre - Verificar mejora rendimiento', '{"silo": "VIRTUALIZACION", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Test de rendimiento ejecutado", "Métricas comparadas con baseline", "Tiempo de login verificado", "Utilización GPU validada", "Reporte de mejoras generado", "Incidencia cerrada con evidencias", "Documentación actualizada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "PT-VDI-001 - VDI Citrix Farm", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.20.50", "source": "CMDB"}, {"campo": "Sesiones objetivo", "valor": "300 concurrentes", "source": "CMDB"}, {"campo": "GPU", "valor": "NVIDIA T4", "source": "CMDB"}, {"campo": "Hosts", "valor": "8 hosts", "source": "CMDB"}, {"campo": "Métricas baseline", "valor": "Datos de KT-20260325-E9AC", "source": "IA"}, {"campo": "Herramienta monitoreo", "valor": "Citrix Director + Performance Monitor", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Ejecutar test de rendimiento post-optimización", "detalle": "Realizar pruebas de carga para medir mejoras", "comandos": ["Get-BrokerSession | Measure-Object", "Get-Counter ''\\Citrix HDX MediaStream for Flash - Redirected\\*'' -MaxSamples 10", "Get-Counter ''\\GPU Engine(*)\\Utilization Percentage'' -MaxSamples 10"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Comparar métricas con baseline", "detalle": "Contrastar rendimiento actual vs baseline inicial", "comandos": ["$baseline = Import-Csv C:\\Temp\\baseline_performance.csv", "$current = Get-BrokerMachine | Measure-Object LoadIndex -Average", "Compare-Object $baseline.LoadIndex $current.Average"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar tiempo de login mejorado", "detalle": "Medir tiempo de inicio de sesión promedio", "comandos": ["Get-WinEvent -FilterHashtable @{LogName=''Microsoft-Windows-User Profile Service/Operational'';ID=1} | Select TimeCreated,Message | Sort TimeCreated -Descending | Select -First 10", "Measure-Command { Test-BrokerConnection -AdminAddress 10.0.20.50 }"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Validar utilización de GPU optimizada", "detalle": "Confirmar mejor aprovechamiento de NVIDIA T4", "comandos": ["nvidia-smi --query-gpu=utilization.gpu,utilization.memory --format=csv", "Get-Counter ''\\GPU Process Memory(*)\\Shared Usage'' -MaxSamples 5", "Get-ItemProperty -Path ''HKLM:\\SOFTWARE\\Citrix\\HDX3D'' | fl *GPU*"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Documentar mejoras obtenidas", "detalle": "Generar reporte de mejoras de rendimiento", "comandos": ["$report = @{}", "$report.FechaTest = Get-Date", "$report.SesionesActivas = (Get-BrokerSession | Measure-Object).Count", "$report.LoadIndexPromedio = (Get-BrokerMachine | Measure-Object LoadIndex -Average).Average", "$report | Export-Csv C:\\Reports\\Performance_Improvement_$(Get-Date -f yyyyMMdd).csv"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Cerrar incidencia con evidencias", "detalle": "Actualizar ticket con resultados y cerrar", "comandos": ["# Adjuntar reporte de mejoras al ticket", "# Documentar configuraciones aplicadas", "# Marcar incidencia como resuelta"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Baja', 'Backlog', 'FTE-013', NULL, 'INC-20260325-CE97', NULL, 1.0, 0.0, '2026-03-25 12:46:54.083124+00', NULL, NULL, '[]', '2026-03-25 12:46:54.083124+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260326-40C5', 'Diagnóstico inicial de conectividad red ATM', '{"silo": "REDES", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Ping exitoso a controllers 10.0.80.10 y 10.0.80.11", "Gateway 10.0.80.1 responde correctamente", "Puertos 7777 accesibles en controllers", "Latencia < 50ms hacia controllers", "Sin pérdida de paquetes en pruebas", "Hallazgos documentados en ticket"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Red ATM Norte", "valor": "ATM-NET-001 (45 cajeros)", "source": "CMDB"}, {"campo": "Controller Norte", "valor": "10.0.80.10 (atm-ctrl-norte.atm)", "source": "CMDB"}, {"campo": "Controller Sur", "valor": "10.0.80.11 (atm-ctrl-sur.atm)", "source": "CMDB"}, {"campo": "VLAN ATM", "valor": "VLAN 80 - ATM-RED (10.0.80.0/24)", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.80.1", "source": "CMDB"}, {"campo": "Puerto ATM", "valor": "7777 (protocolo NDC+)", "source": "IA"}, {"campo": "Timeout conexión", "valor": "30 segundos", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica a controllers", "detalle": "Probar conectividad ICMP a los controllers principales", "comandos": ["ping -c 4 10.0.80.10", "ping -c 4 10.0.80.11", "ping -c 4 10.0.80.1"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar estado de puertos ATM", "detalle": "Comprobar si los puertos de comunicación ATM están abiertos", "comandos": ["telnet 10.0.80.10 7777", "telnet 10.0.80.11 7777", "nmap -p 7777 10.0.80.10-11"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar tabla ARP y conectividad L2", "detalle": "Revisar resolución ARP de los controllers", "comandos": ["arp -a | grep ''10.0.80''", "arping -c 3 10.0.80.10", "arping -c 3 10.0.80.11"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Análisis de latencia y pérdida de paquetes", "detalle": "Medir calidad de conexión hacia la red ATM", "comandos": ["ping -c 20 -i 0.5 10.0.80.10", "mtr -c 10 10.0.80.10", "hping3 -c 10 -S -p 7777 10.0.80.10"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar hallazgos iniciales", "detalle": "Registrar estado de conectividad y preparar para análisis avanzado", "comandos": ["echo ''Diagnóstico inicial completado'' >> /tmp/atm_diag.log"], "source_comandos": "IA"}], "skill_requerida": "Redes: Ping", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Crítica', 'En Progreso', 'FTE-014', NULL, 'INC-20260326-3E15', NULL, 0.3, 0.0, '2026-03-26 11:21:54.612197+00', NULL, NULL, '[]', '2026-03-26 11:21:54.612197+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260326-BCF4', 'Análisis de gateway y routing ATM', '{"silo": "REDES", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Tabla de routing contiene ruta a 10.0.80.0/24", "VLAN 80 activa y operativa", "VRRP grupo 80 en estado MASTER", "Tráfico ATM fluyendo normalmente", "Controllers pueden alcanzar internet", "Sin loops de routing detectados", "Configuración documentada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Gateway ATM", "valor": "10.0.80.1", "source": "CMDB"}, {"campo": "Subred ATM", "valor": "10.0.80.0/24", "source": "CMDB"}, {"campo": "VLAN", "valor": "80 - ATM-RED", "source": "CMDB"}, {"campo": "Controllers", "valor": "10.0.80.10, 10.0.80.11", "source": "CMDB"}, {"campo": "Protocolo routing", "valor": "OSPF área 0.0.0.80", "source": "IA"}, {"campo": "VRRP", "valor": "Grupo 80, prioridad 100", "source": "IA"}, {"campo": "Switch core", "valor": "192.168.1.1 (SNMP community: atm_ro)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar tabla de routing en gateway", "detalle": "Acceder al gateway y revisar rutas hacia red ATM", "comandos": ["ssh admin@10.0.80.1", "show ip route", "show ip route 10.0.80.0", "show ip ospf neighbor"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Analizar configuración VLAN 80", "detalle": "Verificar configuración de VLAN ATM en switches", "comandos": ["ssh admin@192.168.1.1", "show vlan 80", "show interfaces vlan 80", "show spanning-tree vlan 80"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar redundancia VRRP", "detalle": "Comprobar estado de alta disponibilidad del gateway", "comandos": ["show vrrp brief", "show vrrp group 80", "show ip arp | include 10.0.80"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Análisis de tráfico ATM", "detalle": "Revisar estadísticas de tráfico en interfaces ATM", "comandos": ["show interfaces statistics", "show ip traffic", "monitor traffic interface vlan80 duration 60"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Pruebas de routing desde controllers", "detalle": "Verificar conectividad desde perspectiva de controllers", "comandos": ["ssh root@10.0.80.10", "route -n", "traceroute 8.8.8.8", "netstat -rn"], "source_comandos": "CMDB"}], "skill_requerida": "Redes: IP/Gateway", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Crítica', 'Backlog', 'FTE-107', NULL, 'INC-20260326-3E15', NULL, 0.4, 0.0, '2026-03-26 11:21:54.623427+00', NULL, NULL, '[]', '2026-03-26 11:21:54.623427+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260326-5F6C', 'Traceroute y análisis de ruta de red', '{"silo": "REDES", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Traceroute completado desde ambos controllers", "Rutas a servidores transaccionales mapeadas", "Latencias por hop documentadas", "Pérdidas de paquetes identificadas", "Cuellos de botella en la ruta detectados", "Reporte de rutas generado", "Hallazgos escalados si es necesario"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Origen", "valor": "Controllers ATM (10.0.80.10, 10.0.80.11)", "source": "CMDB"}, {"campo": "Destinos críticos", "valor": "Datacenter principal, Procesador transaccional", "source": "IA"}, {"campo": "Gateway ATM", "valor": "10.0.80.1", "source": "CMDB"}, {"campo": "DNS primario", "valor": "8.8.8.8", "source": "IA"}, {"campo": "Servidor transaccional", "valor": "172.16.10.50", "source": "IA"}, {"campo": "Servidor autorizador", "valor": "172.16.10.51", "source": "IA"}, {"campo": "Herramientas", "valor": "traceroute, mtr, tcptraceroute", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Traceroute desde controllers a destinos críticos", "detalle": "Ejecutar trazas de ruta desde cada controller ATM", "comandos": ["ssh root@10.0.80.10", "traceroute -n 172.16.10.50", "traceroute -n 172.16.10.51", "traceroute -n 8.8.8.8"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Análisis MTR para detectar pérdidas", "detalle": "Usar MTR para análisis continuo de la ruta", "comandos": ["mtr -c 20 -r 172.16.10.50", "mtr -c 20 -r 172.16.10.51", "mtr -c 20 -r 10.0.80.1"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Traceroute TCP a puertos específicos", "detalle": "Verificar ruta a nivel de aplicación", "comandos": ["tcptraceroute 172.16.10.50 443", "tcptraceroute 172.16.10.51 8080", "hping3 -T -p 443 -c 5 172.16.10.50"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Análisis de latencia por salto", "detalle": "Medir latencia en cada hop de la ruta", "comandos": ["for i in {1..10}; do ping -c 1 -t $i 172.16.10.50; done", "traceroute -q 1 -w 2 172.16.10.50"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Documentar rutas y anomalías", "detalle": "Generar reporte de análisis de rutas", "comandos": ["echo ''=== REPORTE TRACEROUTE ATM ==='' > /tmp/traceroute_report.txt", "date >> /tmp/traceroute_report.txt"], "source_comandos": "IA"}], "skill_requerida": "Redes: Tracert", "requiere_negocio": false, "sla_tarea_minutos": 75}', 'RUN', 'Crítica', 'Backlog', 'FTE-077', NULL, 'INC-20260326-3E15', NULL, 0.3, 0.0, '2026-03-26 11:21:54.627521+00', NULL, NULL, '[]', '2026-03-26 11:21:54.627521+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260326-F1C0', 'Diagnóstico hardware infraestructura ATM', '{"silo": "INFRAESTRUCTURA", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Estado IPMI/iDRAC verificado", "Logs de hardware revisados", "Discos duros sin errores SMART", "Memoria RAM sin errores", "Temperaturas dentro de rango normal", "Interfaces de red operativas", "Reporte de hardware generado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Controllers ATM", "valor": "atm-ctrl-norte.atm, atm-ctrl-sur.atm", "source": "CMDB"}, {"campo": "IPs Controllers", "valor": "10.0.80.10, 10.0.80.11", "source": "CMDB"}, {"campo": "Fabricantes", "valor": "NCR (Norte), Diebold (Sur)", "source": "CMDB"}, {"campo": "Modelos", "valor": "SelfServ 80, DN Series 200", "source": "CMDB"}, {"campo": "IPMI/iDRAC", "valor": "10.0.81.10, 10.0.81.11", "source": "IA"}, {"campo": "SNMP Community", "valor": "atm_monitor", "source": "IA"}, {"campo": "Logs hardware", "valor": "/var/log/hardware.log", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado de hardware vía IPMI", "detalle": "Acceder a controladores de gestión para revisar hardware", "comandos": ["ipmitool -I lanplus -H 10.0.81.10 -U admin -P password chassis status", "ipmitool -I lanplus -H 10.0.81.11 -U admin -P password sensor list"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Revisar logs de hardware en controllers", "detalle": "Analizar logs del sistema para errores de hardware", "comandos": ["ssh root@10.0.80.10", "dmesg | grep -i error", "journalctl -p err -since ''1 hour ago''", "cat /var/log/messages | grep -i hardware"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Verificar estado de discos y memoria", "detalle": "Comprobar salud de almacenamiento y RAM", "comandos": ["df -h", "free -h", "smartctl -a /dev/sda", "memtester 100M 1"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Monitoreo de temperatura y ventiladores", "detalle": "Revisar sensores térmicos y sistema de refrigeración", "comandos": ["sensors", "ipmitool sensor list | grep -i temp", "ipmitool sensor list | grep -i fan"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar conectividad de red física", "detalle": "Comprobar estado de interfaces de red", "comandos": ["ethtool eth0", "ip link show", "cat /proc/net/bonding/bond0", "mii-tool -v"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte de diagnóstico hardware", "detalle": "Documentar hallazgos y estado general del hardware", "comandos": ["dmidecode -t system > /tmp/hw_report.txt", "lshw -short >> /tmp/hw_report.txt"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Diagnóstico Fuente", "requiere_negocio": false, "sla_tarea_minutos": 120}', 'RUN', 'Crítica', 'Backlog', 'FTE-086', NULL, 'INC-20260326-3E15', NULL, 0.4, 0.0, '2026-03-26 11:21:54.636531+00', NULL, NULL, '[]', '2026-03-26 11:21:54.636531+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260322-056F', 'Validación y cierre', '{"silo": "Hardware", "tipo": "RUN", "orden": 6, "enriched": true, "checklist": ["Transacción de prueba exitosa", "Comunicación con banco verificada", "Impresión de voucher funcional", "Conformidad del comercio obtenida", "Ticket cerrado correctamente"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Tipo dispositivo", "valor": "Datáfono POS", "source": "IA"}, {"campo": "Protocolo comunicación", "valor": "TCP/IP, GSM/GPRS", "source": "IA"}, {"campo": "Puerto estándar", "valor": "443 (HTTPS)", "source": "IA"}, {"campo": "Logs sistema", "valor": "/var/log/pos/ o memoria interna", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar resolución completa", "detalle": "Confirmar que todas las tareas previas están completadas y funcionando", "comandos": ["Revisar historial de tickets relacionados", "Verificar estado en sistema de gestión"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Prueba transaccional final", "detalle": "Realizar transacción de prueba completa", "comandos": ["Ejecutar venta de prueba por $1.00", "Verificar respuesta del banco", "Confirmar impresión de voucher"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Validación con comercio", "detalle": "Confirmar satisfacción del usuario final", "comandos": ["Solicitar firma de conformidad", "Documentar resolución en ticket"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Cierre administrativo", "detalle": "Actualizar sistemas y cerrar caso", "comandos": ["Actualizar CMDB si aplica", "Cerrar ticket con código de resolución", "Enviar notificación de cierre"], "source_comandos": "IA"}], "skill_requerida": "Ticket: Registro Incidencia", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Media', 'Completado', 'FTE-028', NULL, 'INC-20260322-4602', NULL, 1.0, 0.0, '2026-03-22 17:07:40.298796+00', '2026-04-01 19:19:42.620879+00', '2026-04-01 19:19:44.986081+00', '[{"columna": "Testing", "timestamp": "2026-04-01T19:19:42.620901"}, {"columna": "En Progreso", "timestamp": "2026-04-01T19:19:43.980205"}, {"columna": "Completado", "timestamp": "2026-04-01T19:19:44.986179"}]', '2026-03-22 17:07:40.298796+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-0766', 'Análisis logs hub mensajería SWIFT', '{"silo": "Unix", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Acceso RDP al servidor exitoso", "Logs SWIFT localizados y legibles", "Event Viewer revisado", "Errores de conexión identificados", "Timestamps de fallos documentados"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-PRO-003 (Windows Server 2022)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "SWIFT Version", "valor": "7.4", "source": "CMDB"}, {"campo": "Logs SWIFT", "valor": "C:\\SWIFT\\Logs\\", "source": "IA"}, {"campo": "Event Logs", "valor": "Windows Event Viewer", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceso al servidor SWIFT", "detalle": "Conectar por RDP al servidor", "comandos": ["mstsc /v:10.0.90.2"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Revisar logs SWIFT Alliance", "detalle": "Analizar logs de mensajería SWIFT", "comandos": ["dir C:\\SWIFT\\Logs\\*.log", "type C:\\SWIFT\\Logs\\alliance.log | findstr ERROR"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar Event Viewer", "detalle": "Revisar eventos del sistema", "comandos": ["eventvwr.msc", "Get-EventLog -LogName Application -Source SWIFT*"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar conectividad en logs", "detalle": "Buscar errores de conexión", "comandos": ["findstr /i \"connection\" C:\\SWIFT\\Logs\\*.log", "findstr /i \"timeout\" C:\\SWIFT\\Logs\\*.log"], "source_comandos": "IA"}], "skill_requerida": "Backend: Logging errores", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Análisis', NULL, NULL, 'INC-20260401-6F68', NULL, 0.5, 0.0, '2026-04-01 10:33:31.60098+00', NULL, NULL, '[{"columna": "Análisis", "timestamp": "2026-04-01T18:10:25.583516"}]', '2026-04-01 10:33:31.60098+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260320-023', 'Despliegue switches core fase 2 — Red BCC', NULL, 'BUILD', 'Alta', 'En Progreso', 'FTE-014', 'PRJ0034', NULL, NULL, 20.0, 12.0, '2026-03-12 05:13:00.493591+00', '2026-03-13 09:13:00.493591+00', NULL, '[{"columna": "Backlog", "timestamp": "2026-03-12T05:13:00.493591"}, {"columna": "En Progreso", "timestamp": "2026-03-13T09:13:00.493591"}, {"estado": "pte_tercero", "columna": "Bloqueado", "timestamp": "2026-04-07T10:15:31.582023"}, {"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T10:15:31.770839"}, {"estado": "pte_tercero", "columna": "Bloqueado", "timestamp": "2026-04-07T10:24:12.712997"}, {"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T10:24:12.805133"}]', '2026-03-20 08:13:01.383178+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-E6AD', 'Diagnóstico inicial - Verificar conectividad SWIFT', '{"silo": "Redes", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Ping al servidor SWIFT exitoso", "Gateway responde correctamente", "Puertos 9443 y 8443 accesibles", "Resolución DNS swift.com OK", "Conectividad externa confirmada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "SRV-PRO-003 (swift-gw.swift)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "VLAN", "valor": "VLAN 90 - SWIFT-CORE", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "Puerto SWIFT", "valor": "9443 (HTTPS), 8443 (Admin)", "source": "IA"}, {"campo": "Hub SWIFT", "valor": "swift.com (IP externa)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Ping al servidor SWIFT y gateway", "comandos": ["ping 10.0.90.2 -c 4", "ping 10.0.90.1 -c 4"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar puertos SWIFT", "detalle": "Comprobar puertos de comunicación SWIFT", "comandos": ["telnet 10.0.90.2 9443", "telnet 10.0.90.2 8443"], "source_comandos": "CMDB+IA"}, {"paso": 3, "titulo": "Test conectividad externa SWIFT", "detalle": "Verificar alcance al hub SWIFT", "comandos": ["nslookup swift.com", "ping swift.com -c 4"], "source_comandos": "IA"}], "skill_requerida": "Redes: Ping", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Crítica', 'En Progreso', NULL, NULL, 'INC-20260401-6F68', NULL, 0.5, 0.0, '2026-04-01 10:33:31.588756+00', NULL, NULL, '[]', '2026-04-01 10:33:31.588756+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-4527', 'Verificar procesos SWIFT en servidores', '{"silo": "Unix", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Servicios SWIFT identificados", "Estado de servicios verificado", "Procesos SWIFT en ejecución", "Uso de recursos normal", "Performance monitoreada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-PRO-003 (Windows Server 2022)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "SWIFT Gateway", "valor": "APP-PRO-007 v7.4", "source": "CMDB"}, {"campo": "Servicios SWIFT", "valor": "SWIFT Alliance Gateway Service", "source": "IA"}, {"campo": "Procesos", "valor": "swift.exe, alliance.exe", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar servicios SWIFT", "detalle": "Comprobar estado de servicios Windows", "comandos": ["Get-Service | Where-Object {$_.Name -like ''*SWIFT*''}", "sc query \"SWIFT Alliance Gateway\""], "source_comandos": "IA"}, {"paso": 2, "titulo": "Verificar procesos activos", "detalle": "Listar procesos SWIFT en ejecución", "comandos": ["tasklist | findstr swift", "tasklist | findstr alliance", "Get-Process | Where-Object {$_.ProcessName -like ''*swift*''}"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar uso de recursos", "detalle": "Comprobar CPU y memoria de procesos SWIFT", "comandos": ["Get-Process swift* | Select-Object Name,CPU,WorkingSet", "perfmon /res"], "source_comandos": "IA"}], "skill_requerida": "Linux: Procesos", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260401-6F68', NULL, 0.3, 0.0, '2026-04-01 10:33:31.606406+00', NULL, NULL, '[]', '2026-04-01 10:33:31.606406+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-63F7', 'Traceroute hacia hub SWIFT', '{"silo": "Redes", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Traceroute completado exitosamente", "Todos los saltos responden", "Latencia dentro de parámetros", "Puertos SWIFT accesibles", "Resolución DNS correcta"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Origen", "valor": "10.0.90.2 (SRV-PRO-003)", "source": "CMDB"}, {"campo": "Gateway local", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "Hub SWIFT", "valor": "swift.com", "source": "IA"}, {"campo": "Puertos SWIFT", "valor": "9443 (HTTPS), 636 (LDAPS)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Traceroute básico a SWIFT", "detalle": "Trazar ruta hacia el hub SWIFT", "comandos": ["tracert swift.com", "tracert -h 30 swift.com"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Traceroute con puertos específicos", "detalle": "Verificar ruta hacia puertos SWIFT", "comandos": ["telnet swift.com 9443", "Test-NetConnection swift.com -Port 9443 -TraceRoute"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Análisis de latencia", "detalle": "Medir tiempos de respuesta por salto", "comandos": ["pathping swift.com", "ping swift.com -n 10"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar DNS y resolución", "detalle": "Comprobar resolución de nombres", "comandos": ["nslookup swift.com", "nslookup swift.com 8.8.8.8"], "source_comandos": "IA"}], "skill_requerida": "Redes: Tracert", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260401-6F68', NULL, 0.2, 0.0, '2026-04-01 10:33:31.61434+00', NULL, NULL, '[]', '2026-04-01 10:33:31.61434+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-6677', 'Diagnóstico red - Gateway y rutas', '{"silo": "Redes", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Tabla de rutas revisada", "Gateway responde correctamente", "VLAN 90 configurada", "ARP del gateway resuelto", "Rutas externas funcionales"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "VLAN", "valor": "90 - SWIFT-CORE", "source": "CMDB"}, {"campo": "Subred", "valor": "10.0.90.0/28", "source": "CMDB"}, {"campo": "Switch Core", "valor": "192.168.1.1 (estimado)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar tabla de rutas", "detalle": "Revisar rutas hacia SWIFT y externa", "comandos": ["route print", "netstat -rn"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Diagnosticar gateway", "detalle": "Verificar conectividad y configuración del gateway", "comandos": ["ping 10.0.90.1 -t", "arp -a | findstr 10.0.90.1"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Verificar VLAN y switching", "detalle": "Comprobar configuración de red", "comandos": ["ipconfig /all", "netsh interface ip show config"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Test rutas externas", "detalle": "Verificar enrutamiento hacia Internet", "comandos": ["tracert 8.8.8.8", "tracert swift.com"], "source_comandos": "IA"}], "skill_requerida": "Redes: IP/Gateway", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Análisis', NULL, NULL, 'INC-20260401-6F68', NULL, 0.4, 0.0, '2026-04-01 10:33:31.610127+00', NULL, NULL, '[{"columna": "Análisis", "timestamp": "2026-04-01T18:10:24.274832"}]', '2026-04-01 10:33:31.610127+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260321-31FF', 'Restaurar servicio y configurar respaldo en cloud', '{"tipo": "RUN", "silo": "Infraestructura", "sla_tarea_minutos": 180, "contexto_cmdb": {"items": [{"campo": "Servicio", "valor": "Backend APIs", "source": "IA"}, {"campo": "Cloud Provider", "valor": "AWS/Azure (por determinar)", "source": "IA"}, {"campo": "Backup Location", "valor": "/backup o S3 bucket", "source": "IA"}, {"campo": "Puerto API", "valor": "8080/443", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar estado actual del servicio", "detalle": "Comprobar si el servicio está funcionando", "comandos": ["systemctl status api-backend", "curl -I http://localhost:8080/health", "ps aux | grep java"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Restaurar servicio si está caído", "detalle": "Reiniciar servicios necesarios", "comandos": ["systemctl start api-backend", "systemctl enable api-backend", "tail -f /var/log/api-backend/application.log"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Configurar backup en cloud", "detalle": "Configurar respaldo automático", "comandos": ["aws s3 mb s3://backup-api-backend", "crontab -e # Añadir: 0 2 * * * /scripts/backup-api.sh", "chmod +x /scripts/backup-api.sh"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Probar backup", "detalle": "Ejecutar backup manual para validar", "comandos": ["/scripts/backup-api.sh", "aws s3 ls s3://backup-api-backend/", "ls -la /backup/"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar funcionamiento completo", "detalle": "Probar APIs y confirmar backup", "comandos": ["curl -X GET http://localhost:8080/api/status", "systemctl status api-backend", "crontab -l | grep backup"], "source_comandos": "IA"}], "checklist": ["Servicio backend restaurado y funcionando", "Backup configurado en cloud", "Script de backup probado exitosamente", "Cron job configurado para backup automático", "APIs respondiendo correctamente", "Documentación de configuración actualizada"], "enriched": true}', 'RUN', 'Crítica', 'En Progreso', 'FTE-026', NULL, 'INC-20260321-B278', NULL, 0.2, 0.0, '2026-03-21 19:01:53.509986+00', '2026-04-01 18:10:08.075745+00', NULL, '[{"columna": "Completado", "timestamp": "2026-04-01T18:10:08.075789"}, {"estado": "en_curso", "columna": "En Progreso", "timestamp": "2026-04-07T10:24:34.157992"}]', '2026-03-21 19:01:53.509986+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-DDD8', 'Verificar procesos SWIFT en servidores', '{"silo": "UNIX", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Conexión RDP establecida", "Servicios SWIFT verificados", "Procesos SWIFT en ejecución", "Puertos 9443/9444 activos", "Recursos sistema normales", "Estado procesos documentado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-PRO-003 (swift-gw.swift)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "SO", "valor": "Windows Server 2022", "source": "CMDB"}, {"campo": "SWIFT Gateway", "valor": "Alliance Gateway 7.4", "source": "CMDB"}, {"campo": "Servicios SWIFT", "valor": "SWIFT Alliance Service", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar al servidor", "detalle": "Acceso RDP al servidor SWIFT", "comandos": ["mstsc /v:10.0.90.2"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar servicios SWIFT", "detalle": "Comprobar estado de servicios Windows", "comandos": ["services.msc", "Get-Service | Where-Object {$_.Name -like ''*SWIFT*''}", "Get-Service ''SWIFT Alliance Service'' | Select-Object Status"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar procesos SWIFT", "detalle": "Comprobar procesos en ejecución", "comandos": ["tasklist | findstr swift", "Get-Process | Where-Object {$_.ProcessName -like ''*swift*''}", "Get-Process | Where-Object {$_.ProcessName -like ''*alliance*''}"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar puertos de escucha", "detalle": "Comprobar puertos SWIFT activos", "comandos": ["netstat -an | findstr :9443", "netstat -an | findstr :9444", "netstat -an | findstr LISTENING"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar recursos del sistema", "detalle": "Comprobar CPU, memoria y disco", "comandos": ["Get-Counter ''\\Processor(_Total)\\% Processor Time''", "Get-Counter ''\\Memory\\Available MBytes''", "Get-WmiObject -Class Win32_LogicalDisk | Select-Object Size,FreeSpace"], "source_comandos": "IA"}], "skill_requerida": "Linux: Procesos", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 'Crítica', 'Análisis', NULL, NULL, 'INC-20260401-3BD9', NULL, 0.3, 0.0, '2026-04-01 10:58:17.887686+00', NULL, NULL, '[{"columna": "Análisis", "timestamp": "2026-04-01T18:10:21.463975"}]', '2026-04-01 10:58:17.887686+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-3898', 'Restaurar conectividad SWIFT', '{"silo": "REDES", "tipo": "RUN", "orden": 6, "enriched": true, "checklist": ["Diagnóstico previo revisado", "Servicios red reiniciados", "Conectividad básica restaurada", "Rutas SWIFT configuradas", "Conectividad externa verificada", "Servicios SWIFT coordinados", "Restauración validada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "SRV-PRO-003 (swift-gw.swift)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "VLAN", "valor": "90 - SWIFT-CORE", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "Puertos SWIFT", "valor": "9443 (HTTPS), 9444 (SWIFT)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar diagnóstico previo", "detalle": "Revisar resultados de tareas anteriores", "comandos": ["Consultar tickets KT-20260401-FFA2 y KT-20260401-2165"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Reiniciar servicios de red", "detalle": "Reiniciar interfaces y servicios VLAN", "comandos": ["interface vlan 90", "shutdown", "no shutdown", "show interface vlan 90 status"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Verificar conectividad básica", "detalle": "Probar ping y conectividad TCP", "comandos": ["ping -c 5 10.0.90.2", "telnet 10.0.90.2 9443", "telnet 10.0.90.2 9444"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Restaurar rutas SWIFT", "detalle": "Reconfigurar rutas si es necesario", "comandos": ["show ip route | grep 10.0.90", "ip route 10.0.90.0 255.255.255.240 10.0.90.1", "show ip route 10.0.90.0"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Verificar conectividad externa", "detalle": "Probar conectividad hacia red SWIFT", "comandos": ["ping -c 5 swift.com", "traceroute swift.com", "nslookup swift.com"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Coordinar reinicio servicios SWIFT", "detalle": "Solicitar reinicio de servicios en servidor", "comandos": ["Coordinar con silo Unix para reinicio servicios"], "source_comandos": "IA"}, {"paso": 7, "titulo": "Validar restauración completa", "detalle": "Confirmar conectividad total", "comandos": ["ping -c 10 10.0.90.2", "telnet 10.0.90.2 9443", "telnet 10.0.90.2 9444"], "source_comandos": "CMDB"}], "skill_requerida": "Redes: Netstat", "requiere_negocio": false, "sla_tarea_minutos": 90}', 'RUN', 'Crítica', 'Backlog', 'FTE-055', NULL, 'INC-20260401-3BD9', NULL, 1.0, 0.0, '2026-04-01 10:58:17.901532+00', NULL, NULL, '[{"columna": "Análisis", "timestamp": "2026-04-06T21:06:18.963733"}, {"columna": "Backlog", "timestamp": "2026-04-06T21:06:20.361584"}]', '2026-04-01 10:58:17.901532+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-3F90', 'Análisis logs hub mensajería SWIFT', '{"silo": "UNIX", "tipo": "RUN", "orden": 2, "enriched": true, "checklist": ["Acceso RDP al servidor exitoso", "Logs Alliance Gateway revisados", "Logs conectividad analizados", "Event Viewer consultado", "Errores críticos identificados", "Reporte de análisis generado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor", "valor": "SRV-PRO-003 (swift-gw.swift)", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "SO", "valor": "Windows Server 2022", "source": "CMDB"}, {"campo": "SWIFT Version", "valor": "7.4", "source": "CMDB"}, {"campo": "Ruta logs SWIFT", "valor": "C:\\SWIFT\\logs\\", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Acceder al servidor SWIFT", "detalle": "Conectar vía RDP al servidor", "comandos": ["mstsc /v:10.0.90.2"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Revisar logs del Alliance Gateway", "detalle": "Analizar logs de mensajería SWIFT", "comandos": ["cd C:\\SWIFT\\logs", "dir /od *.log", "type alliance_gateway.log | findstr ERROR", "type alliance_gateway.log | findstr WARN"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Revisar logs de conectividad", "detalle": "Verificar logs de conexión SWIFT", "comandos": ["type connectivity.log | findstr \"Connection\"", "type swift_network.log | findstr \"Timeout\"", "type swift_network.log | findstr \"Failed\""], "source_comandos": "IA"}, {"paso": 4, "titulo": "Analizar eventos del sistema", "detalle": "Revisar Event Viewer para errores SWIFT", "comandos": ["eventvwr.msc", "Filtrar por Application Log - SWIFT"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de análisis", "detalle": "Documentar hallazgos en logs", "comandos": ["Crear resumen de errores encontrados"], "source_comandos": "IA"}], "skill_requerida": "Backend: Logging errores", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260401-3BD9', NULL, 0.5, 0.0, '2026-04-01 10:58:17.883761+00', NULL, NULL, '[]', '2026-04-01 10:58:17.883761+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-2165', 'Diagnóstico red - Gateway y rutas SWIFT', '{"silo": "REDES", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Gateway 10.0.90.1 responde", "Rutas SWIFT configuradas", "VLAN 90 operativa", "Conectividad externa verificada", "ACLs revisadas", "Diagnóstico documentado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "SRV-PRO-003", "source": "CMDB"}, {"campo": "IP SWIFT", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "VLAN", "valor": "90 - SWIFT-CORE", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "Subred", "valor": "10.0.90.0/28", "source": "CMDB"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar gateway SWIFT", "detalle": "Comprobar estado del gateway de la VLAN", "comandos": ["ping -c 10 10.0.90.1", "show ip route | grep 10.0.90.1", "show interface vlan 90"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar rutas hacia SWIFT", "detalle": "Comprobar tabla de rutas y conectividad", "comandos": ["show ip route | grep swift", "traceroute 10.0.90.2", "show arp | grep 10.0.90"], "source_comandos": "CMDB"}, {"paso": 3, "titulo": "Verificar conectividad externa", "detalle": "Probar rutas hacia red SWIFT externa", "comandos": ["ping -c 5 swift.com", "traceroute swift.com", "nslookup swift.com"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Verificar VLAN SWIFT-CORE", "detalle": "Comprobar configuración y estado VLAN 90", "comandos": ["show vlan id 90", "show spanning-tree vlan 90", "show interface trunk | grep 90"], "source_comandos": "CMDB"}, {"paso": 5, "titulo": "Verificar firewall y ACLs", "detalle": "Comprobar reglas que afecten tráfico SWIFT", "comandos": ["show access-list | grep 10.0.90", "show ip access-list extended", "show firewall rules | grep swift"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Documentar diagnóstico", "detalle": "Generar reporte de estado de red", "comandos": ["Documentar hallazgos en ticket"], "source_comandos": "IA"}], "skill_requerida": "Redes: IP/Gateway", "requiere_negocio": false, "sla_tarea_minutos": 60}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260401-3BD9', NULL, 0.7, 0.0, '2026-04-01 10:58:17.892758+00', NULL, NULL, '[]', '2026-04-01 10:58:17.892758+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-51EB', 'Consultar estado transferencias en BBDD', '{"silo": "BBDD", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Conexión BBDD establecida", "Transferencias pendientes consultadas", "Transferencias completadas verificadas", "Errores identificados", "Estado BBDD comprobado", "Reporte generado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "SRV-PRO-003", "source": "CMDB"}, {"campo": "IP", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "BBDD SWIFT", "valor": "SQL Server (default)", "source": "IA"}, {"campo": "Puerto BBDD", "valor": "1433", "source": "IA"}, {"campo": "Schema SWIFT", "valor": "SWIFT_MESSAGES", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a BBDD SWIFT", "detalle": "Acceder a la base de datos", "comandos": ["sqlcmd -S 10.0.90.2,1433 -E", "USE SWIFT_MESSAGES"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Consultar transferencias pendientes", "detalle": "Verificar mensajes en cola", "comandos": ["SELECT COUNT(*) FROM SWIFT_QUEUE WHERE STATUS=''PENDING''", "SELECT TOP 10 * FROM SWIFT_QUEUE WHERE STATUS=''PENDING'' ORDER BY CREATED_DATE DESC"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Consultar transferencias procesadas", "detalle": "Verificar mensajes completados", "comandos": ["SELECT COUNT(*) FROM SWIFT_MESSAGES WHERE STATUS=''COMPLETED'' AND DATE >= GETDATE()-1", "SELECT COUNT(*) FROM SWIFT_MESSAGES WHERE STATUS=''FAILED'' AND DATE >= GETDATE()-1"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Consultar transferencias con error", "detalle": "Identificar mensajes fallidos", "comandos": ["SELECT * FROM SWIFT_MESSAGES WHERE STATUS=''ERROR'' AND DATE >= GETDATE()-1", "SELECT ERROR_CODE, COUNT(*) FROM SWIFT_MESSAGES WHERE STATUS=''ERROR'' GROUP BY ERROR_CODE"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar conectividad BBDD", "detalle": "Comprobar estado de conexiones", "comandos": ["SELECT @@SERVERNAME, @@VERSION", "SELECT COUNT(*) FROM sys.dm_exec_sessions WHERE is_user_process=1"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte", "detalle": "Documentar estado de transferencias", "comandos": ["Crear resumen de consultas realizadas"], "source_comandos": "IA"}], "skill_requerida": "SQL: Select Simple", "requiere_negocio": false, "sla_tarea_minutos": 45}', 'RUN', 'Crítica', 'Backlog', NULL, NULL, 'INC-20260401-3BD9', NULL, 0.3, 0.0, '2026-04-01 10:58:17.896885+00', NULL, NULL, '[]', '2026-04-01 10:58:17.896885+00');
INSERT INTO public.kanban_tareas (id, titulo, descripcion, tipo, prioridad, columna, id_tecnico, id_proyecto, id_incidencia, bloqueador, horas_estimadas, horas_reales, fecha_creacion, fecha_inicio_ejecucion, fecha_cierre, historial_columnas, created_at) VALUES ('KT-20260401-FFA2', 'Diagnóstico inicial - Verificar conectividad SWIFT', '{"silo": "REDES", "tipo": "RUN", "orden": 1, "enriched": true, "checklist": ["Ping a servidor SWIFT exitoso", "Puertos 9443 y 9444 accesibles", "Conectividad externa SWIFT verificada", "Estado VLAN 90 comprobado", "Ticket actualizado con diagnóstico"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Servidor SWIFT", "valor": "SRV-PRO-003 (swift-gw.swift)", "source": "CMDB"}, {"campo": "IP Principal", "valor": "10.0.90.2", "source": "CMDB"}, {"campo": "VLAN", "valor": "90 - SWIFT-CORE", "source": "CMDB"}, {"campo": "Gateway", "valor": "10.0.90.1", "source": "CMDB"}, {"campo": "Puerto SWIFT", "valor": "9443 (HTTPS), 9444 (SWIFT)", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Verificar conectividad básica", "detalle": "Comprobar ping y conectividad TCP", "comandos": ["ping -c 4 10.0.90.2", "telnet 10.0.90.2 9443", "telnet 10.0.90.2 9444"], "source_comandos": "CMDB"}, {"paso": 2, "titulo": "Verificar conectividad SWIFT externa", "detalle": "Probar conectividad hacia red SWIFT", "comandos": ["ping -c 4 swift.com", "nslookup swift.com", "traceroute swift.com"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Verificar estado interfaces de red", "detalle": "Comprobar estado de interfaces en VLAN SWIFT", "comandos": ["show interface vlan 90", "show ip route | grep 10.0.90", "show arp | grep 10.0.90.2"], "source_comandos": "CMDB"}, {"paso": 4, "titulo": "Documentar hallazgos", "detalle": "Registrar estado de conectividad en ticket", "comandos": ["Actualizar ticket con resultados de conectividad"], "source_comandos": "IA"}], "skill_requerida": "Redes: Ping", "requiere_negocio": false, "sla_tarea_minutos": 30}', 'RUN', 